{
  "name": "AI Art Director",
  "description": "Transforms your creative concepts into professional print & ad design prompts and generates high-quality visuals using Gemini."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum ProductType {
  POSTER = 'Poster',
  STANDEE = 'Standee',
  BACKDROP = 'Backdrop',
  BANNER = 'Banner',
  SOCIAL_POST = 'Social Media Post',
  FLYER = 'Flyer'
}

export enum VisualStyle {
  MODERN_TECH = 'Modern Tech',
  LUXURY = 'Luxury',
  VINTAGE = 'Vintage',
  FESTIVE = 'Festive',
  MINIMALIST = 'Minimalist',
  CORPORATE = 'Corporate',
  CYBERPUNK = 'Cyberpunk',
  NATURAL_ORGANIC = 'Natural/Organic'
}

export enum ColorMode {
  AUTO = 'Auto',
  CUSTOM = 'Custom'
}

export interface ArtDirectionRequest {
  productType: ProductType;
  contentText: string;
  visualStyle: VisualStyle;
  colorMode: ColorMode;
  customColor?: string;
  subject: string;
}

export interface ArtDirectionResponse {
  analysis: string;
  final_prompt: string;
  recommendedAspectRatio: "1:1" | "3:4" | "4:3" | "9:16" | "16:9";
}

export interface ImageGenerationResult {
  imageUrl: string | null;
  loading: boolean;
  error: string | null;
}

import { GoogleGenAI, Type, Schema } from "@google/genai";
import { ArtDirectionRequest, ArtDirectionResponse } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const SYSTEM_INSTRUCTION = `
You are a professional "AI Art Director" in the print & advertising design field. Your task is to transform raw user requests into a HIGHLY SPECIALIZED ENGLISH PROMPT for an image generation model (like Gemini Image).

### INPUT DATA
1. **Product Type:** (Poster, Backdrop, Banner, Standee...)
2. **Content Text:** (Headline, Slogan...)
3. **Visual Style:** (Modern Tech, Luxury, Vintage, Festive...)
4. **Color Mode:** (Auto or Specific Hex/Pantone)
5. **Subject:** (Product description/Main theme)

### LOGIC CORE & CONSTRAINTS

**1. LAYOUT RULES (Must influence the prompt description)**
* IF **Poster/Standee (Vertical):**
    * Priority: Vertical composition, Central focus, Top-down view (for food).
    * Forbidden: Wide angle, Panoramic.
* IF **Backdrop (Wide Horizontal):**
    * Priority: Ultra-wide angle, Symmetrical, Rule of thirds.
    * Note: Add "Leave empty space in center for people standing".
* IF **Banner (Narrow Horizontal):**
    * Priority: Split layout (Text left/Image right), Negative space.

**2. STYLE MAPPING**
* **Modern Tech:** Keywords -> 3D render, abstract geometry, glassmorphism, circuit patterns, glowing edges.
* **Luxury:** Keywords -> Minimalist, gold foil texture, marble, silk, studio soft lighting, elegant serif font.
* **Vintage:** Keywords -> Retro texture, noise/grain, sepia tone, handwritten font, art deco.
* **Festive:** Keywords -> Vibrant colors, 3D cartoon style, confetti, dynamic motion, bold typography.
* **Natural/Organic:** Keywords -> Soft sunlight, botanical elements, wood textures, fresh green tones, airy composition.

**3. COLOR LOGIC**
* **Auto:** Choose harmonious colors based on Style (e.g., Tech -> Neon Blue).
* **Strict Mode (Hex/Name):** Translate to descriptive English (e.g., #FF0000 -> Bright Red) and add: "Dominant color scheme: [Color Name] ([Hex]), maintain brand consistency."
* Always add: "Ensure high contrast between text and background."

**4. QUALITY SPECS**
* Always add at the end: "High fidelity, 8k resolution, highly detailed, professional graphic design, print quality text rendering."

### OUTPUT FORMAT
Return a JSON object with:
1. "analysis": Brief explanation of layout/color choices.
2. "final_prompt": The complete English prompt.
3. "recommendedAspectRatio": The most suitable aspect ratio for the image model strictly selected from: "1:1", "3:4", "4:3", "9:16", "16:9".
   - Poster/Standee -> "9:16" (or "3:4")
   - Backdrop/Banner -> "16:9"
   - Social Post -> "1:1" or "4:3"
`;

const RESPONSE_SCHEMA: Schema = {
  type: Type.OBJECT,
  properties: {
    analysis: {
      type: Type.STRING,
      description: "Brief explanation of the design choices.",
    },
    final_prompt: {
      type: Type.STRING,
      description: "The highly detailed prompt for the image generator.",
    },
    recommendedAspectRatio: {
      type: Type.STRING,
      enum: ["1:1", "3:4", "4:3", "9:16", "16:9"],
      description: "The best aspect ratio supported by the API.",
    },
  },
  required: ["analysis", "final_prompt", "recommendedAspectRatio"],
};

export const generateArtDirection = async (request: ArtDirectionRequest): Promise<ArtDirectionResponse> => {
  try {
    const userPrompt = `
      Product Type: ${request.productType}
      Content Text: "${request.contentText}"
      Visual Style: ${request.visualStyle}
      Color Mode: ${request.colorMode === 'Custom' ? `Custom (${request.customColor})` : 'Auto'}
      Subject: ${request.subject}
    `;

    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: userPrompt,
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        responseMimeType: "application/json",
        responseSchema: RESPONSE_SCHEMA,
      },
    });

    const text = response.text;
    if (!text) throw new Error("No response from AI Director");

    return JSON.parse(text) as ArtDirectionResponse;
  } catch (error) {
    console.error("Error generating art direction:", error);
    throw error;
  }
};

export const generateDesignImage = async (prompt: string, aspectRatio: string): Promise<string> => {
  try {
    // gemini-2.5-flash-image handles standard generation well
    // gemini-3-pro-image-preview is better for text rendering in images
    const modelName = "gemini-3-pro-image-preview"; 

    const response = await ai.models.generateContent({
      model: modelName,
      contents: {
        parts: [{ text: prompt }],
      },
      config: {
        imageConfig: {
            aspectRatio: aspectRatio,
            imageSize: "1K" // Defaulting to 1K for speed/standard usage
        }
      },
    });

    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData) {
        return `data:image/png;base64,${part.inlineData.data}`;
      }
    }

    throw new Error("No image data found in response");
  } catch (error) {
    console.error("Error generating image:", error);
    throw error;
  }
};

import React from 'react';
import { ArtDirectionRequest, ProductType, VisualStyle, ColorMode } from '../types';

interface InputFormProps {
  values: ArtDirectionRequest;
  onChange: (field: keyof ArtDirectionRequest, value: any) => void;
  onSubmit: () => void;
  isGenerating: boolean;
}

const InputForm: React.FC<InputFormProps> = ({ values, onChange, onSubmit, isGenerating }) => {
  return (
    <div className="bg-slate-800/50 p-6 rounded-2xl border border-slate-700 shadow-xl backdrop-blur-sm h-full flex flex-col overflow-y-auto">
      <h2 className="text-xl font-bold text-white mb-6 flex items-center gap-2">
        <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6 text-purple-400" fill="none" viewBox="0 0 24 24" stroke="currentColor">
          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M11 5H6a2 2 0 00-2 2v11a2 2 0 002 2h11a2 2 0 002-2v-5m-1.414-9.414a2 2 0 112.828 2.828L11.828 15H9v-2.828l8.586-8.586z" />
        </svg>
        Creative Brief
      </h2>

      <div className="space-y-5 flex-grow">
        {/* Product Type */}
        <div>
          <label className="block text-sm font-medium text-slate-300 mb-1">Product Type</label>
          <select
            className="w-full bg-slate-900 border border-slate-700 rounded-lg px-4 py-2 text-white focus:ring-2 focus:ring-purple-500 focus:border-transparent outline-none transition-all"
            value={values.productType}
            onChange={(e) => onChange('productType', e.target.value)}
          >
            {Object.values(ProductType).map((type) => (
              <option key={type} value={type}>{type}</option>
            ))}
          </select>
        </div>

        {/* Content Text */}
        <div>
          <label className="block text-sm font-medium text-slate-300 mb-1">Content Text (Headline/Slogan)</label>
          <input
            type="text"
            className="w-full bg-slate-900 border border-slate-700 rounded-lg px-4 py-2 text-white focus:ring-2 focus:ring-purple-500 focus:border-transparent outline-none transition-all placeholder-slate-500"
            placeholder="e.g., SUMMER SALE - 50% OFF"
            value={values.contentText}
            onChange={(e) => onChange('contentText', e.target.value)}
          />
        </div>

        {/* Visual Style */}
        <div>
          <label className="block text-sm font-medium text-slate-300 mb-1">Visual Style</label>
          <select
            className="w-full bg-slate-900 border border-slate-700 rounded-lg px-4 py-2 text-white focus:ring-2 focus:ring-purple-500 focus:border-transparent outline-none transition-all"
            value={values.visualStyle}
            onChange={(e) => onChange('visualStyle', e.target.value)}
          >
            {Object.values(VisualStyle).map((style) => (
              <option key={style} value={style}>{style}</option>
            ))}
          </select>
        </div>

        {/* Color Mode */}
        <div>
          <label className="block text-sm font-medium text-slate-300 mb-2">Color Mode</label>
          <div className="flex gap-4">
            <label className="flex items-center gap-2 cursor-pointer">
              <input
                type="radio"
                name="colorMode"
                value={ColorMode.AUTO}
                checked={values.colorMode === ColorMode.AUTO}
                onChange={() => onChange('colorMode', ColorMode.AUTO)}
                className="text-purple-500 focus:ring-purple-500"
              />
              <span className="text-sm text-slate-200">Auto (AI Choice)</span>
            </label>
            <label className="flex items-center gap-2 cursor-pointer">
              <input
                type="radio"
                name="colorMode"
                value={ColorMode.CUSTOM}
                checked={values.colorMode === ColorMode.CUSTOM}
                onChange={() => onChange('colorMode', ColorMode.CUSTOM)}
                className="text-purple-500 focus:ring-purple-500"
              />
              <span className="text-sm text-slate-200">Custom Hex</span>
            </label>
          </div>
          {values.colorMode === ColorMode.CUSTOM && (
            <div className="mt-2 flex items-center gap-2">
               <input
                type="color"
                value={values.customColor}
                onChange={(e) => onChange('customColor', e.target.value)}
                className="h-10 w-10 rounded border-0 cursor-pointer bg-transparent"
              />
              <input
                type="text"
                value={values.customColor}
                onChange={(e) => onChange('customColor', e.target.value)}
                className="flex-1 bg-slate-900 border border-slate-700 rounded-lg px-4 py-2 text-white text-sm focus:ring-2 focus:ring-purple-500 outline-none"
                placeholder="#FF0000"
              />
            </div>
          )}
        </div>

        {/* Subject */}
        <div>
          <label className="block text-sm font-medium text-slate-300 mb-1">Subject Description</label>
          <textarea
            className="w-full bg-slate-900 border border-slate-700 rounded-lg px-4 py-2 text-white focus:ring-2 focus:ring-purple-500 focus:border-transparent outline-none transition-all placeholder-slate-500 h-28 resize-none"
            placeholder="Describe the main product or theme. e.g., A futuristic electric car on a neon highway..."
            value={values.subject}
            onChange={(e) => onChange('subject', e.target.value)}
          />
        </div>
      </div>

      <div className="pt-6 mt-4 border-t border-slate-700">
        <button
          onClick={onSubmit}
          disabled={isGenerating || !values.subject}
          className={`w-full py-3 px-6 rounded-lg text-white font-semibold shadow-lg transition-all duration-300 transform hover:scale-[1.02] flex items-center justify-center gap-2
            ${isGenerating || !values.subject
              ? 'bg-slate-700 cursor-not-allowed text-slate-400'
              : 'bg-gradient-to-r from-purple-600 to-blue-600 hover:from-purple-500 hover:to-blue-500 hover:shadow-purple-500/25'
            }`}
        >
          {isGenerating ? (
            <>
              <svg className="animate-spin -ml-1 mr-3 h-5 w-5 text-white" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
              </svg>
              Directing AI...
            </>
          ) : (
            <>
              Generate Design
              <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 10V3L4 14h7v7l9-11h-7z" />
              </svg>
            </>
          )}
        </button>
      </div>
    </div>
  );
};

export default InputForm;

import React, { useState, useEffect } from 'react';
import { ArtDirectionResponse, ImageGenerationResult } from '../types';

interface ResultDisplayProps {
  artDirection: ArtDirectionResponse | null;
  imageResult: ImageGenerationResult;
  onRegenerateImage: (prompt: string) => void;
}

const ResultDisplay: React.FC<ResultDisplayProps> = ({ artDirection, imageResult, onRegenerateImage }) => {
  const [editablePrompt, setEditablePrompt] = useState('');

  // Update local state when art direction changes
  useEffect(() => {
    if (artDirection) {
      setEditablePrompt(artDirection.final_prompt);
    }
  }, [artDirection]);

  if (!artDirection && !imageResult.loading && !imageResult.imageUrl) {
    return (
      <div className="h-full flex items-center justify-center bg-slate-800/30 rounded-2xl border border-slate-700/50 border-dashed">
        <div className="text-center p-8 max-w-md">
          <div className="w-16 h-16 bg-slate-800 rounded-full flex items-center justify-center mx-auto mb-4 text-slate-500">
            <svg xmlns="http://www.w3.org/2000/svg" className="h-8 w-8" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" />
            </svg>
          </div>
          <h3 className="text-lg font-medium text-slate-300 mb-2">Ready to Design</h3>
          <p className="text-slate-500">Fill out the creative brief on the left to generate your AI-directed artwork.</p>
        </div>
      </div>
    );
  }

  return (
    <div className="flex flex-col h-full gap-6 overflow-y-auto">
      {/* 1. Art Direction Analysis Card */}
      {artDirection && (
        <div className="bg-slate-800/50 rounded-2xl border border-purple-500/30 overflow-hidden shadow-lg backdrop-blur-sm animate-fade-in-up">
           <div className="bg-purple-900/20 px-6 py-3 border-b border-purple-500/20 flex items-center gap-2">
             <span className="text-purple-400 text-xs font-bold tracking-wider uppercase bg-purple-900/40 px-2 py-1 rounded">AI Director's Note</span>
             <span className="text-slate-400 text-xs ml-auto">Ratio: {artDirection.recommendedAspectRatio}</span>
           </div>
           <div className="p-6">
             <p className="text-slate-300 italic text-sm leading-relaxed border-l-2 border-purple-500 pl-4 mb-4">
               "{artDirection.analysis}"
             </p>

             <div className="bg-slate-900 rounded-lg p-3 border border-slate-700">
                <div className="flex justify-between items-center mb-2">
                   <span className="text-xs text-slate-500 font-semibold uppercase">Generated Prompt</span>
                   <button 
                     className="text-xs text-blue-400 hover:text-blue-300"
                     onClick={() => navigator.clipboard.writeText(editablePrompt)}
                   >
                     Copy
                   </button>
                </div>
                <textarea 
                  className="w-full bg-transparent text-sm text-slate-300 focus:outline-none resize-none h-24 scrollbar-thin scrollbar-thumb-slate-700 scrollbar-track-transparent"
                  value={editablePrompt}
                  onChange={(e) => setEditablePrompt(e.target.value)}
                />
                <div className="mt-2 flex justify-end">
                   <button 
                     onClick={() => onRegenerateImage(editablePrompt)}
                     disabled={imageResult.loading}
                     className="text-xs bg-slate-700 hover:bg-slate-600 text-white px-3 py-1.5 rounded transition-colors flex items-center gap-1"
                   >
                     {imageResult.loading ? 'Processing...' : 'Refine & Regenerate Image'}
                   </button>
                </div>
             </div>
           </div>
        </div>
      )}

      {/* 2. Image Display Area */}
      <div className="flex-grow min-h-[400px] bg-slate-900 rounded-2xl border border-slate-700 relative overflow-hidden flex items-center justify-center group">
        {imageResult.loading ? (
          <div className="text-center z-10">
            <div className="inline-block w-12 h-12 border-4 border-purple-500 border-t-transparent rounded-full animate-spin mb-4"></div>
            <p className="text-slate-400 text-sm animate-pulse">Rendering high-fidelity artwork...</p>
          </div>
        ) : imageResult.error ? (
          <div className="text-red-400 p-8 text-center max-w-sm">
            <svg xmlns="http://www.w3.org/2000/svg" className="h-10 w-10 mx-auto mb-3 opacity-80" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" />
            </svg>
            <p>{imageResult.error}</p>
          </div>
        ) : imageResult.imageUrl ? (
          <>
            <img 
              src={imageResult.imageUrl} 
              alt="Generated Art" 
              className="w-full h-full object-contain z-0"
            />
            <div className="absolute top-4 right-4 opacity-0 group-hover:opacity-100 transition-opacity duration-300 flex gap-2">
              <a 
                href={imageResult.imageUrl} 
                download="ai-design.png"
                className="bg-black/60 hover:bg-black/80 text-white p-2 rounded-lg backdrop-blur-md"
                title="Download"
              >
                <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" />
                </svg>
              </a>
            </div>
          </>
        ) : null}

        {/* Grid Overlay for professional look */}
        {!imageResult.imageUrl && !imageResult.loading && (
             <div className="absolute inset-0 pointer-events-none" 
                  style={{
                    backgroundImage: 'radial-gradient(#334155 1px, transparent 1px)',
                    backgroundSize: '20px 20px',
                    opacity: 0.2
                  }}
             ></div>
        )}
      </div>
    </div>
  );
};

export default ResultDisplay;

import React, { useState } from 'react';
import InputForm from './components/InputForm';
import ResultDisplay from './components/ResultDisplay';
import { ArtDirectionRequest, ArtDirectionResponse, ColorMode, ImageGenerationResult, ProductType, VisualStyle } from './types';
import { generateArtDirection, generateDesignImage } from './services/geminiService';

const App: React.FC = () => {
  // Form State
  const [request, setRequest] = useState<ArtDirectionRequest>({
    productType: ProductType.POSTER,
    contentText: '',
    visualStyle: VisualStyle.MODERN_TECH,
    colorMode: ColorMode.AUTO,
    customColor: '#7c3aed',
    subject: ''
  });

  // Result States
  const [artDirection, setArtDirection] = useState<ArtDirectionResponse | null>(null);
  const [imageResult, setImageResult] = useState<ImageGenerationResult>({
    imageUrl: null,
    loading: false,
    error: null
  });

  // Handlers
  const handleInputChange = (field: keyof ArtDirectionRequest, value: any) => {
    setRequest(prev => ({ ...prev, [field]: value }));
  };

  const handleGenerate = async () => {
    if (!request.subject) return;

    setImageResult(prev => ({ ...prev, loading: true, error: null, imageUrl: null }));

    try {
      // Step 1: Generate Art Direction (Prompt + Analysis)
      console.log("Generating art direction...");
      const direction = await generateArtDirection(request);
      setArtDirection(direction);

      // Step 2: Generate Image using the directed prompt and aspect ratio
      console.log("Generating image with prompt:", direction.final_prompt);
      const imageBase64 = await generateDesignImage(direction.final_prompt, direction.recommendedAspectRatio);

      setImageResult({
        imageUrl: imageBase64,
        loading: false,
        error: null
      });

    } catch (err: any) {
      console.error(err);
      setImageResult({
        imageUrl: null,
        loading: false,
        error: err.message || "Something went wrong. Please check your API key and try again."
      });
    }
  };

  const handleRegenerateImage = async (newPrompt: string) => {
    if (!artDirection) return;

    setImageResult(prev => ({ ...prev, loading: true, error: null }));
    try {
      const imageBase64 = await generateDesignImage(newPrompt, artDirection.recommendedAspectRatio);
      setImageResult({
        imageUrl: imageBase64,
        loading: false,
        error: null
      });
    } catch (err: any) {
       setImageResult({
        imageUrl: null,
        loading: false,
        error: err.message || "Failed to regenerate image."
      });
    }
  };

  return (
    <div className="min-h-screen bg-[#0f172a] text-slate-200 selection:bg-purple-500/30">
      {/* Background Ambience */}
      <div className="fixed inset-0 z-0 pointer-events-none">
        <div className="absolute top-0 left-1/4 w-96 h-96 bg-purple-600/10 rounded-full blur-[100px]"></div>
        <div className="absolute bottom-0 right-1/4 w-96 h-96 bg-blue-600/10 rounded-full blur-[100px]"></div>
      </div>

      <div className="relative z-10 container mx-auto px-4 py-6 h-screen flex flex-col">
        {/* Header */}
        <header className="flex items-center justify-between mb-6 shrink-0">
          <div className="flex items-center gap-3">
             <div className="w-10 h-10 bg-gradient-to-br from-purple-500 to-blue-600 rounded-lg flex items-center justify-center shadow-lg shadow-purple-500/20">
               <span className="text-white font-bold text-xl">Ai</span>
             </div>
             <div>
               <h1 className="text-xl font-bold text-white tracking-tight">Art Director</h1>
               <p className="text-xs text-slate-400">Powered by Gemini</p>
             </div>
          </div>
          <div className="flex gap-2">
            <span className="px-3 py-1 bg-slate-800 rounded-full text-xs font-medium text-slate-400 border border-slate-700">v1.0</span>
          </div>
        </header>

        {/* Main Content Grid */}
        <main className="flex-grow grid grid-cols-1 lg:grid-cols-12 gap-6 overflow-hidden min-h-0 pb-2">
          {/* Left: Input Panel */}
          <div className="lg:col-span-4 h-full min-h-[500px]">
            <InputForm 
              values={request} 
              onChange={handleInputChange} 
              onSubmit={handleGenerate}
              isGenerating={imageResult.loading}
            />
          </div>

          {/* Right: Visualization Panel */}
          <div className="lg:col-span-8 h-full min-h-[500px]">
            <ResultDisplay 
              artDirection={artDirection} 
              imageResult={imageResult} 
              onRegenerateImage={handleRegenerateImage}
            />
          </div>
        </main>
      </div>
    </div>
  );
};

export default App;

export enum ProductType {
  POSTER = 'Poster',
  STANDEE = 'Standee',
  BACKDROP = 'Backdrop',
  BANNER = 'Banner',
  SOCIAL_POST = 'Social Media Post',
  FLYER = 'Flyer'
}

export enum VisualStyle {
  MODERN_TECH = 'Modern Tech',
  LUXURY = 'Luxury',
  VINTAGE = 'Vintage',
  FESTIVE = 'Festive',
  MINIMALIST = 'Minimalist',
  CORPORATE = 'Corporate',
  CYBERPUNK = 'Cyberpunk',
  NATURAL_ORGANIC = 'Natural/Organic'
}

export enum ColorMode {
  AUTO = 'Auto',
  CUSTOM = 'Custom'
}

export enum QualityLevel {
  LOW = '1K',
  MEDIUM = '2K',
  HIGH = '4K'
}

export interface ArtDirectionRequest {
  productType: ProductType;
  contentText: string;
  visualStyle: VisualStyle;
  colorMode: ColorMode;
  customColor?: string;
  subject: string;
  // New fields
  width: string;
  height: string;
  assetImages: string[]; // Base64 strings
  referenceImage: string | null; // Base64 string
  referenceAttributes: string[]; // 'style', 'background', 'text_effects', 'layout'
  batchSize: 1 | 3 | 5;
  quality: QualityLevel;
}

export interface ArtDirectionResponse {
  analysis: string;
  final_prompt: string;
  recommendedAspectRatio: "1:1" | "3:4" | "4:3" | "9:16" | "16:9";
}

export interface ImageGenerationResult {
  imageUrls: string[];
  loading: boolean;
  error: string | null;
}

import { GoogleGenAI, Type, Schema } from "@google/genai";
import { ArtDirectionRequest, ArtDirectionResponse } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const SYSTEM_INSTRUCTION = `
You are a professional "AI Art Director" in the print & advertising design field. Your task is to transform raw user requests AND provided visual assets/references into a HIGHLY SPECIALIZED ENGLISH PROMPT for an image generation model.

### INPUT DATA
1. **Product Type:** (Poster, Backdrop, Banner...)
2. **Dimensions:** (User preferred size)
3. **Content Text:** (Headline, Slogan...)
4. **Visual Style:** (Modern Tech, Luxury...)
5. **Color Mode:** (Auto or Hex)
6. **Subject:** (Product description)
7. **Assets:** (Images of products to include)
8. **Reference Image & Attributes:** (User provided reference and specific aspects to mimic: Style, Background, Text Effects, Layout)

### LOGIC CORE & CONSTRAINTS

**1. LAYOUT RULES**
* IF **Poster/Standee (Vertical):** Priority: Vertical composition, Central focus.
* IF **Backdrop (Wide):** Priority: Ultra-wide angle, Symmetrical.
* IF **Banner (Narrow):** Priority: Split layout.
* **Reference Constraint:** If a Reference Image is provided AND 'Layout' attribute is checked, you MUST describe the composition of the reference image in the prompt and instruct the model to follow it.

**2. VISUAL ANALYSIS & INTEGRATION**
* **Asset Images:** If provided, describe them in detail (color, shape, material) in the prompt so the image generator can reconstruct a similar object.
* **Reference Attributes:**
    * **Style:** Mimic the artistic style (e.g., watercolor, 3D render, flat vector).
    * **Background:** Mimic the setting/environment.
    * **Text Effects:** Describe the typography style (e.g., neon, metallic, bold serif).
    * **Layout:** Mimic the object placement and hierarchy.

**3. QUALITY SPECS**
* Always add: "High fidelity, 8k resolution, highly detailed, professional graphic design, print quality text rendering."

### OUTPUT FORMAT
Return a JSON object with:
1. "analysis": Brief explanation of layout/color choices and how the reference was applied.
2. "final_prompt": The complete English prompt.
3. "recommendedAspectRatio": The most suitable aspect ratio for the image model strictly selected from: "1:1", "3:4", "4:3", "9:16", "16:9" based on the user's requested dimensions.
`;

const RESPONSE_SCHEMA: Schema = {
  type: Type.OBJECT,
  properties: {
    analysis: {
      type: Type.STRING,
      description: "Brief explanation of the design choices.",
    },
    final_prompt: {
      type: Type.STRING,
      description: "The highly detailed prompt for the image generator.",
    },
    recommendedAspectRatio: {
      type: Type.STRING,
      enum: ["1:1", "3:4", "4:3", "9:16", "16:9"],
      description: "The best aspect ratio supported by the API.",
    },
  },
  required: ["analysis", "final_prompt", "recommendedAspectRatio"],
};

export const generateArtDirection = async (request: ArtDirectionRequest): Promise<ArtDirectionResponse> => {
  try {
    // Construct the multimodal prompt
    const parts: any[] = [];

    // 1. Text Prompt
    let promptText = `
      Product Type: ${request.productType}
      Dimensions: ${request.width} x ${request.height}
      Content Text: "${request.contentText}"
      Visual Style: ${request.visualStyle}
      Color Mode: ${request.colorMode === 'Custom' ? `Custom (${request.customColor})` : 'Auto'}
      Subject: ${request.subject}
    `;

    if (request.referenceAttributes.length > 0) {
      promptText += `\nReference Image Attributes to Mimic: ${request.referenceAttributes.join(', ')}`;
    }

    parts.push({ text: promptText });

    // 2. Reference Image
    if (request.referenceImage) {
      parts.push({ text: "Reference Image (Use this for style/layout/etc as requested):" });
      parts.push({
        inlineData: {
          mimeType: "image/png",
          data: request.referenceImage.split(',')[1] // Remove data:image/png;base64, prefix
        }
      });
    }

    // 3. Asset Images
    if (request.assetImages && request.assetImages.length > 0) {
      parts.push({ text: "Asset Images (The main products/elements to verify and describe in the prompt):" });
      request.assetImages.forEach((imgBase64, index) => {
        parts.push({
          inlineData: {
            mimeType: "image/png",
            data: imgBase64.split(',')[1]
          }
        });
      });
    }

    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: { parts },
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        responseMimeType: "application/json",
        responseSchema: RESPONSE_SCHEMA,
      },
    });

    const text = response.text;
    if (!text) throw new Error("No response from AI Director");

    return JSON.parse(text) as ArtDirectionResponse;
  } catch (error) {
    console.error("Error generating art direction:", error);
    throw error;
  }
};

export const generateDesignImage = async (
  prompt: string, 
  aspectRatio: string, 
  batchSize: number, 
  imageSize: string
): Promise<string[]> => {
  try {
    const modelName = "gemini-3-pro-image-preview";
    const imageUrls: string[] = [];

    // The API typically generates 1 image per request for high quality models.
    // To support batch size, we execute requests in sequence or parallel.
    // Given rate limits, sequential is often safer, but parallel is faster.
    // We will try parallel requests.

    const promises = Array.from({ length: batchSize }).map(async () => {
      const response = await ai.models.generateContent({
        model: modelName,
        contents: { parts: [{ text: prompt }] },
        config: {
          imageConfig: {
            aspectRatio: aspectRatio,
            imageSize: imageSize // "1K", "2K", "4K"
          }
        },
      });

      for (const part of response.candidates?.[0]?.content?.parts || []) {
        if (part.inlineData) {
          return `data:image/png;base64,${part.inlineData.data}`;
        }
      }
      return null;
    });

    const results = await Promise.all(promises);

    // Filter out any failed generations (nulls)
    return results.filter((url): url is string => url !== null);
  } catch (error) {
    console.error("Error generating image:", error);
    throw error;
  }
};

import React, { useRef } from 'react';
import { ArtDirectionRequest, ProductType, VisualStyle, ColorMode, QualityLevel } from '../types';

interface InputFormProps {
  values: ArtDirectionRequest;
  onChange: (field: keyof ArtDirectionRequest, value: any) => void;
  onSubmit: () => void;
  isGenerating: boolean;
}

const InputForm: React.FC<InputFormProps> = ({ values, onChange, onSubmit, isGenerating }) => {
  const assetInputRef = useRef<HTMLInputElement>(null);
  const refInputRef = useRef<HTMLInputElement>(null);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>, field: 'assetImages' | 'referenceImage') => {
    const files = e.target.files;
    if (!files || files.length === 0) return;

    if (field === 'assetImages') {
      const newImages: string[] = [...values.assetImages];
      Array.from(files).forEach(file => {
        const reader = new FileReader();
        reader.onloadend = () => {
          if (reader.result) newImages.push(reader.result as string);
          // Only update state after last one (simple implementation)
          if (newImages.length === values.assetImages.length + files.length) {
             onChange('assetImages', newImages);
          }
        };
        reader.readAsDataURL(file);
      });
    } else {
      const file = files[0];
      const reader = new FileReader();
      reader.onloadend = () => {
        if (reader.result) onChange('referenceImage', reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const removeAsset = (index: number) => {
    const newImages = [...values.assetImages];
    newImages.splice(index, 1);
    onChange('assetImages', newImages);
  };

  const toggleAttribute = (attr: string) => {
    const current = [...values.referenceAttributes];
    const index = current.indexOf(attr);
    if (index > -1) {
      current.splice(index, 1);
    } else {
      current.push(attr);
    }
    onChange('referenceAttributes', current);
  };

  return (
    <div className="bg-slate-800/50 p-6 rounded-2xl border border-slate-700 shadow-xl backdrop-blur-sm h-full flex flex-col overflow-y-auto">
      <h2 className="text-xl font-bold text-white mb-6 flex items-center gap-2">
        <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6 text-purple-400" fill="none" viewBox="0 0 24 24" stroke="currentColor">
          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M11 5H6a2 2 0 00-2 2v11a2 2 0 002 2h11a2 2 0 002-2v-5m-1.414-9.414a2 2 0 112.828 2.828L11.828 15H9v-2.828l8.586-8.586z" />
        </svg>
        Creative Brief
      </h2>

      <div className="space-y-5 flex-grow">
        {/* Product Type & Dimensions */}
        <div className="grid grid-cols-2 gap-4">
          <div className="col-span-2">
            <label className="block text-sm font-medium text-slate-300 mb-1">Product Type</label>
            <select
              className="w-full bg-slate-900 border border-slate-700 rounded-lg px-4 py-2 text-white focus:ring-2 focus:ring-purple-500 outline-none"
              value={values.productType}
              onChange={(e) => onChange('productType', e.target.value)}
            >
              {Object.values(ProductType).map((type) => (
                <option key={type} value={type}>{type}</option>
              ))}
            </select>
          </div>
          <div>
            <label className="block text-sm font-medium text-slate-300 mb-1">Width</label>
            <input 
              type="text" placeholder="e.g. 1080px"
              className="w-full bg-slate-900 border border-slate-700 rounded-lg px-3 py-2 text-white text-sm focus:ring-2 focus:ring-purple-500 outline-none"
              value={values.width} onChange={(e) => onChange('width', e.target.value)}
            />
          </div>
          <div>
            <label className="block text-sm font-medium text-slate-300 mb-1">Height</label>
            <input 
              type="text" placeholder="e.g. 1920px"
              className="w-full bg-slate-900 border border-slate-700 rounded-lg px-3 py-2 text-white text-sm focus:ring-2 focus:ring-purple-500 outline-none"
              value={values.height} onChange={(e) => onChange('height', e.target.value)}
            />
          </div>
        </div>

        {/* Content & Subject */}
        <div>
          <label className="block text-sm font-medium text-slate-300 mb-1">Content Text</label>
          <input
            type="text"
            className="w-full bg-slate-900 border border-slate-700 rounded-lg px-4 py-2 text-white focus:ring-2 focus:ring-purple-500 outline-none placeholder-slate-500"
            placeholder="Headline / Slogan"
            value={values.contentText}
            onChange={(e) => onChange('contentText', e.target.value)}
          />
        </div>

        <div>
          <label className="block text-sm font-medium text-slate-300 mb-1">Subject Description</label>
          <textarea
            className="w-full bg-slate-900 border border-slate-700 rounded-lg px-4 py-2 text-white focus:ring-2 focus:ring-purple-500 outline-none placeholder-slate-500 h-20 resize-none text-sm"
            placeholder="Main product or theme description..."
            value={values.subject}
            onChange={(e) => onChange('subject', e.target.value)}
          />
        </div>

        {/* Asset Images */}
        <div>
          <label className="block text-sm font-medium text-slate-300 mb-1">Asset Images (Data)</label>
          <div className="flex flex-wrap gap-2 mb-2">
            {values.assetImages.map((img, idx) => (
              <div key={idx} className="relative w-12 h-12 rounded overflow-hidden border border-slate-600 group">
                <img src={img} alt="asset" className="w-full h-full object-cover" />
                <button 
                  onClick={() => removeAsset(idx)}
                  className="absolute inset-0 bg-black/50 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity text-white text-xs"
                >
                  X
                </button>
              </div>
            ))}
            <button 
              onClick={() => assetInputRef.current?.click()}
              className="w-12 h-12 rounded border border-dashed border-slate-500 flex items-center justify-center text-slate-400 hover:border-purple-500 hover:text-purple-500 transition-colors"
            >
              +
            </button>
          </div>
          <input 
            type="file" multiple ref={assetInputRef} className="hidden" accept="image/*"
            onChange={(e) => handleFileChange(e, 'assetImages')} 
          />
        </div>

        {/* Reference Image */}
        <div>
           <div className="flex justify-between items-center mb-1">
            <label className="text-sm font-medium text-slate-300">Reference Image (Style)</label>
            {values.referenceImage && (
              <button 
                onClick={() => onChange('referenceImage', null)}
                className="text-xs text-red-400 hover:text-red-300"
              >
                Clear
              </button>
            )}
           </div>

           {!values.referenceImage ? (
             <div 
               onClick={() => refInputRef.current?.click()}
               className="w-full h-16 border border-dashed border-slate-600 rounded-lg flex flex-col items-center justify-center cursor-pointer hover:border-purple-500 hover:bg-slate-800/50 transition-all group"
             >
               <span className="text-xs text-slate-500 group-hover:text-purple-400">Click to upload reference</span>
             </div>
           ) : (
             <div className="w-full h-32 rounded-lg border border-slate-600 overflow-hidden relative">
               <img src={values.referenceImage} alt="ref" className="w-full h-full object-cover" />
             </div>
           )}
           <input 
            type="file" ref={refInputRef} className="hidden" accept="image/*"
            onChange={(e) => handleFileChange(e, 'referenceImage')} 
           />

           {/* Reference Attributes Checkboxes */}
           {values.referenceImage && (
             <div className="mt-2 grid grid-cols-2 gap-2">
               {['Style', 'Background', 'Text Effects', 'Layout'].map((attr) => (
                 <label key={attr} className="flex items-center space-x-2 cursor-pointer">
                   <input 
                     type="checkbox" 
                     className="rounded border-slate-600 bg-slate-900 text-purple-600 focus:ring-purple-500"
                     checked={values.referenceAttributes.includes(attr)}
                     onChange={() => toggleAttribute(attr)}
                   />
                   <span className="text-xs text-slate-300">{attr}</span>
                 </label>
               ))}
             </div>
           )}
        </div>

        {/* Style & Color */}
        <div className="grid grid-cols-2 gap-4">
          <div>
            <label className="block text-sm font-medium text-slate-300 mb-1">Visual Style</label>
            <select
              className="w-full bg-slate-900 border border-slate-700 rounded-lg px-2 py-2 text-white text-sm outline-none"
              value={values.visualStyle}
              onChange={(e) => onChange('visualStyle', e.target.value)}
            >
              {Object.values(VisualStyle).map((style) => (
                <option key={style} value={style}>{style}</option>
              ))}
            </select>
          </div>
          <div>
            <label className="block text-sm font-medium text-slate-300 mb-1">Color Mode</label>
            <select
               className="w-full bg-slate-900 border border-slate-700 rounded-lg px-2 py-2 text-white text-sm outline-none"
               value={values.colorMode}
               onChange={(e) => onChange('colorMode', e.target.value)}
            >
               <option value={ColorMode.AUTO}>Auto</option>
               <option value={ColorMode.CUSTOM}>Custom</option>
            </select>
          </div>
        </div>
        {values.colorMode === ColorMode.CUSTOM && (
             <div className="flex items-center gap-2">
                <input
                 type="color"
                 value={values.customColor}
                 onChange={(e) => onChange('customColor', e.target.value)}
                 className="h-8 w-8 rounded border-0 cursor-pointer bg-transparent"
               />
               <input
                 type="text"
                 value={values.customColor}
                 onChange={(e) => onChange('customColor', e.target.value)}
                 className="flex-1 bg-slate-900 border border-slate-700 rounded-lg px-3 py-1.5 text-white text-xs"
               />
             </div>
        )}

        {/* Output Settings */}
        <div className="pt-2 border-t border-slate-700/50">
           <label className="block text-xs font-bold text-slate-400 uppercase tracking-wider mb-3">Output Settings</label>

           <div className="grid grid-cols-2 gap-4 mb-4">
             <div>
               <label className="block text-xs text-slate-300 mb-1">Quantity</label>
               <div className="flex bg-slate-900 rounded-lg p-1 border border-slate-700">
                  {[1, 3, 5].map(num => (
                    <button
                      key={num}
                      onClick={() => onChange('batchSize', num)}
                      className={`flex-1 text-xs py-1.5 rounded transition-all ${
                        values.batchSize === num ? 'bg-purple-600 text-white shadow' : 'text-slate-400 hover:text-white'
                      }`}
                    >
                      {num}
                    </button>
                  ))}
               </div>
             </div>

             <div>
               <label className="block text-xs text-slate-300 mb-1">Quality</label>
               <select
                 className="w-full bg-slate-900 border border-slate-700 rounded-lg px-2 py-1.5 text-white text-xs outline-none h-[30px]"
                 value={values.quality}
                 onChange={(e) => onChange('quality', e.target.value)}
               >
                 <option value={QualityLevel.LOW}>Low (1K)</option>
                 <option value={QualityLevel.MEDIUM}>Medium (2K)</option>
                 <option value={QualityLevel.HIGH}>High (4K)</option>
               </select>
             </div>
           </div>
        </div>

      </div>

      <div className="pt-4 border-t border-slate-700 mt-2">
        <button
          onClick={onSubmit}
          disabled={isGenerating || !values.subject}
          className={`w-full py-3 px-6 rounded-lg text-white font-semibold shadow-lg transition-all duration-300 transform hover:scale-[1.02] flex items-center justify-center gap-2
            ${isGenerating || !values.subject
              ? 'bg-slate-700 cursor-not-allowed text-slate-400'
              : 'bg-gradient-to-r from-purple-600 to-blue-600 hover:from-purple-500 hover:to-blue-500 hover:shadow-purple-500/25'
            }`}
        >
          {isGenerating ? (
            <>
              <svg className="animate-spin -ml-1 mr-3 h-5 w-5 text-white" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
              </svg>
              Processing...
            </>
          ) : (
            <>
              Generate Design
              <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 10V3L4 14h7v7l9-11h-7z" />
              </svg>
            </>
          )}
        </button>
      </div>
    </div>
  );
};

export default InputForm;

import React, { useState, useEffect } from 'react';
import { ArtDirectionResponse, ImageGenerationResult } from '../types';

interface ResultDisplayProps {
  artDirection: ArtDirectionResponse | null;
  imageResult: ImageGenerationResult;
  onRegenerateImage: (prompt: string) => void;
}

const ResultDisplay: React.FC<ResultDisplayProps> = ({ artDirection, imageResult, onRegenerateImage }) => {
  const [editablePrompt, setEditablePrompt] = useState('');
  const [selectedImageIndex, setSelectedImageIndex] = useState<number | null>(null);

  // Update local state when art direction changes
  useEffect(() => {
    if (artDirection) {
      setEditablePrompt(artDirection.final_prompt);
    }
  }, [artDirection]);

  // Select the first image when results arrive
  useEffect(() => {
    if (imageResult.imageUrls.length > 0) {
      setSelectedImageIndex(0);
    } else {
      setSelectedImageIndex(null);
    }
  }, [imageResult.imageUrls]);

  if (!artDirection && !imageResult.loading && imageResult.imageUrls.length === 0) {
    return (
      <div className="h-full flex items-center justify-center bg-slate-800/30 rounded-2xl border border-slate-700/50 border-dashed">
        <div className="text-center p-8 max-w-md">
          <div className="w-16 h-16 bg-slate-800 rounded-full flex items-center justify-center mx-auto mb-4 text-slate-500">
            <svg xmlns="http://www.w3.org/2000/svg" className="h-8 w-8" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" />
            </svg>
          </div>
          <h3 className="text-lg font-medium text-slate-300 mb-2">Ready to Design</h3>
          <p className="text-slate-500">Configure your requirements, upload assets, and select a reference style to begin.</p>
        </div>
      </div>
    );
  }

  const selectedImage = selectedImageIndex !== null ? imageResult.imageUrls[selectedImageIndex] : null;

  return (
    <div className="flex flex-col h-full gap-6 overflow-y-auto">
      {/* 1. Art Direction Analysis Card */}
      {artDirection && (
        <div className="bg-slate-800/50 rounded-2xl border border-purple-500/30 overflow-hidden shadow-lg backdrop-blur-sm animate-fade-in-up flex-shrink-0">
           <div className="bg-purple-900/20 px-6 py-3 border-b border-purple-500/20 flex items-center gap-2">
             <span className="text-purple-400 text-xs font-bold tracking-wider uppercase bg-purple-900/40 px-2 py-1 rounded">AI Director's Note</span>
             <span className="text-slate-400 text-xs ml-auto">Ratio: {artDirection.recommendedAspectRatio}</span>
           </div>
           <div className="p-6">
             <p className="text-slate-300 italic text-sm leading-relaxed border-l-2 border-purple-500 pl-4 mb-4">
               "{artDirection.analysis}"
             </p>

             <div className="bg-slate-900 rounded-lg p-3 border border-slate-700">
                <div className="flex justify-between items-center mb-2">
                   <span className="text-xs text-slate-500 font-semibold uppercase">Generated Prompt</span>
                   <button 
                     className="text-xs text-blue-400 hover:text-blue-300"
                     onClick={() => navigator.clipboard.writeText(editablePrompt)}
                   >
                     Copy
                   </button>
                </div>
                <textarea 
                  className="w-full bg-transparent text-sm text-slate-300 focus:outline-none resize-none h-20 scrollbar-thin scrollbar-thumb-slate-700 scrollbar-track-transparent"
                  value={editablePrompt}
                  onChange={(e) => setEditablePrompt(e.target.value)}
                />
                <div className="mt-2 flex justify-end">
                   <button 
                     onClick={() => onRegenerateImage(editablePrompt)}
                     disabled={imageResult.loading}
                     className="text-xs bg-slate-700 hover:bg-slate-600 text-white px-3 py-1.5 rounded transition-colors flex items-center gap-1"
                   >
                     {imageResult.loading ? 'Processing...' : 'Refine & Regenerate Image'}
                   </button>
                </div>
             </div>
           </div>
        </div>
      )}

      {/* 2. Image Display Area */}
      <div className="flex-grow flex flex-col min-h-[400px]">
        {/* Main Display */}
        <div className="flex-grow bg-slate-900 rounded-2xl border border-slate-700 relative overflow-hidden flex items-center justify-center group mb-4">
          {imageResult.loading ? (
            <div className="text-center z-10">
              <div className="inline-block w-12 h-12 border-4 border-purple-500 border-t-transparent rounded-full animate-spin mb-4"></div>
              <p className="text-slate-400 text-sm animate-pulse">Rendering {imageResult.imageUrls.length > 0 ? 'additional ' : ''}high-fidelity artwork...</p>
            </div>
          ) : imageResult.error ? (
            <div className="text-red-400 p-8 text-center max-w-sm">
              <p>{imageResult.error}</p>
            </div>
          ) : selectedImage ? (
            <>
              <img 
                src={selectedImage} 
                alt="Generated Art" 
                className="w-full h-full object-contain z-0"
              />
              <div className="absolute top-4 right-4 opacity-0 group-hover:opacity-100 transition-opacity duration-300 flex gap-2">
                <a 
                  href={selectedImage} 
                  download={`ai-design-${selectedImageIndex}.png`}
                  className="bg-black/60 hover:bg-black/80 text-white p-2 rounded-lg backdrop-blur-md shadow-lg"
                  title="Download"
                >
                  <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" />
                  </svg>
                </a>
              </div>
            </>
          ) : null}

          {/* Grid Overlay */}
          {!selectedImage && !imageResult.loading && (
               <div className="absolute inset-0 pointer-events-none" 
                    style={{
                      backgroundImage: 'radial-gradient(#334155 1px, transparent 1px)',
                      backgroundSize: '20px 20px',
                      opacity: 0.2
                    }}
               ></div>
          )}
        </div>

        {/* Thumbnail Grid (if multiple images) */}
        {imageResult.imageUrls.length > 0 && (
          <div className="flex gap-4 overflow-x-auto pb-2 scrollbar-thin scrollbar-thumb-slate-700">
            {imageResult.imageUrls.map((url, idx) => (
              <div 
                key={idx}
                onClick={() => setSelectedImageIndex(idx)}
                className={`w-24 h-24 flex-shrink-0 rounded-lg overflow-hidden cursor-pointer border-2 transition-all ${
                  selectedImageIndex === idx ? 'border-purple-500 shadow-lg shadow-purple-500/20' : 'border-slate-700 opacity-60 hover:opacity-100'
                }`}
              >
                <img src={url} alt={`Thumbnail ${idx}`} className="w-full h-full object-cover" />
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
};

