import React, { useState } from 'react';
import InputForm from './components/InputForm';
import ResultDisplay from './components/ResultDisplay';
import { ArtDirectionRequest, ArtDirectionResponse, ColorMode, ImageGenerationResult, ProductType, VisualStyle, QualityLevel } from './types';
import { generateArtDirection, generateDesignImage } from './services/geminiService';

const App: React.FC = () => {
  // Form State
  const [request, setRequest] = useState<ArtDirectionRequest>({
    productType: ProductType.POSTER,
    contentText: '',
    visualStyle: VisualStyle.MODERN_TECH,
    colorMode: ColorMode.AUTO,
    customColor: '#7c3aed',
    subject: '',
    width: '',
    height: '',
    assetImages: [],
    referenceImage: null,
    referenceAttributes: [],
    batchSize: 1,
    quality: QualityLevel.LOW
  });

  // Result States
  const [artDirection, setArtDirection] = useState<ArtDirectionResponse | null>(null);
  const [imageResult, setImageResult] = useState<ImageGenerationResult>({
    imageUrls: [],
    loading: false,
    error: null
  });

  // Handlers
  const handleInputChange = (field: keyof ArtDirectionRequest, value: any) => {
    setRequest(prev => ({ ...prev, [field]: value }));
  };

  const handleGenerate = async () => {
    if (!request.subject) return;

    setImageResult(prev => ({ ...prev, loading: true, error: null, imageUrls: [] }));

    try {
      // Step 1: Generate Art Direction (Prompt + Analysis)
      // Pass the images to the art director for analysis
      console.log("Generating art direction...");
      const direction = await generateArtDirection(request);
      setArtDirection(direction);

      // Step 2: Generate Images
      console.log(`Generating ${request.batchSize} images with quality ${request.quality}...`);

      const images = await generateDesignImage(
        direction.final_prompt, 
        direction.recommendedAspectRatio, 
        request.batchSize, 
        request.quality
      );

      setImageResult({
        imageUrls: images,
        loading: false,
        error: images.length === 0 ? "Failed to generate any images." : null
      });

    } catch (err: any) {
      console.error(err);
      setImageResult(prev => ({
        ...prev,
        loading: false,
        error: err.message || "Something went wrong. Please check your API key and try again."
      }));
    }
  };

  const handleRegenerateImage = async (newPrompt: string) => {
    if (!artDirection) return;

    setImageResult(prev => ({ ...prev, loading: true, error: null }));
    try {
      const images = await generateDesignImage(
        newPrompt, 
        artDirection.recommendedAspectRatio, 
        request.batchSize, 
        request.quality
      );

      setImageResult({
        imageUrls: images,
        loading: false,
        error: images.length === 0 ? "Failed to generate images." : null
      });
    } catch (err: any) {
       setImageResult(prev => ({
        ...prev,
        loading: false,
        error: err.message || "Failed to regenerate image."
      }));
    }
  };

  return (
    <div className="min-h-screen bg-[#0f172a] text-slate-200 selection:bg-purple-500/30">
      {/* Background Ambience */}
      <div className="fixed inset-0 z-0 pointer-events-none">
        <div className="absolute top-0 left-1/4 w-96 h-96 bg-purple-600/10 rounded-full blur-[100px]"></div>
        <div className="absolute bottom-0 right-1/4 w-96 h-96 bg-blue-600/10 rounded-full blur-[100px]"></div>
      </div>

      <div className="relative z-10 container mx-auto px-4 py-6 h-screen flex flex-col">
        {/* Header */}
        <header className="flex items-center justify-between mb-6 shrink-0">
          <div className="flex items-center gap-3">
             <div className="w-10 h-10 bg-gradient-to-br from-purple-500 to-blue-600 rounded-lg flex items-center justify-center shadow-lg shadow-purple-500/20">
               <span className="text-white font-bold text-xl">Ai</span>
             </div>
             <div>
               <h1 className="text-xl font-bold text-white tracking-tight">Art Director</h1>
               <p className="text-xs text-slate-400">Powered by Gemini</p>
             </div>
          </div>
          <div className="flex gap-2">
            <span className="px-3 py-1 bg-slate-800 rounded-full text-xs font-medium text-slate-400 border border-slate-700">v1.1</span>
          </div>
        </header>

        {/* Main Content Grid */}
        <main className="flex-grow grid grid-cols-1 lg:grid-cols-12 gap-6 overflow-hidden min-h-0 pb-2">
          {/* Left: Input Panel */}
          <div className="lg:col-span-4 h-full min-h-[500px]">
            <InputForm 
              values={request} 
              onChange={handleInputChange} 
              onSubmit={handleGenerate}
              isGenerating={imageResult.loading}
            />
          </div>

          {/* Right: Visualization Panel */}
          <div className="lg:col-span-8 h-full min-h-[500px]">
            <ResultDisplay 
              artDirection={artDirection} 
              imageResult={imageResult} 
              onRegenerateImage={handleRegenerateImage}
            />
          </div>
        </main>
      </div>
    </div>
  );
};

