import React, { useRef } from 'react';
import { ArtDirectionRequest, ProductType, VisualStyle, ColorMode, QualityLevel } from '../types';

interface InputFormProps {
  values: ArtDirectionRequest;
  onChange: (field: keyof ArtDirectionRequest, value: any) => void;
  onSubmit: () => void;
  isGenerating: boolean;
}

const InputForm: React.FC<InputFormProps> = ({ values, onChange, onSubmit, isGenerating }) => {
  const assetInputRef = useRef<HTMLInputElement>(null);
  const refInputRef = useRef<HTMLInputElement>(null);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>, field: 'assetImages' | 'referenceImage') => {
    const files = e.target.files;
    if (!files || files.length === 0) return;

    if (field === 'assetImages') {
      const newImages: string[] = [...values.assetImages];
      Array.from(files).forEach(file => {
        const reader = new FileReader();
        reader.onloadend = () => {
          if (reader.result) newImages.push(reader.result as string);
          // Only update state after last one (simple implementation)
          if (newImages.length === values.assetImages.length + files.length) {
             onChange('assetImages', newImages);
          }
        };
        reader.readAsDataURL(file as Blob);
      });
    } else {
      const file = files[0];
      const reader = new FileReader();
      reader.onloadend = () => {
        if (reader.result) onChange('referenceImage', reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const removeAsset = (index: number) => {
    const newImages = [...values.assetImages];
    newImages.splice(index, 1);
    onChange('assetImages', newImages);
  };

  const toggleAttribute = (attr: string) => {
    const current = [...values.referenceAttributes];
    const index = current.indexOf(attr);
    if (index > -1) {
      current.splice(index, 1);
    } else {
      current.push(attr);
    }
    onChange('referenceAttributes', current);
  };

  return (
    <div className="bg-slate-800/50 p-6 rounded-2xl border border-slate-700 shadow-xl backdrop-blur-sm h-full flex flex-col overflow-y-auto">
      <h2 className="text-xl font-bold text-white mb-6 flex items-center gap-2">
        <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6 text-purple-400" fill="none" viewBox="0 0 24 24" stroke="currentColor">
          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M11 5H6a2 2 0 00-2 2v11a2 2 0 002 2h11a2 2 0 002-2v-5m-1.414-9.414a2 2 0 112.828 2.828L11.828 15H9v-2.828l8.586-8.586z" />
        </svg>
        Creative Brief
      </h2>

      <div className="space-y-5 flex-grow">
        {/* Product Type & Dimensions */}
        <div className="grid grid-cols-2 gap-4">
          <div className="col-span-2">
            <label className="block text-sm font-medium text-slate-300 mb-1">Product Type</label>
            <select
              className="w-full bg-slate-900 border border-slate-700 rounded-lg px-4 py-2 text-white focus:ring-2 focus:ring-purple-500 outline-none"
              value={values.productType}
              onChange={(e) => onChange('productType', e.target.value)}
            >
              {Object.values(ProductType).map((type) => (
                <option key={type} value={type}>{type}</option>
              ))}
            </select>
          </div>
          <div>
            <label className="block text-sm font-medium text-slate-300 mb-1">Width</label>
            <input 
              type="text" placeholder="e.g. 1080px"
              className="w-full bg-slate-900 border border-slate-700 rounded-lg px-3 py-2 text-white text-sm focus:ring-2 focus:ring-purple-500 outline-none"
              value={values.width} onChange={(e) => onChange('width', e.target.value)}
            />
          </div>
          <div>
            <label className="block text-sm font-medium text-slate-300 mb-1">Height</label>
            <input 
              type="text" placeholder="e.g. 1920px"
              className="w-full bg-slate-900 border border-slate-700 rounded-lg px-3 py-2 text-white text-sm focus:ring-2 focus:ring-purple-500 outline-none"
              value={values.height} onChange={(e) => onChange('height', e.target.value)}
            />
          </div>
        </div>

        {/* Content & Subject */}
        <div>
          <label className="block text-sm font-medium text-slate-300 mb-1">Content Text</label>
          <input
            type="text"
            className="w-full bg-slate-900 border border-slate-700 rounded-lg px-4 py-2 text-white focus:ring-2 focus:ring-purple-500 outline-none placeholder-slate-500"
            placeholder="Headline / Slogan"
            value={values.contentText}
            onChange={(e) => onChange('contentText', e.target.value)}
          />
        </div>

        <div>
          <label className="block text-sm font-medium text-slate-300 mb-1">Subject Description</label>
          <textarea
            className="w-full bg-slate-900 border border-slate-700 rounded-lg px-4 py-2 text-white focus:ring-2 focus:ring-purple-500 outline-none placeholder-slate-500 h-20 resize-none text-sm"
            placeholder="Main product or theme description..."
            value={values.subject}
            onChange={(e) => onChange('subject', e.target.value)}
          />
        </div>

        {/* Asset Images */}
        <div>
          <label className="block text-sm font-medium text-slate-300 mb-1">Asset Images (Data)</label>
          <div className="flex flex-wrap gap-2 mb-2">
            {values.assetImages.map((img, idx) => (
              <div key={idx} className="relative w-12 h-12 rounded overflow-hidden border border-slate-600 group">
                <img src={img} alt="asset" className="w-full h-full object-cover" />
                <button 
                  onClick={() => removeAsset(idx)}
                  className="absolute inset-0 bg-black/50 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity text-white text-xs"
                >
                  X
                </button>
              </div>
            ))}
            <button 
              onClick={() => assetInputRef.current?.click()}
              className="w-12 h-12 rounded border border-dashed border-slate-500 flex items-center justify-center text-slate-400 hover:border-purple-500 hover:text-purple-500 transition-colors"
            >
              +
            </button>
          </div>
          <input 
            type="file" multiple ref={assetInputRef} className="hidden" accept="image/*"
            onChange={(e) => handleFileChange(e, 'assetImages')} 
          />
        </div>

        {/* Reference Image */}
        <div>
           <div className="flex justify-between items-center mb-1">
            <label className="text-sm font-medium text-slate-300">Reference Image (Style)</label>
            {values.referenceImage && (
              <button 
                onClick={() => onChange('referenceImage', null)}
                className="text-xs text-red-400 hover:text-red-300"
              >
                Clear
              </button>
            )}
           </div>

           {!values.referenceImage ? (
             <div 
               onClick={() => refInputRef.current?.click()}
               className="w-full h-16 border border-dashed border-slate-600 rounded-lg flex flex-col items-center justify-center cursor-pointer hover:border-purple-500 hover:bg-slate-800/50 transition-all group"
             >
               <span className="text-xs text-slate-500 group-hover:text-purple-400">Click to upload reference</span>
             </div>
           ) : (
             <div className="w-full h-32 rounded-lg border border-slate-600 overflow-hidden relative">
               <img src={values.referenceImage} alt="ref" className="w-full h-full object-cover" />
             </div>
           )}
           <input 
            type="file" ref={refInputRef} className="hidden" accept="image/*"
            onChange={(e) => handleFileChange(e, 'referenceImage')} 
           />

           {/* Reference Attributes Checkboxes */}
           {values.referenceImage && (
             <div className="mt-2 grid grid-cols-2 gap-2">
               {['Style', 'Background', 'Text Effects', 'Layout'].map((attr) => (
                 <label key={attr} className="flex items-center space-x-2 cursor-pointer">
                   <input 
                     type="checkbox" 
                     className="rounded border-slate-600 bg-slate-900 text-purple-600 focus:ring-purple-500"
                     checked={values.referenceAttributes.includes(attr)}
                     onChange={() => toggleAttribute(attr)}
                   />
                   <span className="text-xs text-slate-300">{attr}</span>
                 </label>
               ))}
             </div>
           )}
        </div>

        {/* Style & Color */}
        <div className="grid grid-cols-2 gap-4">
          <div>
            <label className="block text-sm font-medium text-slate-300 mb-1">Visual Style</label>
            <select
              className="w-full bg-slate-900 border border-slate-700 rounded-lg px-2 py-2 text-white text-sm outline-none"
              value={values.visualStyle}
              onChange={(e) => onChange('visualStyle', e.target.value)}
            >
              {Object.values(VisualStyle).map((style) => (
                <option key={style} value={style}>{style}</option>
              ))}
            </select>
          </div>
          <div>
            <label className="block text-sm font-medium text-slate-300 mb-1">Color Mode</label>
            <select
               className="w-full bg-slate-900 border border-slate-700 rounded-lg px-2 py-2 text-white text-sm outline-none"
               value={values.colorMode}
               onChange={(e) => onChange('colorMode', e.target.value)}
            >
               <option value={ColorMode.AUTO}>Auto</option>
               <option value={ColorMode.CUSTOM}>Custom</option>
            </select>
          </div>
        </div>
        {values.colorMode === ColorMode.CUSTOM && (
             <div className="flex items-center gap-2">
                <input
                 type="color"
                 value={values.customColor}
                 onChange={(e) => onChange('customColor', e.target.value)}
                 className="h-8 w-8 rounded border-0 cursor-pointer bg-transparent"
               />
               <input
                 type="text"
                 value={values.customColor}
                 onChange={(e) => onChange('customColor', e.target.value)}
                 className="flex-1 bg-slate-900 border border-slate-700 rounded-lg px-3 py-1.5 text-white text-xs"
               />
             </div>
        )}

        {/* Output Settings */}
        <div className="pt-2 border-t border-slate-700/50">
           <label className="block text-xs font-bold text-slate-400 uppercase tracking-wider mb-3">Output Settings</label>

           <div className="grid grid-cols-2 gap-4 mb-4">
             <div>
               <label className="block text-xs text-slate-300 mb-1">Quantity</label>
               <div className="flex bg-slate-900 rounded-lg p-1 border border-slate-700">
                  {[1, 3, 5].map(num => (
                    <button
                      key={num}
                      onClick={() => onChange('batchSize', num)}
                      className={`flex-1 text-xs py-1.5 rounded transition-all ${
                        values.batchSize === num ? 'bg-purple-600 text-white shadow' : 'text-slate-400 hover:text-white'
                      }`}
                    >
                      {num}
                    </button>
                  ))}
               </div>
             </div>

             <div>
               <label className="block text-xs text-slate-300 mb-1">Quality</label>
               <select
                 className="w-full bg-slate-900 border border-slate-700 rounded-lg px-2 py-1.5 text-white text-xs outline-none h-[30px]"
                 value={values.quality}
                 onChange={(e) => onChange('quality', e.target.value)}
               >
                 <option value={QualityLevel.LOW}>Low (1K)</option>
                 <option value={QualityLevel.MEDIUM}>Medium (2K)</option>
                 <option value={QualityLevel.HIGH}>High (4K)</option>
               </select>
             </div>
           </div>
        </div>

      </div>

      <div className="pt-4 border-t border-slate-700 mt-2">
        <button
          onClick={onSubmit}
          disabled={isGenerating || !values.subject}
          className={`w-full py-3 px-6 rounded-lg text-white font-semibold shadow-lg transition-all duration-300 transform hover:scale-[1.02] flex items-center justify-center gap-2
            ${isGenerating || !values.subject
              ? 'bg-slate-700 cursor-not-allowed text-slate-400'
              : 'bg-gradient-to-r from-purple-600 to-blue-600 hover:from-purple-500 hover:to-blue-500 hover:shadow-purple-500/25'
            }`}
        >
          {isGenerating ? (
            <>
              <svg className="animate-spin -ml-1 mr-3 h-5 w-5 text-white" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
              </svg>
              Processing...
            </>
          ) : (
            <>
              Generate Design
              <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 10V3L4 14h7v7l9-11h-7z" />
              </svg>
            </>
          )}
        </button>
      </div>
    </div>
  );
};

