import React, { useRef } from 'react';
import { ArtDirectionRequest, ProductType, VisualStyle, ColorMode, QualityLevel } from '../types';

interface InputFormProps {
  values: ArtDirectionRequest;
  onChange: (field: keyof ArtDirectionRequest, value: any) => void;
  onSubmit: () => void;
  isGenerating: boolean;
}

const InputForm: React.FC<InputFormProps> = ({ values, onChange, onSubmit, isGenerating }) => {
  const assetInputRef = useRef<HTMLInputElement>(null);
  const refInputRef = useRef<HTMLInputElement>(null);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>, field: 'assetImages' | 'referenceImage') => {
    const files = e.target.files;
    if (!files || files.length === 0) return;

    if (field === 'assetImages') {
      const newImages: string[] = [...values.assetImages];
      Array.from(files).forEach(file => {
        const reader = new FileReader();
        reader.onloadend = () => {
          if (reader.result) newImages.push(reader.result as string);
          // Only update state after last one (simple implementation)
          if (newImages.length === values.assetImages.length + files.length) {
             onChange('assetImages', newImages);
          }
        };
        reader.readAsDataURL(file as Blob);
      });
    } else {
      const file = files[0];
      const reader = new FileReader();
      reader.onloadend = () => {
        if (reader.result) onChange('referenceImage', reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const removeAsset = (index: number) => {
    const newImages = [...values.assetImages];
    newImages.splice(index, 1);
    onChange('assetImages', newImages);
  };

  const toggleAttribute = (attr: string) => {
    const current = [...values.referenceAttributes];
    const index = current.indexOf(attr);
    if (index > -1) {
