import { GoogleGenAI, Type, Schema } from "@google/genai";
import { ArtDirectionRequest, ArtDirectionResponse } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const SYSTEM_INSTRUCTION = `
You are a professional "AI Art Director" in the print & advertising design field. Your task is to transform raw user requests AND provided visual assets/references into a HIGHLY SPECIALIZED ENGLISH PROMPT for an image generation model.

### INPUT DATA
1. **Product Type:** (Poster, Backdrop, Banner...)
2. **Dimensions:** (User preferred size in cm)
3. **Content - Main Headline:** (Primary big text)
4. **Content - Secondary Text:** (Subtitles, body text)
5. **Layout & Placement:** (Specific requirements for where things go)
6. **Visual Style:** (Modern Tech, Luxury...)
7. **Color Mode:** (Auto or Hex Palette)
8. **Image Elements Description:** (Description of objects/scenes)
9. **Assets:** (Images of products to include)
10. **Reference Image & Attributes:** (User provided reference and specific aspects to mimic: Style, Background, Text Effects, Layout)

### LOGIC CORE & CONSTRAINTS

**1. LAYOUT RULES**
* IF **Poster/Standee (Vertical):** Priority: Vertical composition, Central focus.
* IF **Backdrop (Wide):** Priority: Ultra-wide angle, Symmetrical.
* IF **Banner (Narrow):** Priority: Split layout.
* **Layout Requirements:** YOU MUST strictly follow the user's "Layout & Placement" instructions if provided (e.g., "Logo top right", "Empty space in center").
* **Reference Constraint:** If a Reference Image is provided AND 'Layout' attribute is checked, you MUST describe the composition of the reference image in the prompt and instruct the model to follow it.

**2. VISUAL ANALYSIS & INTEGRATION**
* **Asset Images:** If provided, describe them in detail (color, shape, material) in the prompt so the image generator can reconstruct a similar object.
* **Image Elements:** Use the "Image Elements Description" to build the scene, characters, and environment.
* **Reference Attributes:**
    * **Style:** Mimic the artistic style (e.g., watercolor, 3D render, flat vector).
    * **Background:** Mimic the setting/environment.
    * **Text Effects:** Describe the typography style (e.g., neon, metallic, bold serif) for the Main Headline.
    * **Layout:** Mimic the object placement and hierarchy.

**3. QUALITY SPECS**
* Always add: "High fidelity, 8k resolution, highly detailed, professional graphic design, print quality text rendering."

### OUTPUT FORMAT
Return a JSON object with:
1. "analysis": Brief explanation of layout/color choices and how the reference was applied.
2. "final_prompt": The complete English prompt.
3. "recommendedAspectRatio": The most suitable aspect ratio for the image model strictly selected from: "1:1", "3:4", "4:3", "9:16", "16:9" based on the user's requested dimensions.
`;

const RESPONSE_SCHEMA: Schema = {
  type: Type.OBJECT,
  properties: {
    analysis: {
      type: Type.STRING,
      description: "Brief explanation of the design choices.",
    },
    final_prompt: {
      type: Type.STRING,
      description: "The highly detailed prompt for the image generator.",
    },
    recommendedAspectRatio: {
      type: Type.STRING,
      enum: ["1:1", "3:4", "4:3", "9:16", "16:9"],
      description: "The best aspect ratio supported by the API.",
    },
  },
  required: ["analysis", "final_prompt", "recommendedAspectRatio"],
};

export const generateArtDirection = async (request: ArtDirectionRequest): Promise<ArtDirectionResponse> => {
  try {
    // Construct the multimodal prompt
    const parts: any[] = [];

    // 1. Text Prompt
    let promptText = `
      Product Type: ${request.productType}
      Dimensions: ${request.width}cm x ${request.height}cm

      -- CONTENT --
      Main Headline (Big Text): "${request.mainHeadline}"
      Secondary Text (Small Text): "${request.secondaryText}"

      -- REQUIREMENTS --
      Layout & Placement Instructions: "${request.layoutRequirements}"
      Image Elements/Scene Description: "${request.imageElementDescription}"

      -- STYLE --
      Visual Style: ${request.visualStyle}
      Color Mode: ${request.colorMode === 'Custom' ? `Custom Palette (${request.customColors.join(', ')})` : 'Auto'}
    `;

    if (request.referenceAttributes.length > 0) {
      promptText += `\nReference Image Attributes to Mimic: ${request.referenceAttributes.join(', ')}`;
    }

    parts.push({ text: promptText });

    // 2. Reference Image
    if (request.referenceImage) {
      parts.push({ text: "Reference Image (Use this for style/layout/etc as requested):" });
      parts.push({
        inlineData: {
          mimeType: "image/png",
          data: request.referenceImage.split(',')[1] // Remove data:image/png;base64, prefix
        }
      });
    }

    // 3. Asset Images
    if (request.assetImages && request.assetImages.length > 0) {
      parts.push({ text: "Asset Images (The main products/elements to verify and describe in the prompt):" });
      request.assetImages.forEach((imgBase64, index) => {
        parts.push({
          inlineData: {
            mimeType: "image/png",
            data: imgBase64.split(',')[1]
          }
        });
      });
    }

    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: { parts },
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        responseMimeType: "application/json",
        responseSchema: RESPONSE_SCHEMA,
      },
    });

    const text = response.text;
    if (!text) throw new Error("No response from AI Director");

    return JSON.parse(text) as ArtDirectionResponse;
  } catch (error) {
    console.error("Error generating art direction:", error);
    throw error;
  }
};

export const generateDesignImage = async (
  prompt: string, 
  aspectRatio: string, 
  batchSize: number, 
  imageSize: string
): Promise<string[]> => {
  try {
    const modelName = "gemini-3-pro-image-preview";
    const imageUrls: string[] = [];

    // The API typically generates 1 image per request for high quality models.
    // To support batch size, we execute requests in sequence or parallel.
    // Given rate limits, sequential is often safer, but parallel is faster.
    // We will try parallel requests.

    const promises = Array.from({ length: batchSize }).map(async () => {
      const response = await ai.models.generateContent({
        model: modelName,
        contents: { parts: [{ text: prompt }] },
        config: {
          imageConfig: {
            aspectRatio: aspectRatio,
            imageSize: imageSize // "1K", "2K", "4K"
          }
        },
      });

      for (const part of response.candidates?.[0]?.content?.parts || []) {
        if (part.inlineData) {
          return `data:image/png;base64,${part.inlineData.data}`;
        }
      }
      return null;
    });

