import React, { useRef, useMemo } from 'react';
import { ArtDirectionRequest, ProductType, VisualStyle, ColorMode, QualityLevel } from '../types';

interface InputFormProps {
  values: ArtDirectionRequest;
  onChange: (field: keyof ArtDirectionRequest, value: any) => void;
  onSubmit: () => void;
  isGenerating: boolean;
}

const InputForm: React.FC<InputFormProps> = ({ values, onChange, onSubmit, isGenerating }) => {
  const assetInputRef = useRef<HTMLInputElement>(null);
  const refInputRef = useRef<HTMLInputElement>(null);

  // Calculate estimated pixels based on dimensions (cm) and Quality Level (1K/2K/4K)
  const estimatedPixels = useMemo(() => {
    if (!values.width || !values.height) return null;
    const w = parseFloat(values.width);
    const h = parseFloat(values.height);

    if (isNaN(w) || isNaN(h) || w === 0 || h === 0) return null;

    // Define max dimension based on Quality Level
    let maxDim = 1024; // Default Low/1K
    if (values.quality === QualityLevel.MEDIUM) maxDim = 2048; // 2K
    if (values.quality === QualityLevel.HIGH) maxDim = 4096; // 4K

    const aspectRatio = w / h;
    let pxWidth, pxHeight;

    if (w >= h) {
        // Landscape or Square
        pxWidth = maxDim;
        pxHeight = Math.round(maxDim / aspectRatio);
    } else {
        // Portrait
        pxHeight = maxDim;
        pxWidth = Math.round(maxDim * aspectRatio);
    }

    return `${pxWidth} x ${pxHeight} px`;
  }, [values.width, values.height, values.quality]);


  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>, field: 'assetImages' | 'referenceImage') => {
    const files = e.target.files;
    if (!files || files.length === 0) return;

    if (field === 'assetImages') {
      const newImages: string[] = [...values.assetImages];
      Array.from(files).forEach(file => {
        const reader = new FileReader();
        reader.onloadend = () => {
          if (reader.result) newImages.push(reader.result as string);
          // Only update state after last one (simple implementation)
          if (newImages.length === values.assetImages.length + files.length) {
             onChange('assetImages', newImages);
          }
        };
        reader.readAsDataURL(file as Blob);
      });
    } else {
      const file = files[0];
      const reader = new FileReader();
      reader.onloadend = () => {
        if (reader.result) onChange('referenceImage', reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const removeAsset = (index: number) => {
    const newImages = [...values.assetImages];
    newImages.splice(index, 1);
    onChange('assetImages', newImages);
  };

  const toggleAttribute = (attr: string) => {
    const current = [...values.referenceAttributes];
    const index = current.indexOf(attr);
    if (index > -1) {
      current.splice(index, 1);
    } else {
      current.push(attr);
    }
    onChange('referenceAttributes', current);
  };

  const handleColorChange = (index: number, value: string) => {
    const newColors = [...values.customColors];
    newColors[index] = value;
    onChange('customColors', newColors);
  };

  const addColor = () => {
    if (values.customColors.length < 5) { // Limit to reasonable amount
        onChange('customColors', [...values.customColors, '#000000']);
    }
  };

  const removeColor = (index: number) => {
    if (values.customColors.length > 1) {
        const newColors = values.customColors.filter((_, i) => i !== index);
        onChange('customColors', newColors);
    }
  };

  return (
    <div className="bg-slate-800/50 p-6 rounded-2xl border border-slate-700 shadow-xl backdrop-blur-sm h-full flex flex-col overflow-y-auto">
      <h2 className="text-xl font-bold text-white mb-6 flex items-center gap-2">
        <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6 text-purple-400" fill="none" viewBox="0 0 24 24" stroke="currentColor">
          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M11 5H6a2 2 0 00-2 2v11a2 2 0 002 2h11a2 2 0 002-2v-5m-1.414-9.414a2 2 0 112.828 2.828L11.828 15H9v-2.828l8.586-8.586z" />
        </svg>
        Creative Brief
      </h2>

      <div className="space-y-5 flex-grow">
        {/* Product Type & Dimensions */}
        <div className="grid grid-cols-2 gap-4">
          <div className="col-span-2">
