3. "recommendedAspectRatio": The most suitable aspect ratio for the image model strictly selected from: "1:1", "3:4", "4:3", "9:16", "16:9" based on the user's requested dimensions.
`;

const RESPONSE_SCHEMA: Schema = {
  type: Type.OBJECT,
  properties: {
    analysis: {
      type: Type.STRING,
      description: "Brief explanation of the design choices.",
    },
    final_prompt: {
      type: Type.STRING,
      description: "The highly detailed prompt for the image generator.",
    },
