export enum ProductType {
  POSTER = 'Poster',
  STANDEE = 'Standee',
  BACKDROP = 'Backdrop',
  BANNER = 'Banner',
  SOCIAL_POST = 'Social Media Post',
  FLYER = 'Flyer'
}

export enum VisualStyle {
  MODERN_TECH = 'Modern Tech',
  LUXURY = 'Luxury',
  VINTAGE = 'Vintage',
  FESTIVE = 'Festive',
  MINIMALIST = 'Minimalist',
  CORPORATE = 'Corporate',
  CYBERPUNK = 'Cyberpunk',
  NATURAL_ORGANIC = 'Natural/Organic'
}

export enum ColorMode {
  AUTO = 'Auto',
  CUSTOM = 'Custom'
}

export enum QualityLevel {
  LOW = '1K',
  MEDIUM = '2K',
  HIGH = '4K'
}

export interface ArtDirectionRequest {
  productType: ProductType;
  // Content Text Split
  mainHeadline: string;
  mainHeadlineImage: string | null; // Image reference specifically for the headline style
  secondaryText: string;

  visualStyle: VisualStyle;
  colorMode: ColorMode;
  customColors: string[];

  // Design Requirements
  layoutRequirements: string; // Specific placement instructions
  imageElementDescription: string; // Description of objects/elements in the image
  fontPreferences: string; // New field for typography/font usage

  width: string;
  height: string;
  assetImages: string[]; // Base64 strings
  referenceImage: string | null; // Base64 string
  referenceAttributes: string[]; // 'style', 'background', 'text_effects', 'layout'
  batchSize: 1 | 3 | 5;
  quality: QualityLevel;
}

export interface ArtDirectionResponse {
  analysis: string;
  final_prompt: string;
  recommendedAspectRatio: "1:1" | "3:4" | "4:3" | "9:16" | "16:9";
}

export interface ImageGenerationResult {
  imageUrls: string[];
  loading: boolean;
  error: string | null;
}

export interface SeparatedAssets {
  background: string | null;
  textLayer: string | null;
  elements: string | null;
  loading: boolean;
  error: string | null;
}

import React, { useState } from 'react';
import InputForm from './components/InputForm';
import ResultDisplay from './components/ResultDisplay';
import { ArtDirectionRequest, ArtDirectionResponse, ColorMode, ImageGenerationResult, ProductType, VisualStyle, QualityLevel, SeparatedAssets } from './types';
import { generateArtDirection, generateDesignImage, separateDesignComponents } from './services/geminiService';

const App: React.FC = () => {
  // Form State
  const [request, setRequest] = useState<ArtDirectionRequest>({
    productType: ProductType.POSTER,
    mainHeadline: '',
    mainHeadlineImage: null,
    secondaryText: '',
    layoutRequirements: '',
    imageElementDescription: '',
    fontPreferences: '',
    visualStyle: VisualStyle.MODERN_TECH,
    colorMode: ColorMode.AUTO,
    customColors: ['#7c3aed', '#2563eb'],
    width: '',
    height: '',
    assetImages: [],
    referenceImage: null,
    referenceAttributes: [],
    batchSize: 1,
    quality: QualityLevel.LOW
  });

  // Result States
  const [artDirection, setArtDirection] = useState<ArtDirectionResponse | null>(null);
  const [imageResult, setImageResult] = useState<ImageGenerationResult>({
    imageUrls: [],
    loading: false,
    error: null
  });

  const [separatedAssets, setSeparatedAssets] = useState<SeparatedAssets>({
    background: null,
    textLayer: null,
    elements: null,
    loading: false,
    error: null
  });

  // Handlers
  const handleInputChange = (field: keyof ArtDirectionRequest, value: any) => {
    setRequest(prev => ({ ...prev, [field]: value }));
  };

  const handleGenerate = async () => {
    if (!request.mainHeadline && !request.imageElementDescription) return;

    setImageResult(prev => ({ ...prev, loading: true, error: null, imageUrls: [] }));
    setSeparatedAssets({ background: null, textLayer: null, elements: null, loading: false, error: null }); // Reset separation

    try {
      // Step 1: Generate Art Direction (Prompt + Analysis)
      // Pass the images to the art director for analysis
      console.log("Generating art direction...");
      const direction = await generateArtDirection(request);
      setArtDirection(direction);

      // Step 2: Generate Images
      console.log(`Generating ${request.batchSize} images with quality ${request.quality}...`);

      const images = await generateDesignImage(
        direction.final_prompt, 
        direction.recommendedAspectRatio, 
        request.batchSize, 
        request.quality
      );

      setImageResult({
        imageUrls: images,
        loading: false,
        error: images.length === 0 ? "Failed to generate any images." : null
      });

    } catch (err: any) {
      console.error(err);
      setImageResult(prev => ({
        ...prev,
        loading: false,
        error: err.message || "Something went wrong. Please check your API key and try again."
      }));
    }
  };

  const handleRegenerateImage = async (newPrompt: string) => {
    if (!artDirection) return;

    setImageResult(prev => ({ ...prev, loading: true, error: null }));
    setSeparatedAssets({ background: null, textLayer: null, elements: null, loading: false, error: null });

    try {
      const images = await generateDesignImage(
        newPrompt, 
        artDirection.recommendedAspectRatio, 
        request.batchSize, 
        request.quality
      );

      setImageResult({
        imageUrls: images,
        loading: false,
        error: images.length === 0 ? "Failed to generate images." : null
      });
    } catch (err: any) {
       setImageResult(prev => ({
        ...prev,
        loading: false,
        error: err.message || "Failed to regenerate image."
      }));
    }
  };

  const handleSeparateLayout = async () => {
    if (!artDirection) return;

    setSeparatedAssets(prev => ({ ...prev, loading: true, error: null }));

    try {
       const result = await separateDesignComponents(
         artDirection.final_prompt,
         artDirection.recommendedAspectRatio,
         request.quality
       );

       setSeparatedAssets({
         background: result.background,
         textLayer: result.textLayer,
         elements: result.elements,
         loading: false,
         error: (!result.background && !result.textLayer) ? "Failed to separate assets." : null
       });

    } catch (err: any) {
      setSeparatedAssets(prev => ({
        ...prev,
        loading: false,
        error: err.message || "Failed to separate layout."
      }));
    }
  };

  return (
    <div className="min-h-screen bg-[#0f172a] text-slate-200 selection:bg-purple-500/30">
      {/* Background Ambience */}
      <div className="fixed inset-0 z-0 pointer-events-none">
        <div className="absolute top-0 left-1/4 w-96 h-96 bg-purple-600/10 rounded-full blur-[100px]"></div>
        <div className="absolute bottom-0 right-1/4 w-96 h-96 bg-blue-600/10 rounded-full blur-[100px]"></div>
      </div>

      <div className="relative z-10 container mx-auto px-4 py-6 h-screen flex flex-col">
        {/* Header */}
        <header className="flex items-center justify-between mb-6 shrink-0">
          <div className="flex items-center gap-3">
             <div className="w-10 h-10 bg-gradient-to-br from-purple-500 to-blue-600 rounded-lg flex items-center justify-center shadow-lg shadow-purple-500/20">
               <span className="text-white font-bold text-xl">Ai</span>
             </div>
             <div>
               <h1 className="text-xl font-bold text-white tracking-tight">Art Director</h1>
               <p className="text-xs text-slate-400">Powered by Gemini</p>
             </div>
          </div>
          <div className="flex gap-2">
            <span className="px-3 py-1 bg-slate-800 rounded-full text-xs font-medium text-slate-400 border border-slate-700">v1.3</span>
          </div>
        </header>

        {/* Main Content Grid */}
        <main className="flex-grow grid grid-cols-1 lg:grid-cols-12 gap-6 overflow-hidden min-h-0 pb-2">
          {/* Left: Input Panel */}
          <div className="lg:col-span-4 h-full min-h-[500px]">
            <InputForm 
              values={request} 
              onChange={handleInputChange} 
              onSubmit={handleGenerate}
              isGenerating={imageResult.loading}
            />
          </div>

          {/* Right: Visualization Panel */}
          <div className="lg:col-span-8 h-full min-h-[500px]">
            <ResultDisplay 
              artDirection={artDirection} 
              imageResult={imageResult} 
              onRegenerateImage={handleRegenerateImage}
              onSeparateLayout={handleSeparateLayout}
              separatedAssets={separatedAssets}
            />
          </div>
        </main>
      </div>
    </div>
  );
};

export default App;

import React, { useRef, useMemo } from 'react';
import { ArtDirectionRequest, ProductType, VisualStyle, ColorMode, QualityLevel } from '../types';

interface InputFormProps {
  values: ArtDirectionRequest;
  onChange: (field: keyof ArtDirectionRequest, value: any) => void;
  onSubmit: () => void;
  isGenerating: boolean;
}

const InputForm: React.FC<InputFormProps> = ({ values, onChange, onSubmit, isGenerating }) => {
  const assetInputRef = useRef<HTMLInputElement>(null);
  const refInputRef = useRef<HTMLInputElement>(null);
  const headlineImageInputRef = useRef<HTMLInputElement>(null);

  // Calculate estimated pixels based on dimensions (cm) and Quality Level (1K/2K/4K)
  const estimatedPixels = useMemo(() => {
    if (!values.width || !values.height) return null;
    const w = parseFloat(values.width);
    const h = parseFloat(values.height);

    if (isNaN(w) || isNaN(h) || w === 0 || h === 0) return null;

    // Define max dimension based on Quality Level
    let maxDim = 1024; // Default Low/1K
    if (values.quality === QualityLevel.MEDIUM) maxDim = 2048; // 2K
    if (values.quality === QualityLevel.HIGH) maxDim = 4096; // 4K

    const aspectRatio = w / h;
    let pxWidth, pxHeight;

    if (w >= h) {
        // Landscape or Square
        pxWidth = maxDim;
        pxHeight = Math.round(maxDim / aspectRatio);
    } else {
        // Portrait
        pxHeight = maxDim;
        pxWidth = Math.round(maxDim * aspectRatio);
    }

    return `${pxWidth} x ${pxHeight} px`;
  }, [values.width, values.height, values.quality]);


  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>, field: 'assetImages' | 'referenceImage' | 'mainHeadlineImage') => {
    const files = e.target.files;
    if (!files || files.length === 0) return;

    if (field === 'assetImages') {
      const newImages: string[] = [...values.assetImages];
      Array.from(files).forEach(file => {
        const reader = new FileReader();
        reader.onloadend = () => {
          if (reader.result) newImages.push(reader.result as string);
          // Only update state after last one (simple implementation)
          if (newImages.length === values.assetImages.length + files.length) {
             onChange('assetImages', newImages);
          }
        };
        reader.readAsDataURL(file as Blob);
      });
    } else {
      const file = files[0];
      const reader = new FileReader();
      reader.onloadend = () => {
        if (reader.result) onChange(field, reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const removeAsset = (index: number) => {
    const newImages = [...values.assetImages];
    newImages.splice(index, 1);
    onChange('assetImages', newImages);
  };

  const toggleAttribute = (attr: string) => {
    const current = [...values.referenceAttributes];
    const index = current.indexOf(attr);
    if (index > -1) {
      current.splice(index, 1);
    } else {
      current.push(attr);
    }
    onChange('referenceAttributes', current);
  };

  const handleColorChange = (index: number, value: string) => {
    const newColors = [...values.customColors];
    newColors[index] = value;
    onChange('customColors', newColors);
  };

  const addColor = () => {
    if (values.customColors.length < 5) { // Limit to reasonable amount
        onChange('customColors', [...values.customColors, '#000000']);
    }
  };

  const removeColor = (index: number) => {
    if (values.customColors.length > 1) {
        const newColors = values.customColors.filter((_, i) => i !== index);
        onChange('customColors', newColors);
    }
  };

  return (
    <div className="bg-slate-800/50 p-6 rounded-2xl border border-slate-700 shadow-xl backdrop-blur-sm h-full flex flex-col overflow-y-auto">
      <h2 className="text-xl font-bold text-white mb-6 flex items-center gap-2">
        <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6 text-purple-400" fill="none" viewBox="0 0 24 24" stroke="currentColor">
          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M11 5H6a2 2 0 00-2 2v11a2 2 0 002 2h11a2 2 0 002-2v-5m-1.414-9.414a2 2 0 112.828 2.828L11.828 15H9v-2.828l8.586-8.586z" />
        </svg>
        Creative Brief
      </h2>

      <div className="space-y-5 flex-grow">
        {/* Product Type & Dimensions */}
        <div className="grid grid-cols-2 gap-4">
          <div className="col-span-2">
            <label className="block text-sm font-medium text-slate-300 mb-1">Product Type</label>
            <select
              className="w-full bg-slate-900 border border-slate-700 rounded-lg px-4 py-2 text-white focus:ring-2 focus:ring-purple-500 outline-none"
              value={values.productType}
              onChange={(e) => onChange('productType', e.target.value)}
            >
              {Object.values(ProductType).map((type) => (
                <option key={type} value={type}>{type}</option>
              ))}
            </select>
          </div>
          <div>
            <label className="block text-sm font-medium text-slate-300 mb-1">Width (cm)</label>
            <input 
              type="number" placeholder="e.g. 60"
              className="w-full bg-slate-900 border border-slate-700 rounded-lg px-3 py-2 text-white text-sm focus:ring-2 focus:ring-purple-500 outline-none"
              value={values.width} onChange={(e) => onChange('width', e.target.value)}
            />
          </div>
          <div>
            <label className="block text-sm font-medium text-slate-300 mb-1">Height (cm)</label>
            <input 
              type="number" placeholder="e.g. 160"
              className="w-full bg-slate-900 border border-slate-700 rounded-lg px-3 py-2 text-white text-sm focus:ring-2 focus:ring-purple-500 outline-none"
              value={values.height} onChange={(e) => onChange('height', e.target.value)}
            />
          </div>
          {/* Pixel Output Indicator */}
          <div className="col-span-2 -mt-2">
             {estimatedPixels ? (
                <div className="flex items-center gap-2 bg-slate-900/50 rounded px-2 py-1.5 border border-slate-700/50">
                    <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4 text-purple-400" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 8V4m0 0h4M4 4l5 5m11-1V4m0 0h-4m4 4l-5 5M4 16v4m0 0h4m-4 0l5-5m11 5l-5-5m5 5v-4m0 4h-4" />
                    </svg>
                    <span className="text-xs text-slate-400">Est. Output Resolution: <span className="text-white font-mono font-medium">{estimatedPixels}</span></span>
                </div>
             ) : (
                <div className="flex items-center gap-2 px-2 py-1">
                   <span className="text-xs text-slate-600">Enter dimensions to see output pixels</span>
                </div>
             )}
          </div>
        </div>

        {/* Content Section Split */}
        <div className="space-y-3 p-3 bg-slate-900/30 rounded-lg border border-slate-700/50">
          <label className="block text-xs font-bold text-slate-400 uppercase tracking-wider">Content Info</label>

