import { ArtDirectionRequest, ArtDirectionResponse, ProductImageMode, VisualStyle, ColorMode } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const SYSTEM_INSTRUCTION = `
You are a professional "AI Art Director" in the print & advertising design field. Your task is to transform raw user requests (likely in Vietnamese) AND provided visual assets/references into a HIGHLY SPECIALIZED ENGLISH PROMPT for an image generation model.

### INPUT DATA
1. **Product Type:** (Poster, Backdrop, Banner...)
2. **Dimensions:** (User preferred size in cm)
3. **Content - Main Headline:** (Primary big text)
4. **Content - Secondary Text:** (Subtitles, body text)
5. **Layout & Placement:** (Specific requirements for where things go)
6. **Visual Style:** (Modern Tech, Luxury...)
7. **Color Mode:** (Auto or Hex Palette)
8. **Image Elements Description:** (Description of objects/scenes)
9. **Typography/Font Preference:** (Specific font styles or typography instructions)
10. **Assets:** (Images of products to include)
11. **Asset Processing Mode:** (Realistic/Sharpen vs Stylized)
12. **Logo:** (Brand Logo image)
13. **Reference Image & Attributes:** (User provided reference and specific aspects to mimic: Style, Background, Text Effects, Layout)
14. **Main Headline Image:** (Visual reference specifically for the main text style)

### LOGIC CORE & CONSTRAINTS

**1. LANGUAGE PROCESSING**
* **TRANSLATION:** The user input will mostly be in Vietnamese. You MUST translate all descriptions, styles, and requirements into professional **ENGLISH** for the \`final_prompt\`.
* **ANALYSIS:** However, the \`analysis\` field in the JSON response MUST be in **VIETNAMESE** so the user can understand your creative decisions.

**2. ASSET HANDLING RULES**
* **LOGO:** If a Logo is provided, the prompt MUST instruct the generator to include the specific logo reference in the composition, keeping it unchanged as much as possible.
* **PRODUCT IMAGES:**
    * **IF MODE = 'Realistic' (Làm Nét):** Prompt for "High fidelity, photorealistic render of the product provided in reference. Isolate the product from its original background and composite it seamlessly into the new design."
    * **IF MODE = 'Stylized' (AI Cách Điệu):** Prompt for "Artistic interpretation of the product provided in reference, matching the overall [Visual Style] of the poster."

**3. LAYOUT RULES**
* IF **Poster/Standee (Vertical):** Priority: Vertical composition, Central focus.
* IF **Backdrop (Wide):** Priority: Ultra-wide angle, Symmetrical.
* IF **Banner (Narrow):** Priority: Split layout.
* **Layout Requirements:** YOU MUST strictly follow the user's "Layout & Placement" instructions if provided.

**4. QUALITY SPECS**
* Always add: "High fidelity, 8k resolution, highly detailed, professional graphic design, print quality text rendering, flat 2D digital artwork."

### OUTPUT FORMAT
Return a JSON object with:
1. "analysis": Brief explanation of layout/color choices and how the assets (Logo/Product) are treated (IN VIETNAMESE).
2. "final_prompt": The complete English prompt.
3. "recommendedAspectRatio": The most suitable aspect ratio for the image model strictly selected from: "1:1", "3:4", "4:3", "9:16", "16:9" based on the user's requested dimensions.
`;

const RESPONSE_SCHEMA: Schema = {
  type: Type.OBJECT,
  properties: {
    analysis: {
      type: Type.STRING,
      description: "Brief explanation of the design choices in Vietnamese.",
    },
    final_prompt: {
      type: Type.STRING,
      description: "The highly detailed prompt for the image generator in English.",
    },
    recommendedAspectRatio: {
      type: Type.STRING,
      enum: ["1:1", "3:4", "4:3", "9:16", "16:9"],
      description: "The best aspect ratio supported by the API.",
    },
  },
  required: ["analysis", "final_prompt", "recommendedAspectRatio"],
};

export const generateArtDirection = async (request: ArtDirectionRequest): Promise<ArtDirectionResponse> => {
  try {
    // Construct the multimodal prompt
    const parts: any[] = [];

    // Helper to format style string
    let styleInstruction = request.visualStyle;
    if (request.visualStyle === VisualStyle.FOLLOW_REF) {
        styleInstruction = "STRICTLY MIMIC the artistic style, rendering technique, and vibe of the General Reference Image provided.";
    }

    // Helper to format color string
    let colorInstruction = request.colorMode === 'Custom' 
      ? `Custom Palette (${request.customColors.join(', ')})` 
      : 'Auto';

    if (request.colorMode === ColorMode.BRAND_LOGO) {
        colorInstruction = "EXTRACT the dominant colors from the provided Brand Logo and use them as the primary color palette.";
    }

    // 1. Text Prompt
    let promptText = `
      Product Type: ${request.productType}
      Dimensions: ${request.width}cm x ${request.height}cm

      -- CONTENT --
      Main Headline (Big Text): "${request.mainHeadline}"
      Secondary Text (Small Text): "${request.secondaryText}"

      -- REQUIREMENTS --
      Layout & Placement Instructions: "${request.layoutRequirements}"
      Image Elements/Scene Description: "${request.imageElementDescription}"
      Typography/Font Usage: "${request.fontPreferences}"

      -- STYLE --
      Visual Style: ${styleInstruction}
      Color Mode: ${colorInstruction}

      -- ASSETS CONFIG --
      Product Image Mode: ${request.productImageMode}
      Has Logo: ${request.logoImage ? 'YES' : 'NO'}
    `;

    if (request.referenceAttributes.length > 0) {
      promptText += `\nReference Image Attributes to Mimic: ${request.referenceAttributes.join(', ')}`;
    }

    parts.push({ text: promptText });

    // 2. Logo Reference
    if (request.logoImage) {
      parts.push({ text: "Brand Logo Image (To be placed in design):" });
      parts.push({
        inlineData: {
          mimeType: "image/png",
          data: request.logoImage.split(',')[1]
        }
      });
    }

    // 3. Asset Images (Products)
    if (request.assetImages && request.assetImages.length > 0) {
      parts.push({ text: "Product Asset Images (Subject matter):" });
      request.assetImages.forEach((imgBase64, index) => {
        parts.push({
          inlineData: {
            mimeType: "image/png",
            data: imgBase64.split(',')[1]
          }
        });
      });
    }

    // 4. Main Headline Reference Image
    if (request.mainHeadlineImage) {
      parts.push({ text: "Reference Image for MAIN HEADLINE STYLE (Mimic this specific font/texture/effect):" });
      parts.push({
        inlineData: {
          mimeType: "image/png",
          data: request.mainHeadlineImage.split(',')[1]
        }
      });
    }

    // 5. Overall Reference Image
    if (request.referenceImage) {
      parts.push({ text: "General Reference Image (Use for style/layout):" });
      parts.push({
        inlineData: {
          mimeType: "image/png",
          data: request.referenceImage.split(',')[1]
        }
      });
    }

    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: { parts },
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        responseMimeType: "application/json",
        responseSchema: RESPONSE_SCHEMA,
      },
    });

    const text = response.text;
    if (!text) throw new Error("No response from AI Director");

    return JSON.parse(text) as ArtDirectionResponse;
  } catch (error) {
    console.error("Error generating art direction:", error);
    throw error;
  }
};

export const generateDesignImage = async (
  prompt: string, 
  aspectRatio: string, 
  batchSize: number, 
  imageSize: string,
  assetImages: string[] = [],
  logoImage: string | null = null
): Promise<string[]> => {
  try {
    const modelName = "gemini-3-pro-image-preview";

    // Build the content parts for the image generation request
    // We explicitly tell the model which image is what.
    const parts: any[] = [{ text: prompt }];

    if (logoImage) {
      parts.push({ text: " REFERENCE_IMAGE_LOGO (Incorporate this logo unchanged): " });
      parts.push({
        inlineData: {
          mimeType: "image/png",
          data: logoImage.split(',')[1]
        }
      });
    }

    if (assetImages.length > 0) {
       parts.push({ text: " REFERENCE_IMAGE_PRODUCT (Main Subject - Isolate and Place): " });
       assetImages.forEach(img => {
          parts.push({
            inlineData: {
              mimeType: "image/png",
              data: img.split(',')[1]
            }
          });
       });
    }

    const promises = Array.from({ length: batchSize }).map(async () => {
      const response = await ai.models.generateContent({
        model: modelName,
        contents: { parts },
        config: {
          imageConfig: {
            aspectRatio: aspectRatio,
            imageSize: imageSize 
          }
        },
      });

      for (const part of response.candidates?.[0]?.content?.parts || []) {
        if (part.inlineData) {
          return `data:image/png;base64,${part.inlineData.data}`;
        }
      }
      return null;
    });

    const results = await Promise.all(promises);
    return results.filter((url): url is string => url !== null);
  } catch (error) {
    console.error("Error generating image:", error);
    throw error;
  }
};

// New function for Refining/Editing an existing image
export const refineDesignImage = async (
  sourceImageBase64: string,
  instruction: string,
  aspectRatio: string,
  imageSize: string
): Promise<string[]> => {
  try {
    const modelName = "gemini-3-pro-image-preview";

    const prompt = `
      Perform the following edit on the provided design image: ${instruction}.
      Keep the layout and main elements consistent with the source image unless asked to change.
      High fidelity, professional design quality.
    `;

    const response = await ai.models.generateContent({
      model: modelName,
      contents: {
        parts: [
          { text: prompt },
          {
            inlineData: {
              mimeType: "image/png",
              data: sourceImageBase64.split(',')[1]
            }
          }
        ]
      },
      config: {
        imageConfig: {
          aspectRatio: aspectRatio,
          imageSize: imageSize 
        }
      },
    });

    const urls: string[] = [];
    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData) {
        urls.push(`data:image/png;base64,${part.inlineData.data}`);
      }
    }
    return urls;
  } catch (error) {
    console.error("Error refining image:", error);
    throw error;
  }
};

// Updated separation function to use the selected image as reference
export const separateDesignComponents = async (
  originalPrompt: string,
  aspectRatio: string,
  imageSize: string,
  referenceImageBase64?: string
): Promise<{ background: string | null, textLayer: string | null, elements: string | null }> => {

  const modelName = "gemini-3-pro-image-preview";

  // Helper to build content parts
  const buildParts = (taskPrompt: string) => {
    const parts: any[] = [{ text: taskPrompt }];
    if (referenceImageBase64) {
      parts.push({
        inlineData: {
          mimeType: "image/png",
          data: referenceImageBase64.split(',')[1]
        }
      });
    }
    return parts;
  };

  const bgPrompt = `
    Based on the provided reference design:
    *** TASK: GENERATE BACKGROUND ONLY ***
    - EXACTLY REPLICATE the background from the reference image.
    - Remove all text, typography, headlines.
    - Remove main foreground characters or products.
    - KEEP: The background texture, abstract shapes, environment, lighting.
    - RESULT: A clean, empty background ready for overlay.
  `;

  const textPrompt = `
    Based on the provided reference design:
    *** TASK: GENERATE TYPOGRAPHY LAYER ONLY ***
    - REPLICATE the exact text layout, font style, and position from the reference.
    - BACKGROUND: PURE WHITE (#FFFFFF).
    - CONTENT: Only the text elements (Headlines, body text).
    - NO images, NO decorations, NO background textures.
  `;

  // Updated Elements Prompt to respect "Keep Product Original" request if applicable
  const elementsPrompt = `
    Based on the provided reference design:
    *** TASK: GENERATE PRODUCT/ELEMENTS ONLY ***
    - REPLICATE the main visual elements, PRODUCTS, and Logo from the reference.
    - ISOLATE the product and logo.
    - REMOVE all text.
    - BACKGROUND: PURE WHITE (#FFFFFF).
    - RESULT: Isolated assets on white background for easy extraction.
  `;

  try {
    const [bgRes, textRes, elemRes] = await Promise.all([
      ai.models.generateContent({
        model: modelName,
        contents: { parts: buildParts(bgPrompt) },
        config: { imageConfig: { aspectRatio, imageSize } },
      }),
      ai.models.generateContent({
        model: modelName,
        contents: { parts: buildParts(textPrompt) },
        config: { imageConfig: { aspectRatio, imageSize } },
      }),
      ai.models.generateContent({
        model: modelName,
        contents: { parts: buildParts(elementsPrompt) },
        config: { imageConfig: { aspectRatio, imageSize } },
      })
    ]);

    const extractImage = (response: any) => {
       for (const part of response.candidates?.[0]?.content?.parts || []) {
        if (part.inlineData) {
          return `data:image/png;base64,${part.inlineData.data}`;
        }
      }
      return null;
    };

    return {
      background: extractImage(bgRes),
      textLayer: extractImage(textRes),
      elements: extractImage(elemRes)
    };

  } catch (error) {
    console.error("Error separating components:", error);
    throw error;
  }
};

