                    </svg>
                 )}
                 <span className="text-sm font-medium text-white">Tách Nền & Chi Tiết</span>
              </button>
           </div>

           {/* REFINEMENT COMPARISON VIEW */}
           {(refinementResult.loading || refinementResult.imageUrls.length > 0) && (
               <div className="mt-4 pt-4 border-t border-slate-700 animate-fade-in">
                  <h4 className="text-sm font-bold text-white mb-3 flex items-center gap-2">
                     <span className="w-2 h-4 bg-purple-500 rounded-sm"></span>
                     So Sánh Kết Quả
                  </h4>
                  <div className="grid grid-cols-2 gap-4 items-center bg-slate-900/50 p-3 rounded-lg border border-slate-700">
                      {/* Before */}
                      <div className="relative group">
                          <span className="absolute top-2 left-2 bg-slate-800/80 text-xs text-white px-2 py-1 rounded backdrop-blur-sm z-10 border border-slate-600">Ảnh Gốc</span>
                          <img 
                            src={selectedImage} 
                            alt="Original" 
                            className="w-full h-48 object-contain rounded-lg border border-slate-600" 
                            onClick={() => setLightboxImage(selectedImage)}
                          />
                      </div>

                      {/* Arrow (Hidden on mobile, shown on larger screens if layout permits, otherwise implied by grid) */}
                      {/* After */}
                      <div className="relative group">
                          <span className="absolute top-2 left-2 bg-purple-600/90 text-xs text-white px-2 py-1 rounded backdrop-blur-sm z-10 border border-purple-400 shadow-lg shadow-purple-500/20">Kết Quả Mới</span>
                          {refinementResult.loading ? (
                             <div className="w-full h-48 bg-slate-800 rounded-lg flex flex-col items-center justify-center border border-slate-700 border-dashed animate-pulse">
                                 <div className="w-8 h-8 border-2 border-purple-500 border-t-transparent rounded-full animate-spin mb-2"></div>
                                 <span className="text-xs text-slate-500">Đang vẽ lại...</span>
                             </div>
                          ) : (
                             <>
                                <img 
                                    src={refinementResult.imageUrls[0]} 
                                    alt="Refined" 
                                    className="w-full h-48 object-contain rounded-lg border-2 border-purple-500 shadow-lg shadow-purple-500/10 cursor-pointer"
                                    onClick={() => setLightboxImage(refinementResult.imageUrls[0])}
                                />
                                <div className="absolute bottom-2 right-2 flex gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
                                    <button 
                                        onClick={() => setLightboxImage(refinementResult.imageUrls[0])}
                                        className="p-1.5 bg-slate-800/80 rounded-full text-white hover:bg-blue-600"
                                    >
                                        <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                                            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0zM10 7v3m0 0v3m0-3h3m-3 0H7" />
                                        </svg>
                                    </button>
                                    <a 
                                        href={refinementResult.imageUrls[0]} 
                                        download="refined-design.png"
                                        className="p-1.5 bg-slate-800/80 rounded-full text-white hover:bg-emerald-600"
                                    >
                                        <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                                            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" />
                                        </svg>
                                    </a>
                                </div>
                             </>
                          )}
                      </div>
                  </div>
               </div>
           )}
        </div>
      )}

      {/* 4. Separated Assets Display */}
      {(separatedAssets.background || separatedAssets.textLayer || separatedAssets.elements || separatedAssets.loading) && (
        <div className="mt-4 pt-4 border-t border-slate-700 animate-fade-in-up">
            <h3 className="text-lg font-bold text-white mb-4 flex items-center gap-2">
                <span className="w-2 h-6 bg-emerald-500 rounded-sm"></span>
                Kết Quả Tách Lớp
            </h3>

            <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                {/* Background Card */}
                <AssetCard 
                    title="Chỉ Nền (Background)" 
                    image={separatedAssets.background} 
                    loading={separatedAssets.loading} 
                    onZoom={() => separatedAssets.background && setLightboxImage(separatedAssets.background)}
                />

                {/* Text Layer Card */}
                <AssetCard 
                    title="Lớp Chữ (Nền Trắng)" 
                    image={separatedAssets.textLayer} 
                    loading={separatedAssets.loading} 
                    isWhiteBg 
                    onZoom={() => separatedAssets.textLayer && setLightboxImage(separatedAssets.textLayer)}
                />

                {/* Elements Card */}
                <AssetCard 
                    title="Thành Phần Trang Trí (Nền Trắng)" 
                    image={separatedAssets.elements} 
                    loading={separatedAssets.loading} 
                    isWhiteBg 
                    onZoom={() => separatedAssets.elements && setLightboxImage(separatedAssets.elements)}
                />
            </div>

            {separatedAssets.error && (
                <div className="mt-4 p-3 bg-red-900/30 border border-red-500/30 rounded-lg text-red-200 text-sm">
                    Lỗi khi tách bố cục: {separatedAssets.error}
                </div>
            )}
        </div>
      )}
    </div>
  );
};

// Helper component for separated assets
const AssetCard = ({ title, image, loading, isWhiteBg, onZoom }: { title: string, image: string | null, loading: boolean, isWhiteBg?: boolean, onZoom?: () => void }) => (
    <div className="bg-slate-800 rounded-xl overflow-hidden border border-slate-700 flex flex-col h-[280px] group relative">
        <div className="px-3 py-2 bg-slate-900 border-b border-slate-700 text-xs font-medium text-slate-400">
            {title}
        </div>
        <div className={`relative flex-grow flex items-center justify-center overflow-hidden ${isWhiteBg ? 'bg-white' : 'bg-slate-950'}`}>
            {loading ? (
                <div className="flex flex-col items-center gap-2">
                    <div className="w-8 h-8 border-2 border-slate-500 border-t-emerald-500 rounded-full animate-spin"></div>
                    <span className="text-xs text-slate-500">Đang xử lý...</span>
                </div>
            ) : image ? (
                <>
                  <img src={image} alt={title} className="w-full h-full object-contain" />
                  <div className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center gap-2">
                       <button onClick={onZoom} className="p-2 bg-slate-800/80 rounded-full text-white hover:bg-blue-600">
                            <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0zM10 7v3m0 0v3m0-3h3m-3 0H7" />
                            </svg>
                       </button>
                       <a href={image} download={`${title.replace(/\s/g, '_')}.png`} className="p-2 bg-slate-800/80 rounded-full text-white hover:bg-emerald-600">
                            <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" />
                            </svg>
                       </a>
                  </div>
                </>
            ) : (
                <span className="text-xs text-slate-600">Không có dữ liệu</span>
            )}
        </div>
    </div>
);

export default ResultDisplay;

export enum ProductType {
  POSTER = 'Poster',
  STANDEE = 'Standee',
  BACKDROP = 'Backdrop',
  BANNER = 'Banner',
  SOCIAL_POST = 'Social Media Post',
  FLYER = 'Flyer'
}

export enum VisualStyle {
  MODERN_TECH = 'Modern Tech',
  LUXURY = 'Luxury',
  VINTAGE = 'Vintage',
  FESTIVE = 'Festive',
  MINIMALIST = 'Minimalist',
  CORPORATE = 'Corporate',
  CYBERPUNK = 'Cyberpunk',
  NATURAL_ORGANIC = 'Natural/Organic',
  FOLLOW_REF = 'Follow Reference' // New option
}

export enum ColorMode {
  AUTO = 'Auto',
  CUSTOM = 'Custom',
  BRAND_LOGO = 'Brand Logo' // New option
}

export enum QualityLevel {
  LOW = '1K',
  MEDIUM = '2K',
  HIGH = '4K'
}

export enum ProductImageMode {
  REALISTIC = 'Realistic', // Làm nét, giữ nguyên chi tiết, tách nền
  STYLIZED = 'Stylized'    // AI Cách điệu, vẽ lại
}

export interface ArtDirectionRequest {
  productType: ProductType;
  // Content Text Split
  mainHeadline: string;
  mainHeadlineImage: string | null; // Image reference specifically for the headline style
  secondaryText: string;

  visualStyle: VisualStyle;
  colorMode: ColorMode;
  customColors: string[];

  // Design Requirements
  layoutRequirements: string; // Specific placement instructions & Scene description merged
  fontPreferences: string; // New field for typography/font usage

  width: string;
  height: string;

  // Assets & Logo
  logoImage: string | null; // Base64 string for Brand Logo
  assetImages: string[]; // Base64 strings
  productImageMode: ProductImageMode; // How to treat the asset images

  referenceImage: string | null; // Base64 string
  referenceAttributes: string[]; // 'style', 'background', 'text_effects', 'layout'
  batchSize: 1 | 3 | 5;
  quality: QualityLevel;
}

export interface ArtDirectionResponse {
  analysis: string;
  final_prompt: string;
  recommendedAspectRatio: "1:1" | "3:4" | "4:3" | "9:16" | "16:9";
}

export interface ImageGenerationResult {
  imageUrls: string[];
  loading: boolean;
  error: string | null;
}

export interface SeparatedAssets {
  background: string | null;
  textLayer: string | null;
  elements: string | null;
  loading: boolean;
  error: string | null;
}

import React, { useRef, useMemo } from 'react';
import { ArtDirectionRequest, ProductType, VisualStyle, ColorMode, QualityLevel, ProductImageMode } from '../types';

interface InputFormProps {
  values: ArtDirectionRequest;
  onChange: (field: keyof ArtDirectionRequest, value: any) => void;
  onSubmit: () => void;
  isGenerating: boolean;
}

const InputForm: React.FC<InputFormProps> = ({ values, onChange, onSubmit, isGenerating }) => {
  const assetInputRef = useRef<HTMLInputElement>(null);
  const refInputRef = useRef<HTMLInputElement>(null);
  const headlineImageInputRef = useRef<HTMLInputElement>(null);
  const logoInputRef = useRef<HTMLInputElement>(null);

  // Helper mappings for Vietnamese display
  const productTypeLabels: Record<string, string> = {
    [ProductType.POSTER]: 'Ápp phích (Poster)',
    [ProductType.STANDEE]: 'Standee',
    [ProductType.BACKDROP]: 'Phông nền (Backdrop)',
    [ProductType.BANNER]: 'Băng rôn (Banner)',
    [ProductType.SOCIAL_POST]: 'Bài đăng Mạng Xã Hội',
    [ProductType.FLYER]: 'Tờ rơi (Flyer)'
  };

  const visualStyleLabels: Record<string, string> = {
    [VisualStyle.MODERN_TECH]: 'Công nghệ Hiện đại',
    [VisualStyle.LUXURY]: 'Sang trọng / Cao cấp',
    [VisualStyle.VINTAGE]: 'Cổ điển (Vintage)',
    [VisualStyle.FESTIVE]: 'Lễ hội / Sự kiện',
    [VisualStyle.MINIMALIST]: 'Tối giản (Minimalist)',
    [VisualStyle.CORPORATE]: 'Doanh nghiệp (Corporate)',
    [VisualStyle.CYBERPUNK]: 'Cyberpunk / Tương lai',
    [VisualStyle.NATURAL_ORGANIC]: 'Thiên nhiên / Organic',
    [VisualStyle.FOLLOW_REF]: 'Theo phong cách style ảnh đính kèm'
  };

  const referenceAttributeLabels: Record<string, string> = {
    'Style': 'Phong cách',
    'Background': 'Nền',
    'Text Effects': 'Hiệu ứng chữ',
    'Layout': 'Bố cục'
  };

  // Calculate estimated pixels based on dimensions (cm) and Quality Level (1K/2K/4K)
  const estimatedOutput = useMemo(() => {
    if (!values.width || !values.height) return null;
    const w = parseFloat(values.width);
    const h = parseFloat(values.height);

    if (isNaN(w) || isNaN(h) || w === 0 || h === 0) return null;

    // Define max dimension based on Quality Level
    let maxDim = 1024; // Default Low/1K
    if (values.quality === QualityLevel.MEDIUM) maxDim = 2048; // 2K
    if (values.quality === QualityLevel.HIGH) maxDim = 4096; // 4K

    // Determine the closest standard aspect ratio supported by AI Models
    const currentRatio = w / h;
    const supportedRatios = [
        { label: "1:1", val: 1.0 },
        { label: "3:4", val: 3/4 },
        { label: "4:3", val: 4/3 },
        { label: "9:16", val: 9/16 },
        { label: "16:9", val: 16/9 }
    ];

    const closest = supportedRatios.reduce((prev, curr) => {
        return (Math.abs(curr.val - currentRatio) < Math.abs(prev.val - currentRatio) ? curr : prev);
    });

    let pxWidth, pxHeight;

    if (closest.val >= 1) {
        pxWidth = maxDim;
        pxHeight = Math.round(maxDim / closest.val);
    } else {
        pxHeight = maxDim;
        pxWidth = Math.round(maxDim * closest.val);
    }

    return {
        pixels: `${pxWidth} x ${pxHeight} px`,
        ratio: closest.label
    };
  }, [values.width, values.height, values.quality]);


  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>, field: 'assetImages' | 'referenceImage' | 'mainHeadlineImage' | 'logoImage') => {
    const files = e.target.files;
    if (!files || files.length === 0) return;

    if (field === 'assetImages') {
      const newImages: string[] = [...values.assetImages];
      Array.from(files).forEach(file => {
        const reader = new FileReader();
        reader.onloadend = () => {
          if (reader.result) newImages.push(reader.result as string);
          if (newImages.length === values.assetImages.length + files.length) {
             onChange('assetImages', newImages);
          }
        };
        reader.readAsDataURL(file as Blob);
      });
    } else {
      const file = files[0];
      const reader = new FileReader();
      reader.onloadend = () => {
        if (reader.result) onChange(field, reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const removeAsset = (index: number) => {
    const newImages = [...values.assetImages];
    newImages.splice(index, 1);
    onChange('assetImages', newImages);
  };

  const toggleAttribute = (attr: string) => {
    const current = [...values.referenceAttributes];
    const index = current.indexOf(attr);
    if (index > -1) {
      current.splice(index, 1);
    } else {
      current.push(attr);
    }
    onChange('referenceAttributes', current);
  };

  const handleColorChange = (index: number, value: string) => {
    const newColors = [...values.customColors];
    newColors[index] = value;
    onChange('customColors', newColors);
  };

  const addColor = () => {
    if (values.customColors.length < 5) {
        onChange('customColors', [...values.customColors, '#000000']);
    }
  };

  const removeColor = (index: number) => {
    if (values.customColors.length > 1) {
        const newColors = values.customColors.filter((_, i) => i !== index);
        onChange('customColors', newColors);
    }
  };

  return (
    <div className="bg-slate-800/50 p-6 rounded-2xl border border-slate-700 shadow-xl backdrop-blur-sm h-full flex flex-col overflow-y-auto">
      <h2 className="text-xl font-bold text-white mb-6 flex items-center gap-2">
        <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6 text-purple-400" fill="none" viewBox="0 0 24 24" stroke="currentColor">
          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M11 5H6a2 2 0 00-2 2v11a2 2 0 002 2h11a2 2 0 002-2v-5m-1.414-9.414a2 2 0 112.828 2.828L11.828 15H9v-2.828l8.586-8.586z" />
        </svg>
        Bản Yêu Cầu Thiết Kế
      </h2>

      <div className="space-y-5 flex-grow">
        {/* Product Type & Dimensions */}
        <div className="grid grid-cols-2 gap-4">
          <div className="col-span-2">
            <label className="block text-sm font-medium text-slate-300 mb-1">Loại Sản Phẩm</label>
            <select
              className="w-full bg-slate-900 border border-slate-700 rounded-lg px-4 py-2 text-white focus:ring-2 focus:ring-purple-500 outline-none"
              value={values.productType}
              onChange={(e) => onChange('productType', e.target.value)}
            >
              {Object.values(ProductType).map((type) => (
                <option key={type} value={type}>{productTypeLabels[type] || type}</option>
              ))}
            </select>
          </div>
          <div>
            <label className="block text-sm font-medium text-slate-300 mb-1">Rộng (cm)</label>
            <input 
              type="number" placeholder="Ví dụ: 60"
              className="w-full bg-slate-900 border border-slate-700 rounded-lg px-3 py-2 text-white text-sm focus:ring-2 focus:ring-purple-500 outline-none"
              value={values.width} onChange={(e) => onChange('width', e.target.value)}
            />
          </div>
          <div>
            <label className="block text-sm font-medium text-slate-300 mb-1">Cao (cm)</label>
            <input 
              type="number" placeholder="Ví dụ: 160"
              className="w-full bg-slate-900 border border-slate-700 rounded-lg px-3 py-2 text-white text-sm focus:ring-2 focus:ring-purple-500 outline-none"
              value={values.height} onChange={(e) => onChange('height', e.target.value)}
            />
          </div>
          {/* Pixel Output Indicator */}
          <div className="col-span-2 -mt-2">
             {estimatedOutput ? (
                <div className="flex flex-col gap-1 bg-slate-900/50 rounded px-3 py-2 border border-slate-700/50">
                    <div className="flex items-center justify-between">
                         <div className="flex items-center gap-2">
                            <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4 text-emerald-400" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 8V4m0 0h4M4 4l5 5m11-1V4m0 0h-4m4 4l-5 5M4 16v4m0 0h4m-4 0l5-5m11 5l-5-5m5 5v-4m0 4h-4" />
                            </svg>
                            <span className="text-xs text-slate-300 font-medium">Độ phân giải tối đa:</span>
                         </div>
                         <span className="text-emerald-400 font-bold text-xs font-mono">{estimatedOutput.pixels}</span>
                    </div>
                    <div className="flex justify-end items-center gap-2">
                         <span className="text-[10px] text-slate-500">Tỷ lệ chuẩn AI: {estimatedOutput.ratio}</span>
                    </div>
                </div>
             ) : (
                <div className="flex items-center gap-2 px-2 py-1">
                   <span className="text-xs text-slate-600">Nhập kích thước để xem độ phân giải pixel</span>
                </div>
             )}
          </div>
        </div>

        {/* Content Section Split */}
        <div className="space-y-3 p-3 bg-slate-900/30 rounded-lg border border-slate-700/50">
          <label className="block text-xs font-bold text-slate-400 uppercase tracking-wider">Thông Tin Nội Dung</label>

          <div>
            <label className="block text-sm font-medium text-slate-300 mb-1">Tiêu Đề Chính</label>
            <div className="flex gap-2">
                <input
                    type="text"
                    className="flex-grow bg-slate-900 border border-slate-700 rounded-lg px-4 py-2 text-white focus:ring-2 focus:ring-purple-500 outline-none placeholder-slate-500 font-semibold"
                    placeholder="Ví dụ: KHUYẾN MÃI HÈ"
                    value={values.mainHeadline}
                    onChange={(e) => onChange('mainHeadline', e.target.value)}
                />

                {/* Headline Reference Image Uploader */}
                {!values.mainHeadlineImage ? (
                     <button 
                        onClick={() => headlineImageInputRef.current?.click()}
                        className="w-10 h-10 flex-shrink-0 bg-slate-800 border border-dashed border-slate-600 rounded-lg flex items-center justify-center text-slate-500 hover:text-purple-400 hover:border-purple-500 transition-colors group relative"
                        title="Tải ảnh mẫu phông chữ cho tiêu đề"
                     >
                        <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                           <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" />
                        </svg>
                     </button>
                ) : (
                    <div className="w-10 h-10 flex-shrink-0 relative rounded-lg overflow-hidden border border-purple-500/50 group">
                        <img src={values.mainHeadlineImage} alt="Style" className="w-full h-full object-cover" />
                        <button 
                           onClick={() => onChange('mainHeadlineImage', null)}
                           className="absolute inset-0 bg-black/60 flex items-center justify-center text-white opacity-0 group-hover:opacity-100 transition-opacity"
                        >
                           <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
                           </svg>
                        </button>
                    </div>
                )}
                <input 
                    type="file" ref={headlineImageInputRef} className="hidden" accept="image/*"
                    onChange={(e) => handleFileChange(e, 'mainHeadlineImage')} 
                />
            </div>
            {values.mainHeadlineImage && <p className="text-[10px] text-purple-400 mt-1 ml-1">* Đang dùng ảnh làm mẫu style cho tiêu đề</p>}
          </div>

          <div>
            <label className="block text-sm font-medium text-slate-300 mb-1">Nội Dung Phụ</label>
            <textarea
              className="w-full bg-slate-900 border border-slate-700 rounded-lg px-4 py-2 text-white focus:ring-2 focus:ring-purple-500 outline-none placeholder-slate-500 h-16 resize-none text-sm"
              placeholder="Tiêu đề phụ, ngày tháng, website, nội dung chi tiết..."
              value={values.secondaryText}
              onChange={(e) => onChange('secondaryText', e.target.value)}
            />
          </div>
        </div>

        {/* LOGO SECTION - NEW */}
        <div className="p-3 bg-slate-900/30 rounded-lg border border-slate-700/50">
            <div className="flex justify-between items-center mb-2">
               <label className="block text-xs font-bold text-slate-400 uppercase tracking-wider">Logo Thương Hiệu</label>
               {values.logoImage && (
                  <button onClick={() => onChange('logoImage', null)} className="text-xs text-red-400 hover:text-red-300">Xóa Logo</button>
               )}
            </div>

            {!values.logoImage ? (
