import { GoogleGenAI, Type, Schema } from "@google/genai";
import { ArtDirectionRequest, ArtDirectionResponse, ProductImageMode, VisualStyle, ColorMode } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const SYSTEM_INSTRUCTION = `
You are a professional "AI Art Director" and "Prompt Engineer" in the print & advertising design field. 
Your task is to perform **REVERSE ENGINEERING** on the user's raw request and provided visual assets to create a professional image generation plan.

### WORKFLOW:
1.  **DECOMPOSE (Phân rã):** Break down the user's request (Product type, dimensions, content, layout) and analyze the provided assets (Logo, Product Images).
2.  **REVERSE ENGINEER STYLE:** 
    *   If a **Reference Image** is provided with specific checked attributes (Style, Layout, etc.), you MUST analyze that image and extract those specific qualities to use as the foundation (Anchor).
    *   If **Brand Logo** is provided and Color Mode is "Brand Logo", extract the palette.
3.  **SYNTHESIZE & PLAN:** Create a coherent design strategy.
4.  **TRANSLATE & OPTIMIZE:** Write a highly detailed **ENGLISH PROMPT** for the image generation model.

### INPUT DATA
1. **Product Type:** (Poster, Backdrop, Banner...)
2. **Dimensions:** (User preferred size in cm)
3. **Content:** Main Headline, Secondary Text.
4. **Layout & Placement:** Specific spatial instructions & Scene Description.
5. **Visual Style:** (Modern Tech, Luxury... or Follow Reference)
6. **Color Mode:** (Auto, Custom, or Brand Logo)
7. **Assets:** Product Images & Logo.
8. **Reference:** Image & Specific Attributes to mimic.

### LOGIC CORE & CONSTRAINTS

**1. LANGUAGE PROCESSING**
*   **ANALYSIS (Output 'analysis'):** Return a "Design Note" in **VIETNAMESE**. This should sound like a creative director explaining the concept to a designer. Explain how you decomposed the request and what the key visual hook is.
*   **PROMPT (Output 'final_prompt'):** The actual instruction for the AI model in **ENGLISH**.

**2. REFERENCE IMAGE HANDLING (CRITICAL)**
*   If 'Reference Image' is provided:
    *   Look at the \`referenceAttributes\` list (Style, Background, Text Effects, Layout).
    *   For each checked attribute, the prompt **MUST** explicitly state: "Reference [Attribute] style: [Description of that attribute extracted from the ref image]."
    *   *Example:* If 'Layout' is checked, ignore generic layout rules and strictly follow the reference image's composition.

**3. ASSET HANDLING RULES**
*   **LOGO:** Prompt must ensure space is reserved for the logo or incorporate it if meant to be artistic.
*   **PRODUCT IMAGES:**
    *   **Realistic:** "Photorealistic render, high fidelity, isolate subject."
    *   **Stylized:** "Artistic interpretation, blending with environment style."

**4. QUALITY SPECS**
*   Always add: "High fidelity, 8k resolution, highly detailed, professional graphic design, print quality, rule of thirds, sharp focus."

### OUTPUT FORMAT
Return a JSON object with:
1. "analysis": The creative strategy/notes in **VIETNAMESE**.
2. "final_prompt": The optimized English prompt.
3. "recommendedAspectRatio": The most suitable aspect ratio ("1:1", "3:4", "4:3", "9:16", "16:9").
`;

const RESPONSE_SCHEMA: Schema = {
  type: Type.OBJECT,
  properties: {
    analysis: {
      type: Type.STRING,
      description: "Brief explanation of the design choices in Vietnamese.",
    },
    final_prompt: {
      type: Type.STRING,
      description: "The highly detailed prompt for the image generator in English.",
    },
    recommendedAspectRatio: {
      type: Type.STRING,
      enum: ["1:1", "3:4", "4:3", "9:16", "16:9"],
      description: "The best aspect ratio supported by the API.",
    },
  },
  required: ["analysis", "final_prompt", "recommendedAspectRatio"],
};

export const generateArtDirection = async (request: ArtDirectionRequest): Promise<ArtDirectionResponse> => {
  try {
    // Construct the multimodal prompt
    const parts: any[] = [];

    // Helper to format style string
    let styleInstruction: string = request.visualStyle;
    if (request.visualStyle === VisualStyle.FOLLOW_REF) {
        styleInstruction = "STRICTLY MIMIC the artistic style, rendering technique, and vibe of the General Reference Image provided.";
    }

    // Helper to format color string
    let colorInstruction = request.colorMode === 'Custom' 
      ? `Custom Palette (${request.customColors.join(', ')})` 
      : 'Auto';

    if (request.colorMode === ColorMode.BRAND_LOGO) {
        colorInstruction = "EXTRACT the dominant colors from the provided Brand Logo and use them as the primary color palette.";
    }

    // 1. Text Prompt
    let promptText = `
      Product Type: ${request.productType}
      Dimensions: ${request.width}cm x ${request.height}cm

      -- CONTENT --
      Main Headline (Big Text): "${request.mainHeadline}"
      Secondary Text (Small Text): "${request.secondaryText}"

      -- REQUIREMENTS --
      Layout & Placement & Description: "${request.layoutRequirements}"
      Typography/Font Usage: "${request.fontPreferences}"

      -- STYLE --
      Visual Style: ${styleInstruction}
      Color Mode: ${colorInstruction}

      -- ASSETS CONFIG --
      Product Image Mode: ${request.productImageMode}
      Has Logo: ${request.logoImage ? 'YES' : 'NO'}
    `;

    if (request.referenceAttributes.length > 0) {
      promptText += `\n*** CRITICAL: User wants to mimic the following attributes from the Reference Image: ${request.referenceAttributes.join(', ')}. ***`;
    }

    parts.push({ text: promptText });

    // 2. Logo Reference
    if (request.logoImage) {
      parts.push({ text: "Brand Logo Image:" });
      parts.push({
        inlineData: {
          mimeType: "image/png",
          data: request.logoImage.split(',')[1]
        }
      });
    }

    // 3. Asset Images (Products)
    if (request.assetImages && request.assetImages.length > 0) {
      parts.push({ text: "Product Asset Images (Subject matter):" });
      request.assetImages.forEach((imgBase64, index) => {
        parts.push({
          inlineData: {
            mimeType: "image/png",
            data: imgBase64.split(',')[1]
          }
        });
      });
    }

    // 4. Main Headline Reference Image
    if (request.mainHeadlineImage) {
      parts.push({ text: "Reference Image for MAIN HEADLINE STYLE (Mimic this specific font/texture/effect):" });
      parts.push({
        inlineData: {
          mimeType: "image/png",
          data: request.mainHeadlineImage.split(',')[1]
        }
      });
    }

    // 5. Overall Reference Image
    if (request.referenceImage) {
      parts.push({ text: "General Reference Image (Use as ANCHOR for: " + request.referenceAttributes.join(', ') + "):" });
      parts.push({
        inlineData: {
          mimeType: "image/png",
          data: request.referenceImage.split(',')[1]
        }
      });
    }

    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: { parts },
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        responseMimeType: "application/json",
        responseSchema: RESPONSE_SCHEMA,
      },
    });

    const text = response.text;
    if (!text) throw new Error("No response from AI Director");

    return JSON.parse(text) as ArtDirectionResponse;
  } catch (error) {
    console.error("Error generating art direction:", error);
    throw error;
  }
};

export const generateDesignImage = async (
  prompt: string, 
  aspectRatio: string, 
  batchSize: number, 
  imageSize: string,
  assetImages: string[] = [],
  logoImage: string | null = null
): Promise<string[]> => {
  try {
    const modelName = "gemini-3-pro-image-preview";

    // Build the content parts for the image generation request
    // We explicitly tell the model which image is what.
    const parts: any[] = [{ text: prompt }];

    if (logoImage) {
      parts.push({ text: " REFERENCE_IMAGE_LOGO (Incorporate this logo unchanged): " });
      parts.push({
        inlineData: {
          mimeType: "image/png",
          data: logoImage.split(',')[1]
        }
      });
    }

    if (assetImages.length > 0) {
       parts.push({ text: " REFERENCE_IMAGE_PRODUCT (Main Subject - Isolate and Place): " });
       assetImages.forEach(img => {
          parts.push({
            inlineData: {
              mimeType: "image/png",
              data: img.split(',')[1]
            }
          });
       });
    }

    const promises = Array.from({ length: batchSize }).map(async () => {
      const response = await ai.models.generateContent({
        model: modelName,
        contents: { parts },
        config: {
          imageConfig: {
            aspectRatio: aspectRatio,
            imageSize: imageSize 
          }
        },
      });

      for (const part of response.candidates?.[0]?.content?.parts || []) {
        if (part.inlineData) {
          return `data:image/png;base64,${part.inlineData.data}`;
        }
      }
      return null;
    });

    const results = await Promise.all(promises);
    return results.filter((url): url is string => url !== null);
  } catch (error) {
    console.error("Error generating image:", error);
    throw error;
  }
};

// New function for Refining/Editing an existing image
export const refineDesignImage = async (
  sourceImageBase64: string,
  instruction: string,
  aspectRatio: string,
  imageSize: string
): Promise<string[]> => {
  try {
    const modelName = "gemini-3-pro-image-preview";

    const prompt = `
      Perform the following edit on the provided design image: ${instruction}.
      Keep the layout and main elements consistent with the source image unless asked to change.
      High fidelity, professional design quality.
    `;

    const response = await ai.models.generateContent({
      model: modelName,
      contents: {
        parts: [
          { text: prompt },
          {
            inlineData: {
              mimeType: "image/png",
              data: sourceImageBase64.split(',')[1]
            }
          }
        ]
      },
      config: {
        imageConfig: {
          aspectRatio: aspectRatio,
          imageSize: imageSize 
        }
      },
    });

    const urls: string[] = [];
    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData) {
        urls.push(`data:image/png;base64,${part.inlineData.data}`);
      }
    }
    return urls;
  } catch (error) {
    console.error("Error refining image:", error);
    throw error;
  }
};

// Updated separation function to use the selected image as reference
export const separateDesignComponents = async (
  originalPrompt: string,
  aspectRatio: string,
  imageSize: string,
  referenceImageBase64?: string
): Promise<{ background: string | null, textLayer: string | null, elements: string | null }> => {

  const modelName = "gemini-3-pro-image-preview";

  // Helper to build content parts
  const buildParts = (taskPrompt: string) => {
    const parts: any[] = [{ text: taskPrompt }];
    if (referenceImageBase64) {
      parts.push({
        inlineData: {
          mimeType: "image/png",
          data: referenceImageBase64.split(',')[1]
        }
      });
    }
    return parts;
  };

  const bgPrompt = `
    Based on the provided reference design:
    *** TASK: GENERATE BACKGROUND ONLY ***
    - EXACTLY REPLICATE the background from the reference image.
    - Remove all text, typography, headlines.
    - Remove main foreground characters or products.
    - KEEP: The background texture, abstract shapes, environment, lighting.
    - RESULT: A clean, empty background ready for overlay.
  `;

  const textPrompt = `
    Based on the provided reference design:
    *** TASK: GENERATE TYPOGRAPHY LAYER ONLY ***
    - REPLICATE the exact text layout, font style, and position from the reference.
    - BACKGROUND: PURE WHITE (#FFFFFF).
    - CONTENT: Only the text elements (Headlines, body text).
    - NO images, NO decorations, NO background textures.
  `;

  // Updated Elements Prompt to respect "Keep Product Original" request if applicable
  const elementsPrompt = `
    Based on the provided reference design:
    *** TASK: GENERATE PRODUCT/ELEMENTS ONLY ***
    - REPLICATE the main visual elements, PRODUCTS, and Logo from the reference.
    - ISOLATE the product and logo.
    - REMOVE all text.
    - BACKGROUND: PURE WHITE (#FFFFFF).
    - RESULT: Isolated assets on white background for easy extraction.
  `;

  try {
    const [bgRes, textRes, elemRes] = await Promise.all([
      ai.models.generateContent({
        model: modelName,
        contents: { parts: buildParts(bgPrompt) },
        config: { imageConfig: { aspectRatio, imageSize } },
      }),
      ai.models.generateContent({
        model: modelName,
        contents: { parts: buildParts(textPrompt) },
        config: { imageConfig: { aspectRatio, imageSize } },
      }),
      ai.models.generateContent({
        model: modelName,
        contents: { parts: buildParts(elementsPrompt) },
        config: { imageConfig: { aspectRatio, imageSize } },
      })
    ]);

    const extractImage = (response: any) => {
       for (const part of response.candidates?.[0]?.content?.parts || []) {
        if (part.inlineData) {
          return `data:image/png;base64,${part.inlineData.data}`;
        }
      }
      return null;
    };

    return {
      background: extractImage(bgRes),
      textLayer: extractImage(textRes),
      elements: extractImage(elemRes)
    };

  } catch (error) {
    console.error("Error separating components:", error);
    throw error;
  }
};

import React, { useState } from 'react';
import InputForm from './components/InputForm';
import ResultDisplay from './components/ResultDisplay';
import { ArtDirectionRequest, ArtDirectionResponse, ColorMode, ImageGenerationResult, ProductType, VisualStyle, QualityLevel, SeparatedAssets, ProductImageMode } from './types';
import { generateArtDirection, generateDesignImage, separateDesignComponents, refineDesignImage } from './services/geminiService';

const App: React.FC = () => {
  // Form State
  const [request, setRequest] = useState<ArtDirectionRequest>({
    productType: ProductType.POSTER,
    mainHeadline: '',
    mainHeadlineImage: null,
    secondaryText: '',
    layoutRequirements: '',
    // imageElementDescription removed
    fontPreferences: '',
    visualStyle: VisualStyle.MODERN_TECH,
    colorMode: ColorMode.AUTO,
    customColors: ['#7c3aed', '#2563eb'],
    width: '',
    height: '',

    // Assets
    assetImages: [],
    logoImage: null,
    productImageMode: ProductImageMode.REALISTIC,

    referenceImage: null,
    referenceAttributes: [],
    batchSize: 1,
    quality: QualityLevel.LOW
  });

  // Result States
  const [artDirection, setArtDirection] = useState<ArtDirectionResponse | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false); // State for Step 1: Analysis

  // 1. Original Generation Results
  const [imageResult, setImageResult] = useState<ImageGenerationResult>({
    imageUrls: [],
    loading: false,
    error: null
  });

  // 2. Refinement Results (New state for editing)
  const [refinementResult, setRefinementResult] = useState<ImageGenerationResult>({
    imageUrls: [],
    loading: false,
    error: null
  });

  const [separatedAssets, setSeparatedAssets] = useState<SeparatedAssets>({
    background: null,
    textLayer: null,
    elements: null,
    loading: false,
    error: null
  });

  // Handlers
  const handleInputChange = (field: keyof ArtDirectionRequest, value: any) => {
    setRequest(prev => ({ ...prev, [field]: value }));
  };

  // STEP 1: Analyze & Plan
  const handleAnalyze = async () => {
    if (!request.mainHeadline && !request.layoutRequirements) return;

    // Reset previous states
    setImageResult(prev => ({ ...prev, loading: false, error: null, imageUrls: [] }));
    setRefinementResult({ imageUrls: [], loading: false, error: null });
    setSeparatedAssets({ background: null, textLayer: null, elements: null, loading: false, error: null }); 
    setArtDirection(null);
    setIsAnalyzing(true);

    try {
      console.log("Analyzing art direction...");
      const direction = await generateArtDirection(request);
      setArtDirection(direction);
      setIsAnalyzing(false);
    } catch (err: any) {
      console.error(err);
      setIsAnalyzing(false);
      setImageResult(prev => ({
        ...prev,
        error: err.message || "Có lỗi xảy ra khi phân tích yêu cầu."
      }));
    }
  };

  // STEP 2: Generate Final Images (Called from ResultDisplay)
  const handleGenerateFinalImages = async (finalPrompt: string) => {
    if (!artDirection) return;

    setImageResult(prev => ({ ...prev, loading: true, error: null, imageUrls: [] }));

    try {
      console.log(`Generating ${request.batchSize} images...`);
      const images = await generateDesignImage(
        finalPrompt, 
        artDirection.recommendedAspectRatio, 
        request.batchSize, 
        request.quality,
        request.assetImages, 
        request.logoImage
      );

      setImageResult({
        imageUrls: images,
        loading: false,
        error: images.length === 0 ? "Không thể tạo hình ảnh." : null
      });

    } catch (err: any) {
      console.error(err);
      setImageResult(prev => ({
        ...prev,
        loading: false,
        error: err.message || "Có lỗi xảy ra khi tạo hình ảnh."
      }));
    }
  };

  const handleRegenerateImage = async (newPrompt: string) => {
    if (!artDirection) return;
    // Just reuse the generation logic with new prompt
    handleGenerateFinalImages(newPrompt);
  };

  const handleSeparateLayout = async (selectedImage?: string) => {
    if (!artDirection) return;

    setSeparatedAssets(prev => ({ ...prev, loading: true, error: null }));

    try {
       const result = await separateDesignComponents(
         artDirection.final_prompt,
         artDirection.recommendedAspectRatio,
         request.quality,
         selectedImage // Pass the selected image as reference
       );

       setSeparatedAssets({
         background: result.background,
         textLayer: result.textLayer,
         elements: result.elements,
         loading: false,
         error: (!result.background && !result.textLayer) ? "Không thể tách các thành phần." : null
       });

    } catch (err: any) {
      setSeparatedAssets(prev => ({
        ...prev,
        loading: false,
        error: err.message || "Lỗi khi tách bố cục."
      }));
    }
  };

  const handleRefine = async (sourceImage: string, instruction: string) => {
    if (!artDirection) return;

    // Set Refinement loading, keep original images intact
    setRefinementResult(prev => ({ ...prev, loading: true, error: null, imageUrls: [] }));
    setSeparatedAssets({ background: null, textLayer: null, elements: null, loading: false, error: null });

    try {
      const newImages = await refineDesignImage(
        sourceImage,
        instruction,
        artDirection.recommendedAspectRatio,
        request.quality
      );

      setRefinementResult({
        imageUrls: newImages,
        loading: false,
        error: newImages.length === 0 ? "Không thể hiệu chỉnh hình ảnh." : null
      });

    } catch (err: any) {
      setRefinementResult(prev => ({
        ...prev,
        loading: false,
        error: err.message || "Lỗi khi hiệu chỉnh hình ảnh."
      }));
    }
  };

  // Reset refinement when selecting a new image
  const handleResetRefinement = () => {
    setRefinementResult({ imageUrls: [], loading: false, error: null });
  };

  return (
    <div className="min-h-screen bg-[#0f172a] text-slate-200 selection:bg-purple-500/30">
      {/* Background Ambience */}
      <div className="fixed inset-0 z-0 pointer-events-none">
        <div className="absolute top-0 left-1/4 w-96 h-96 bg-purple-600/10 rounded-full blur-[100px]"></div>
        <div className="absolute bottom-0 right-1/4 w-96 h-96 bg-blue-600/10 rounded-full blur-[100px]"></div>
      </div>

      <div className="relative z-10 container mx-auto px-4 py-6 h-screen flex flex-col">
        {/* Header */}
        <header className="flex items-center justify-between mb-6 shrink-0">
          <div className="flex items-center gap-3">
             <div className="w-10 h-10 bg-gradient-to-br from-purple-500 to-blue-600 rounded-lg flex items-center justify-center shadow-lg shadow-purple-500/20">
               <span className="text-white font-bold text-xl">Ai</span>
             </div>
             <div>
               <h1 className="text-xl font-bold text-white tracking-tight">Giám Đốc Nghệ Thuật</h1>
               <p className="text-xs text-slate-400">Powered by Gemini</p>
             </div>
          </div>
          <div className="flex gap-2">
            <span className="px-3 py-1 bg-slate-800 rounded-full text-xs font-medium text-slate-400 border border-slate-700">v1.5 Pro</span>
          </div>
        </header>

        {/* Main Content Grid */}
        <main className="flex-grow grid grid-cols-1 lg:grid-cols-12 gap-6 overflow-hidden min-h-0 pb-2">
          {/* Left: Input Panel */}
          <div className="lg:col-span-4 h-full min-h-[500px]">
            <InputForm 
              values={request} 
              onChange={handleInputChange} 
              onSubmit={handleAnalyze} // Now calls Analyze first
              isGenerating={isAnalyzing || imageResult.loading}
            />
          </div>

          {/* Right: Visualization Panel */}
          <div className="lg:col-span-8 h-full min-h-[500px]">
            <ResultDisplay 
              artDirection={artDirection} 
              imageResult={imageResult}
              refinementResult={refinementResult}
              isAnalyzing={isAnalyzing} // Pass analyzing state
              onGenerateImages={handleGenerateFinalImages} // Pass generate handler
              onRegenerateImage={handleRegenerateImage}
              onSeparateLayout={handleSeparateLayout}
              onRefineImage={handleRefine}
              onResetRefinement={handleResetRefinement}
              separatedAssets={separatedAssets}
            />
          </div>
        </main>
      </div>
    </div>
  );
};

export default App;

