import { GoogleGenAI, Type, Schema } from "@google/genai";
import { ArtDirectionRequest, ArtDirectionResponse, ProductImageMode, VisualStyle, ColorMode, DesignPlan } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const SYSTEM_INSTRUCTION = `
You are a professional "AI Art Director" and "Prompt Engineer".
Your task is to **DECOMPOSE** the user request into a specific 6-point design plan and then synthesize a highly detailed English prompt.

### 6-POINT DECOMPOSITION CRITERIA (Must be in VIETNAMESE for the 'designPlan'):
1.  **Subject & Secondary Content (Chủ thể):** Define the main hero image (Product/Person) and how the *Secondary Text* is integrated or represented conceptually.
2.  **Style & Context (Bối cảnh & Phong cách):** Define the environment, artistic style (Reference Image attributes go here), and overall mood.
3.  **Composition & Camera (Bố cục):** Define the layout structure (rule of thirds, symmetrical, etc.), camera angle, and focal length.
4.  **Color & Lighting (Màu sắc & Ánh sáng):** 
    *   **CRITICAL:** If a **Brand Logo** is provided, you MUST analyze and list the specific colors from the logo here.
    *   Define the palette (Logo colors or Custom), lighting type (studio, cinematic, neon), and contrast.
5.  **Decor Elements (Chi tiết trang trí):** Define specific graphical elements, shapes, particles, or props that support the concept.
6.  **Typography (Chữ):** Define the font style for the *Main Headline* and *Secondary Text* hierarchy.

### INPUT HANDLING RULES (CRITICAL)
*   **REFERENCE IMAGE LOGIC:**
    The user may provide up to 3 Reference Images. Each image has specific **Attributes** to copy (e.g., Image 1 for Style, Image 2 for Composition).
    You MUST **STRICTLY EXTRACT AND COPY** the specific aspect from the corresponding Reference Image.

    *   If Image X has 'Subject' -> Mimic the pose/subject arrangement from Image X.
    *   If Image X has 'Style' -> Mimic the artistic rendering/vibe from Image X.
    *   If Image X has 'Composition' -> Copy the layout structure from Image X.
    *   If Image X has 'Decor' -> Mimic the decorative elements/shapes from Image X.
    *   If Image X has 'Typography' -> Describe and mimic the font style/placement from Image X.

*   **COLOR/LIGHTING CONFLICT RULE (IMPORTANT):**
    *   **Case A (Normal):** If any Reference Image has 'Color' checked and Color Mode is NOT 'Brand Logo' -> Copy Color Palette and Lighting from that Reference.
    *   **Case B (Conflict):** If any Reference Image has 'Color' checked AND Color Mode IS 'Brand Logo' -> **IGNORE Reference Colors**. You must use **BRAND LOGO COLORS** for the palette, and ONLY use the Reference Image for **LIGHTING/CONTRAST/ATMOSPHERE**.

### OUTPUT FORMAT (JSON)
Return a JSON object with:
1.  "designPlan": Object containing the 6 Vietnamese strings defined above.
2.  "analysis": A short creative summary in Vietnamese.
3.  "final_prompt": The optimized English prompt derived from the plan.
4.  "recommendedAspectRatio": The best ratio.
`;

const RESPONSE_SCHEMA: Schema = {
  type: Type.OBJECT,
  properties: {
    designPlan: {
      type: Type.OBJECT,
      properties: {
        subject: { type: Type.STRING, description: "Analysis of Subject & Content in Vietnamese" },
        styleContext: { type: Type.STRING, description: "Analysis of Style & Context in Vietnamese" },
        composition: { type: Type.STRING, description: "Analysis of Composition & Camera in Vietnamese" },
        colorLighting: { type: Type.STRING, description: "Analysis of Color & Lighting in Vietnamese" },
        decorElements: { type: Type.STRING, description: "Analysis of Decor Elements in Vietnamese" },
        typography: { type: Type.STRING, description: "Analysis of Typography in Vietnamese" }
      },
      required: ["subject", "styleContext", "composition", "colorLighting", "decorElements", "typography"]
    },
    analysis: {
      type: Type.STRING,
      description: "Brief summary in Vietnamese.",
    },
    final_prompt: {
      type: Type.STRING,
      description: "The detailed English prompt.",
    },
    recommendedAspectRatio: {
      type: Type.STRING,
      enum: ["1:1", "3:4", "4:3", "9:16", "16:9"],
    },
  },
  required: ["designPlan", "analysis", "final_prompt", "recommendedAspectRatio"],
};

export const generateArtDirection = async (request: ArtDirectionRequest): Promise<ArtDirectionResponse> => {
  try {
    const parts: any[] = [];

    // Logic for Conflict: Brand Logo Mode vs Reference 'Color'
    const isBrandLogoMode = request.colorMode === ColorMode.BRAND_LOGO;

    // Check if ANY reference image has 'Color' selected
    const anyRefHasColor = request.referenceImages.some(img => img.attributes.includes('Color'));

    let colorInstruction = "";

    // Construct Reference Instructions
    let allRefInstructions = "";

    request.referenceImages.forEach((refImg, index) => {
        const i = index + 1;
        let activeAttributes = [...refImg.attributes];

        let specificNote = "";

        if (isBrandLogoMode && activeAttributes.includes('Color')) {
             // Conflict logic: Remove Color from the "Copy" list for this image context, replace with Lighting note
             activeAttributes = activeAttributes.filter(attr => attr !== 'Color');
             specificNote = `**SPECIAL LIGHTING INSTRUCTION for Ref ${i}:** 'Color' attribute was checked, BUT mode is 'Brand Logo'. -> Extract **LIGHTING & SHADOWS ONLY** from Ref Image ${i}. **DO NOT** use its Colors. Use Brand Logo Colors instead.`;
        }

        if (activeAttributes.length > 0 || specificNote) {
            allRefInstructions += `
            -- REFERENCE IMAGE ${i} --
            Attributes to Copy: [${activeAttributes.join(', ')}]
            ${specificNote}
            `;
        }
    });

    if (isBrandLogoMode) {
        colorInstruction = "STRICTLY USE COLORS EXTRACTED FROM THE PROVIDED BRAND LOGO IMAGE.";
    } else {
        colorInstruction = request.colorMode === 'Custom' ? `Custom Palette: ${request.customColors.join(', ')}` : 'Auto/AI Decision';
    }

    let styleInstruction = request.visualStyle === VisualStyle.FOLLOW_REF 
        ? "STRICTLY MIMIC the Reference Image style(s)." 
        : request.visualStyle;

    let promptText = `
      -- CORE DATA --
      Product: ${request.productType} (${request.width}cm x ${request.height}cm)
      Headline: "${request.mainHeadline}"
      Secondary Text: "${request.secondaryText}"

      -- BRANDING DATA --
      Has Brand Logo: ${request.logoImage ? "YES (See image input)" : "NO"}
      Color Mode: ${request.colorMode}
      Color Instruction: ${colorInstruction}

      -- USER REQUIREMENTS --
      Layout/Description: "${request.layoutRequirements}"
      Font Prefs: "${request.fontPreferences}"
      Style: ${styleInstruction}
      Product Mode: ${request.productImageMode}

      -- REFERENCE INSTRUCTIONS (CRITICAL) --
      ${allRefInstructions}
    `;

    parts.push({ text: promptText });

    // Attach Images
    if (request.logoImage) parts.push({ inlineData: { mimeType: "image/png", data: request.logoImage.split(',')[1] } });
    request.assetImages.forEach(img => parts.push({ inlineData: { mimeType: "image/png", data: img.split(',')[1] } }));
    if (request.mainHeadlineImage) parts.push({ inlineData: { mimeType: "image/png", data: request.mainHeadlineImage.split(',')[1] } });

    // Attach Reference Images with Labels
    request.referenceImages.forEach((refImg, index) => {
        parts.push({ text: `REFERENCE IMAGE ${index + 1}:`});
        parts.push({ inlineData: { mimeType: "image/png", data: refImg.image.split(',')[1] } });
    });

    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: { parts },
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        responseMimeType: "application/json",
        responseSchema: RESPONSE_SCHEMA,
      },
    });

    const text = response.text;
    if (!text) throw new Error("No response from AI Director");
    return JSON.parse(text) as ArtDirectionResponse;
  } catch (error) {
    console.error("Error generating art direction:", error);
    throw error;
  }
};

// Function to Update/Refine the Plan based on user feedback
export const updateArtDirection = async (
    currentPlan: ArtDirectionResponse, 
    userFeedback: string, 
    selectedCriteria: string[]
): Promise<ArtDirectionResponse> => {
    try {
        const prompt = `
            You are the AI Art Director refining a design plan.

            **CURRENT PLAN (JSON):**
            ${JSON.stringify(currentPlan.designPlan)}

            **USER FEEDBACK:**
            The user wants to modify the following specific criteria: ${selectedCriteria.join(', ')}.
            Instruction: "${userFeedback}"

            **TASK:**
            1. Update the specific fields in 'designPlan' based on the feedback. Keep other fields consistent if not mentioned.
            2. Re-write the 'final_prompt' in English to reflect these changes.
            3. Update the 'analysis' summary.

            Return the full JSON object adhering to the same schema.
        `;

        const response = await ai.models.generateContent({
            model: "gemini-3-flash-preview",
            contents: { parts: [{ text: prompt }] },
            config: {
                systemInstruction: SYSTEM_INSTRUCTION, // Use same system instruction to maintain persona
                responseMimeType: "application/json",
                responseSchema: RESPONSE_SCHEMA,
            },
        });

        const text = response.text;
        if (!text) throw new Error("No response from AI update");
        return JSON.parse(text) as ArtDirectionResponse;

    } catch (error) {
        console.error("Error updating art direction:", error);
        throw error;
    }
};

export const generateDesignImage = async (
  prompt: string, 
  aspectRatio: string, 
  batchSize: number, 
  imageSize: string,
  assetImages: string[] = [],
  logoImage: string | null = null
): Promise<string[]> => {
  try {
    const modelName = "gemini-3-pro-image-preview";
    const parts: any[] = [{ text: prompt }];

    if (logoImage) {
      parts.push({ text: " REFERENCE_IMAGE_LOGO (Incorporate this logo unchanged): " });
      parts.push({ inlineData: { mimeType: "image/png", data: logoImage.split(',')[1] } });
    }

    if (assetImages.length > 0) {
       parts.push({ text: " REFERENCE_IMAGE_PRODUCT (Main Subject - Isolate and Place): " });
       assetImages.forEach(img => {
          parts.push({ inlineData: { mimeType: "image/png", data: img.split(',')[1] } });
       });
    }

    const promises = Array.from({ length: batchSize }).map(async () => {
      const response = await ai.models.generateContent({
        model: modelName,
        contents: { parts },
        config: { imageConfig: { aspectRatio: aspectRatio, imageSize: imageSize } },
      });

      for (const part of response.candidates?.[0]?.content?.parts || []) {
        if (part.inlineData) return `data:image/png;base64,${part.inlineData.data}`;
      }
      return null;
    });

    const results = await Promise.all(promises);
    return results.filter((url): url is string => url !== null);
  } catch (error) {
    console.error("Error generating image:", error);
    throw error;
  }
};

export const refineDesignImage = async (sourceImageBase64: string, instruction: string, aspectRatio: string, imageSize: string): Promise<string[]> => {
  try {
    const modelName = "gemini-3-pro-image-preview";
    const prompt = `Perform the following edit: ${instruction}. Keep layout/elements consistent. High fidelity.`;

    const response = await ai.models.generateContent({
      model: modelName,
      contents: {
        parts: [
          { text: prompt },
          { inlineData: { mimeType: "image/png", data: sourceImageBase64.split(',')[1] } }
        ]
      },
      config: { imageConfig: { aspectRatio, imageSize } },
    });

    const urls: string[] = [];
    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData) urls.push(`data:image/png;base64,${part.inlineData.data}`);
    }
    return urls;
  } catch (error) {
    console.error("Error refining image:", error);
    throw error;
  }
};

export const separateDesignComponents = async (originalPrompt: string, aspectRatio: string, imageSize: string, referenceImageBase64?: string): Promise<{ background: string | null, textLayer: string | null, elements: string | null }> => {
  const modelName = "gemini-3-pro-image-preview";
  const buildParts = (taskPrompt: string) => {
    const parts: any[] = [{ text: taskPrompt }];
    if (referenceImageBase64) parts.push({ inlineData: { mimeType: "image/png", data: referenceImageBase64.split(',')[1] } });
    return parts;
  };

  const bgPrompt = `Based on reference: GENERATE BACKGROUND ONLY. Remove text, products. Keep texture/lighting.`;
  const textPrompt = `Based on reference: GENERATE TYPOGRAPHY LAYER ONLY on WHITE background. Replicate font/layout exactly.`;
  const elementsPrompt = `Based on reference: GENERATE PRODUCT/ELEMENTS ONLY on WHITE background. Isolate main assets.`;

  try {
    const [bgRes, textRes, elemRes] = await Promise.all([
      ai.models.generateContent({ model: modelName, contents: { parts: buildParts(bgPrompt) }, config: { imageConfig: { aspectRatio, imageSize } } }),
      ai.models.generateContent({ model: modelName, contents: { parts: buildParts(textPrompt) }, config: { imageConfig: { aspectRatio, imageSize } } }),
      ai.models.generateContent({ model: modelName, contents: { parts: buildParts(elementsPrompt) }, config: { imageConfig: { aspectRatio, imageSize } } })
    ]);

    const extractImage = (response: any) => {
       for (const part of response.candidates?.[0]?.content?.parts || []) {
        if (part.inlineData) return `data:image/png;base64,${part.inlineData.data}`;
      }
      return null;
    };

    return { background: extractImage(bgRes), textLayer: extractImage(textRes), elements: extractImage(elemRes) };
  } catch (error) {
    console.error("Error separating components:", error);
    throw error;
  }
};

