  STANDEE = 'Standee',
  BACKDROP = 'Backdrop',
  BANNER = 'Banner',
  SOCIAL_POST = 'Social Media Post',
  FLYER = 'Flyer'
}

export enum VisualStyle {
  MODERN_TECH = 'Modern Tech',
  LUXURY = 'Luxury',
  VINTAGE = 'Vintage',
  FESTIVE = 'Festive',
  MINIMALIST = 'Minimalist',
  CORPORATE = 'Corporate',
  CYBERPUNK = 'Cyberpunk',
  NATURAL_ORGANIC = 'Natural/Organic',
  FOLLOW_REF = 'Follow Reference' // New option
}

export enum ColorMode {
  AUTO = 'Auto',
  CUSTOM = 'Custom',
  BRAND_LOGO = 'Brand Logo' // New option
}

export enum QualityLevel {
  LOW = '1K',
  MEDIUM = '2K',
  HIGH = '4K'
}

export enum ProductImageMode {
  REALISTIC = 'Realistic', // Làm nét, giữ nguyên chi tiết, tách nền
  STYLIZED = 'Stylized'    // AI Cách điệu, vẽ lại
}

export interface ReferenceImageConfig {
  id: string;
  image: string; // Base64 string
  attributes: string[]; // 'Subject', 'Style', 'Composition', 'Color', 'Decor', 'Typography'
}

export interface ArtDirectionRequest {
  productType: ProductType;
  // Content Text Split
  mainHeadline: string;
  mainHeadlineImage: string | null; // Image reference specifically for the headline style
  secondaryText: string;

  visualStyle: VisualStyle;
  colorMode: ColorMode;
  customColors: string[];

  // Design Requirements
  layoutRequirements: string; // Specific placement instructions & Scene description merged
  fontPreferences: string; // New field for typography/font usage

  width: string;
  height: string;

  // Assets & Logo
  logoImage: string | null; // Base64 string for Brand Logo
  assetImages: string[]; // Base64 strings
  productImageMode: ProductImageMode; // How to treat the asset images

  // Updated to support multiple references
  referenceImages: ReferenceImageConfig[]; 

  batchSize: 1 | 3 | 5;
  quality: QualityLevel;
}

// New Interface for Decomposed Plan
export interface DesignPlan {
  subject: string;        // Chủ thể chính & Nội dung phụ
  styleContext: string;   // Bối cảnh & Phong cách
  composition: string;    // Bố cục & Góc máy
  colorLighting: string;  // Màu sắc & Ánh sáng
  decorElements: string;  // Chi tiết trang trí
  typography: string;     // Typography (Chữ)
}

export interface ArtDirectionResponse {
  designPlan: DesignPlan; // Structured plan
  analysis: string;       // General summary
  final_prompt: string;
  recommendedAspectRatio: "1:1" | "3:4" | "4:3" | "9:16" | "16:9";
}

export interface ImageGenerationResult {
  imageUrls: string[];
  loading: boolean;
  error: string | null;
}

export interface SeparatedAssets {
  background: string | null;
  textLayer: string | null;
  subjects: string[]; // Multiple subject layers
  decor: string[];    // Multiple decor layers
  lighting: string | null; // Lighting/Atmosphere layer
  loading: boolean;
  error: string | null;
}

import { GoogleGenAI, Type, Schema } from "@google/genai";
import { ArtDirectionRequest, ArtDirectionResponse, ProductImageMode, VisualStyle, ColorMode, DesignPlan } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const SYSTEM_INSTRUCTION = `
You are a professional "AI Art Director" and "Prompt Engineer".
Your task is to **DECOMPOSE** the user request into a specific 6-point design plan and then synthesize a highly detailed English prompt.

### 6-POINT DECOMPOSITION CRITERIA (Must be in VIETNAMESE for the 'designPlan'):
1.  **Subject & Secondary Content (Chủ thể):** 
    *   **PRIORITY RULE:** If the user provides **ASSET IMAGES** (Product Images), these are the **HERO**. The Reference Image's subject is only a placeholder for pose/angle.
    *   Define the main hero image and how Secondary Text is integrated.
2.  **Style & Context (Bối cảnh & Phong cách):** Define the environment, artistic style (Reference Image attributes go here), and overall mood.
3.  **Composition & Camera (Bố cục):** Define the layout structure, camera angle, and focal length.
4.  **Color & Lighting (Màu sắc & Ánh sáng):** 
    *   If **Brand Logo** is provided, analyze and list its specific colors.
    *   Define the palette, lighting type, and contrast.
5.  **Decor Elements (Chi tiết trang trí):** Define specific graphical elements, shapes, particles, or props.
6.  **Typography (Chữ):** 
    *   **CRITICAL FOR REFERENCE IMAGES:** If 'Typography' is selected on a Reference, you must describe BOTH the **Font Style** (Weight, Serif/Sans) AND the **TEXT LAYOUT** (Kerning, Leading, Stacking, Rotation, Hierarchy). 
    *   Explain how the User's "Main Headline" will physically match this arrangement.

### INPUT HANDLING RULES (CRITICAL)
*   **REFERENCE IMAGE LOGIC:**
    The user may provide up to 3 Reference Images. Each image has specific **Attributes** to copy.

    *   **If Image X has 'Subject' OR 'Composition' AND User has 'Asset Images':**
        -> **SWAP OPERATION:** Use the layout/pose/angle from Image X, but **REPLACE** the subject in Image X with the User's provided Asset Image.
        -> *Example:* "Place the User's [Asset Product] in the exact same position and angle as the [Reference Subject]."

    *   **If Image X has 'Typography' -> DEEP COPY MODE:**
        1.  Analyze Font Family (Serif/Sans/Script).
        2.  Analyze **TEXT ARRANGEMENT** (Is it stacked? Arched? Overlapping the subject? Huge & Bold?).
        3.  **ACTION:** "Format the text '${'{mainHeadline}'}' to visually mirror the typesetting and layout of the text in Reference Image X."

*   **COLOR/LIGHTING CONFLICT RULE:**
    *   **Brand Logo Mode overrides Reference Colors:** If Color Mode IS 'Brand Logo', ignore Reference Colors. Use Logo colors, but keep Reference Lighting/Contrast.

### OUTPUT FORMAT (JSON)
Return a JSON object with:
1.  "designPlan": Object containing the 6 Vietnamese strings defined above.
2.  "analysis": A short creative summary in Vietnamese.
3.  "final_prompt": The optimized English prompt derived from the plan.
4.  "recommendedAspectRatio": The best ratio.
`;

const RESPONSE_SCHEMA: Schema = {
  type: Type.OBJECT,
  properties: {
    designPlan: {
      type: Type.OBJECT,
      properties: {
        subject: { type: Type.STRING, description: "Analysis of Subject & Content in Vietnamese" },
        styleContext: { type: Type.STRING, description: "Analysis of Style & Context in Vietnamese" },
        composition: { type: Type.STRING, description: "Analysis of Composition & Camera in Vietnamese" },
        colorLighting: { type: Type.STRING, description: "Analysis of Color & Lighting in Vietnamese" },
        decorElements: { type: Type.STRING, description: "Analysis of Decor Elements in Vietnamese" },
        typography: { type: Type.STRING, description: "Analysis of Typography in Vietnamese" }
      },
      required: ["subject", "styleContext", "composition", "colorLighting", "decorElements", "typography"]
    },
    analysis: {
      type: Type.STRING,
      description: "Brief summary in Vietnamese.",
    },
    final_prompt: {
      type: Type.STRING,
      description: "The detailed English prompt.",
    },
    recommendedAspectRatio: {
      type: Type.STRING,
      enum: ["1:1", "3:4", "4:3", "9:16", "16:9"],
    },
  },
  required: ["designPlan", "analysis", "final_prompt", "recommendedAspectRatio"],
};

export const generateArtDirection = async (request: ArtDirectionRequest): Promise<ArtDirectionResponse> => {
  try {
    const parts: any[] = [];

    // Logic for Conflict: Brand Logo Mode vs Reference 'Color'
    const isBrandLogoMode = request.colorMode === ColorMode.BRAND_LOGO;
    const hasUserAssets = request.assetImages.length > 0;

    // Check if ANY reference image has 'Color' selected
    const anyRefHasColor = request.referenceImages.some(img => img.attributes.includes('Color'));

    let colorInstruction = "";

    // Construct Reference Instructions
    let allRefInstructions = "";

    request.referenceImages.forEach((refImg, index) => {
        const i = index + 1;
        let activeAttributes = [...refImg.attributes];

        let specificNote = "";

        // Handle Typography Specifics
        if (activeAttributes.includes('Typography')) {
            specificNote += `\n   - **TYPOGRAPHY & LAYOUT INSTRUCTION:** 
             1. Analyze the font style (Weight, Family) in Ref Image ${i}.
             2. **CRITICAL:** Analyze the **SPATIAL ARRANGEMENT** (Alignment, Line Spacing, Overlap) of the text in Ref Image ${i}.
             3. **ACTION:** Render the Main Headline "${request.mainHeadline}" to EXACTLY MIMIC this visual hierarchy and layout.`;
        }

        // Handle Subject/Composition with User Assets
        if (hasUserAssets && (activeAttributes.includes('Subject') || activeAttributes.includes('Composition'))) {
             specificNote += `\n   - **ASSET INTEGRATION (CRITICAL):** The User provided a PRODUCT IMAGE (Asset). 
             **DO NOT** generate the subject from Ref Image ${i}. 
             INSTEAD, take the **Composition/Angle/Pose** from Ref Image ${i} and **INSERT** the User's Asset into that spot.`;
        }

        // Handle Color Conflict
        if (isBrandLogoMode && activeAttributes.includes('Color')) {
             // Conflict logic: Remove Color from the "Copy" list for this image context, replace with Lighting note
             activeAttributes = activeAttributes.filter(attr => attr !== 'Color');
             specificNote += `\n   - **LIGHTING ONLY:** 'Color' attribute was checked, BUT mode is 'Brand Logo'. -> Extract **LIGHTING & SHADOWS ONLY** from Ref Image ${i}. **DO NOT** use its Colors. Use Brand Logo Colors instead.`;
        }

        if (activeAttributes.length > 0 || specificNote) {
            allRefInstructions += `
            -- REFERENCE IMAGE ${i} --
            Attributes to Copy: [${activeAttributes.join(', ')}]
            ${specificNote}
            `;
        }
    });

    if (isBrandLogoMode) {
        colorInstruction = "STRICTLY USE COLORS EXTRACTED FROM THE PROVIDED BRAND LOGO IMAGE.";
    } else {
        colorInstruction = request.colorMode === 'Custom' ? `Custom Palette: ${request.customColors.join(', ')}` : 'Auto/AI Decision';
    }

    let styleInstruction = request.visualStyle === VisualStyle.FOLLOW_REF 
        ? "STRICTLY MIMIC the Reference Image style(s)." 
        : request.visualStyle;

    let promptText = `
      -- CORE DATA --
      Product Type: ${request.productType}
      Dimensions: ${request.width}cm x ${request.height}cm

      -- TEXT CONTENT --
      Main Headline: "${request.mainHeadline}"
      Secondary Text: "${request.secondaryText}"

      -- BRANDING & ASSETS --
      Has Brand Logo: ${request.logoImage ? "YES" : "NO"}
      Has User Product Assets: ${hasUserAssets ? "YES (PRIORITY HERO)" : "NO"}
      Color Mode: ${request.colorMode}
      Color Instruction: ${colorInstruction}

      -- USER REQUIREMENTS --
      Layout/Description: "${request.layoutRequirements}"
      Font Preferences: "${request.fontPreferences}"
      Visual Style: ${styleInstruction}
      Product Mode: ${request.productImageMode}

      -- REFERENCE INSTRUCTIONS (CRITICAL) --
      ${allRefInstructions}
    `;

    parts.push({ text: promptText });

    // Attach Images
    if (request.logoImage) parts.push({ inlineData: { mimeType: "image/png", data: request.logoImage.split(',')[1] } });
    request.assetImages.forEach(img => parts.push({ inlineData: { mimeType: "image/png", data: img.split(',')[1] } }));
    if (request.mainHeadlineImage) parts.push({ inlineData: { mimeType: "image/png", data: request.mainHeadlineImage.split(',')[1] } });

    // Attach Reference Images with Labels
    request.referenceImages.forEach((refImg, index) => {
        parts.push({ text: `REFERENCE IMAGE ${index + 1}:`});
        parts.push({ inlineData: { mimeType: "image/png", data: refImg.image.split(',')[1] } });
    });

    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: { parts },
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        responseMimeType: "application/json",
        responseSchema: RESPONSE_SCHEMA,
      },
    });

    const text = response.text;
    if (!text) throw new Error("No response from AI Director");
    return JSON.parse(text) as ArtDirectionResponse;
  } catch (error) {
    console.error("Error generating art direction:", error);
    throw error;
  }
};

// Function to Update/Refine the Plan based on user manual edits
export const regeneratePromptFromPlan = async (
    updatedPlan: DesignPlan,
    originalRequest: ArtDirectionRequest,
    currentAspectRatio: string
): Promise<ArtDirectionResponse> => {
    try {
        const prompt = `
            You are the AI Art Director. The user has MANUALLY EDITED the "Design Plan" (in Vietnamese).

            **YOUR TASK:**
            1.  Read the **UPDATED DESIGN PLAN** below.
            2.  Re-synthesize the "final_prompt" (English) to STRICTLY reflect these new Vietnamese details.
            3.  Ensure the English prompt still incorporates instructions for the provided images (Logo, Assets, References) mentioned in the original request context.

            **UPDATED DESIGN PLAN (VIETNAMESE):**
            ${JSON.stringify(updatedPlan, null, 2)}

            **ORIGINAL CONTEXT:**
            Product: ${originalRequest.productType}
            Headline: ${originalRequest.mainHeadline}

            **OUTPUT:**
            Return the full JSON (ArtDirectionResponse) with the 'designPlan' (same as provided), updated 'analysis', and the NEW 'final_prompt'.
            Keep 'recommendedAspectRatio' as: ${currentAspectRatio}.
        `;

        const response = await ai.models.generateContent({
            model: "gemini-3-flash-preview",
            contents: { parts: [{ text: prompt }] },
            config: {
                systemInstruction: SYSTEM_INSTRUCTION,
                responseMimeType: "application/json",
                responseSchema: RESPONSE_SCHEMA,
            },
        });

        const text = response.text;
        if (!text) throw new Error("No response from AI update");
        return JSON.parse(text) as ArtDirectionResponse;

    } catch (error) {
        console.error("Error regenerating prompt from plan:", error);
        throw error;
    }
};

export const generateDesignImage = async (
  prompt: string, 
  aspectRatio: string, 
  batchSize: number, 
  imageSize: string,
  assetImages: string[] = [],
  logoImage: string | null = null
): Promise<string[]> => {
  try {
    const modelName = "gemini-3-pro-image-preview";
    const parts: any[] = [{ text: prompt }];

    if (logoImage) {
      parts.push({ text: " REFERENCE_IMAGE_LOGO (Incorporate this logo unchanged): " });
      parts.push({ inlineData: { mimeType: "image/png", data: logoImage.split(',')[1] } });
    }

    if (assetImages.length > 0) {
       parts.push({ text: " REFERENCE_IMAGE_PRODUCT (Main Subject - Isolate and Place): " });
       assetImages.forEach(img => {
          parts.push({ inlineData: { mimeType: "image/png", data: img.split(',')[1] } });
       });
    }

    const promises = Array.from({ length: batchSize }).map(async () => {
      const response = await ai.models.generateContent({
        model: modelName,
        contents: { parts },
        config: { imageConfig: { aspectRatio: aspectRatio, imageSize: imageSize } },
      });

      for (const part of response.candidates?.[0]?.content?.parts || []) {
        if (part.inlineData) return `data:image/png;base64,${part.inlineData.data}`;
      }
      return null;
    });

    const results = await Promise.all(promises);
    return results.filter((url): url is string => url !== null);
  } catch (error) {
    console.error("Error generating image:", error);
    throw error;
  }
};

export const refineDesignImage = async (sourceImageBase64: string, instruction: string, aspectRatio: string, imageSize: string): Promise<string[]> => {
  try {
    const modelName = "gemini-3-pro-image-preview";
    const prompt = `Perform the following edit: ${instruction}. Keep layout/elements consistent. High fidelity.`;

    const response = await ai.models.generateContent({
      model: modelName,
      contents: {
        parts: [
          { text: prompt },
          { inlineData: { mimeType: "image/png", data: sourceImageBase64.split(',')[1] } }
        ]
      },
      config: { imageConfig: { aspectRatio, imageSize } },
    });

    const urls: string[] = [];
    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData) urls.push(`data:image/png;base64,${part.inlineData.data}`);
    }
    return urls;
  } catch (error) {
    console.error("Error refining image:", error);
    throw error;
  }
};

export const separateDesignComponents = async (originalPrompt: string, aspectRatio: string, _userImageSize: string, referenceImageBase64?: string): Promise<{ background: string | null, textLayer: string | null, subjects: string[], decor: string[], lighting: string | null }> => {
  const modelName = "gemini-3-pro-image-preview";
  const MAX_QUALITY_SIZE = "4K"; 

  const buildParts = (taskPrompt: string) => {
    const parts: any[] = [{ text: taskPrompt }];
    if (referenceImageBase64) parts.push({ inlineData: { mimeType: "image/png", data: referenceImageBase64.split(',')[1] } });
    return parts;
  };

  // 1. Background
  const bgPrompt = `Based on reference: GENERATE BACKGROUND ONLY. Remove text, products, foreground elements. Keep texture, lighting environment. High Resolution.`;

  // 2. Subjects (Attempt to get Main and Secondary/Angle)
  const subjectMainPrompt = `Based on reference: GENERATE & ISOLATE THE SINGLE MAIN HERO SUBJECT (Product/Person) on WHITE background. High precision. No extra decor.`;
  const subjectSecondaryPrompt = `Based on reference: GENERATE & ISOLATE SECONDARY SUBJECTS (or alternate angle of hero) on WHITE background. High precision.`;

  // 3. Text
  const textPrompt = `Based on reference: GENERATE TYPOGRAPHY LAYER ONLY on WHITE background. Replicate font/layout exactly. High Resolution.`;

  // 4. Decor (Main Props & Particles)
  const decorMainPrompt = `Based on reference: GENERATE & ISOLATE MAIN 3D PROPS (Podiums, Stands, Large Geometric Shapes) on WHITE background. No small particles.`;
  const decorParticlesPrompt = `Based on reference: GENERATE & ISOLATE DECORATIVE PARTICLES (Leaves, Confetti, Abstract Floaters) scattered on WHITE background.`;

  // 5. Lighting
  const lightingPrompt = `Based on reference: GENERATE LIGHTING & ATMOSPHERE LAYER (Light beams, Lens flares, Fog, Shadows) on BLACK background (Screen Mode). High Resolution.`;

  try {
    const [bgRes, textRes, subMainRes, subSecRes, decorMainRes, decorPartRes, lightRes] = await Promise.all([
      ai.models.generateContent({ model: modelName, contents: { parts: buildParts(bgPrompt) }, config: { imageConfig: { aspectRatio, imageSize: MAX_QUALITY_SIZE } } }),
      ai.models.generateContent({ model: modelName, contents: { parts: buildParts(textPrompt) }, config: { imageConfig: { aspectRatio, imageSize: MAX_QUALITY_SIZE } } }),
      ai.models.generateContent({ model: modelName, contents: { parts: buildParts(subjectMainPrompt) }, config: { imageConfig: { aspectRatio, imageSize: MAX_QUALITY_SIZE } } }),
      ai.models.generateContent({ model: modelName, contents: { parts: buildParts(subjectSecondaryPrompt) }, config: { imageConfig: { aspectRatio, imageSize: MAX_QUALITY_SIZE } } }),
      ai.models.generateContent({ model: modelName, contents: { parts: buildParts(decorMainPrompt) }, config: { imageConfig: { aspectRatio, imageSize: MAX_QUALITY_SIZE } } }),
      ai.models.generateContent({ model: modelName, contents: { parts: buildParts(decorParticlesPrompt) }, config: { imageConfig: { aspectRatio, imageSize: MAX_QUALITY_SIZE } } }),
      ai.models.generateContent({ model: modelName, contents: { parts: buildParts(lightingPrompt) }, config: { imageConfig: { aspectRatio, imageSize: MAX_QUALITY_SIZE } } })
    ]);

    const extractImage = (response: any) => {
       for (const part of response.candidates?.[0]?.content?.parts || []) {
        if (part.inlineData) return `data:image/png;base64,${part.inlineData.data}`;
      }
      return null;
    };

    const subjects = [];
    const s1 = extractImage(subMainRes);
    const s2 = extractImage(subSecRes);
    if (s1) subjects.push(s1);
    if (s2) subjects.push(s2);

    const decor = [];
    const d1 = extractImage(decorMainRes);
    const d2 = extractImage(decorPartRes);
    if (d1) decor.push(d1);
    if (d2) decor.push(d2);

    return { 
        background: extractImage(bgRes), 
        textLayer: extractImage(textRes), 
        subjects: subjects,
        decor: decor,
        lighting: extractImage(lightRes)
    };
  } catch (error) {
    console.error("Error separating components:", error);
    throw error;
  }
};

import React, { useState } from 'react';
import InputForm from './components/InputForm';
import ResultDisplay from './components/ResultDisplay';
import { ArtDirectionRequest, ArtDirectionResponse, ColorMode, ImageGenerationResult, ProductType, VisualStyle, QualityLevel, SeparatedAssets, ProductImageMode, DesignPlan } from './types';
import { generateArtDirection, generateDesignImage, separateDesignComponents, refineDesignImage, regeneratePromptFromPlan } from './services/geminiService';

const App: React.FC = () => {
  // Form State
  const [request, setRequest] = useState<ArtDirectionRequest>({
    productType: ProductType.POSTER,
    mainHeadline: '',
    mainHeadlineImage: null,
    secondaryText: '',
    layoutRequirements: '',
    // imageElementDescription removed
    fontPreferences: '',
    visualStyle: VisualStyle.MODERN_TECH,
    colorMode: ColorMode.AUTO,
    customColors: ['#7c3aed', '#2563eb'],
    width: '',
    height: '',

    // Assets
    assetImages: [],
    logoImage: null,
    productImageMode: ProductImageMode.REALISTIC,

    referenceImages: [], // Initialized as empty array
    batchSize: 1,
    quality: QualityLevel.LOW
  });

  // Result States
  const [artDirection, setArtDirection] = useState<ArtDirectionResponse | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false); // State for Step 1: Analysis
  const [isUpdatingPlan, setIsUpdatingPlan] = useState(false); // State for updating plan

  // 1. Original Generation Results
  const [imageResult, setImageResult] = useState<ImageGenerationResult>({
    imageUrls: [],
    loading: false,
    error: null
  });

  // 2. Refinement Results (New state for editing)
  const [refinementResult, setRefinementResult] = useState<ImageGenerationResult>({
    imageUrls: [],
    loading: false,
    error: null
  });

  const [separatedAssets, setSeparatedAssets] = useState<SeparatedAssets>({
    background: null,
    textLayer: null,
    subjects: [],
    decor: [],
    lighting: null,
    loading: false,
    error: null
  });

  // Handlers
  const handleInputChange = (field: keyof ArtDirectionRequest, value: any) => {
    setRequest(prev => ({ ...prev, [field]: value }));
  };

  // STEP 1: Analyze & Plan
  const handleAnalyze = async () => {
    if (!request.mainHeadline && !request.layoutRequirements) return;

    // Reset previous states
    setImageResult(prev => ({ ...prev, loading: false, error: null, imageUrls: [] }));
    setRefinementResult({ imageUrls: [], loading: false, error: null });
    setSeparatedAssets({ background: null, textLayer: null, subjects: [], decor: [], lighting: null, loading: false, error: null }); 
    setArtDirection(null);
    setIsAnalyzing(true);

    try {
      console.log("Analyzing art direction...");
      const direction = await generateArtDirection(request);
      setArtDirection(direction);
      setIsAnalyzing(false);
    } catch (err: any) {
      console.error(err);
      setIsAnalyzing(false);
      setImageResult(prev => ({
        ...prev,
        error: err.message || "Có lỗi xảy ra khi phân tích yêu cầu."
      }));
    }
  };

  // Update Plan Handler
  const handleUpdatePlan = async (updatedPlan: DesignPlan) => {
    if (!artDirection) return;

    setIsUpdatingPlan(true);
    try {
       const newResponse = await regeneratePromptFromPlan(
           updatedPlan, 
           request, 
           artDirection.recommendedAspectRatio
       );
       setArtDirection(newResponse); // Update state with new prompt and analysis
       setIsUpdatingPlan(false);
    } catch (err) {
        console.error(err);
        setIsUpdatingPlan(false);
        // Could allow error feedback UI here if needed
    }
  };

  // STEP 2: Generate Final Images (Called from ResultDisplay)
  // Added 'append' parameter to support "Generate More Ideas" without clearing previous results
  const handleGenerateFinalImages = async (finalPrompt: string, append: boolean = false) => {
    if (!artDirection) return;

    setImageResult(prev => ({ 
      ...prev, 
      loading: true, 
      error: null, 
      // If append is true, keep existing images. If false (new generation), clear them.
      imageUrls: append ? prev.imageUrls : [] 
    }));

    try {
      console.log(`Generating ${request.batchSize} images...`);
      const images = await generateDesignImage(
        finalPrompt, 
        artDirection.recommendedAspectRatio, 
        request.batchSize, 
        request.quality,
        request.assetImages, 
        request.logoImage
      );

      setImageResult(prev => ({
        // Concatenate new images to existing list if appending
        imageUrls: append ? [...prev.imageUrls, ...images] : images,
        loading: false,
        error: images.length === 0 ? "Không thể tạo hình ảnh." : null
      }));

    } catch (err: any) {
      console.error(err);
      setImageResult(prev => ({
        ...prev,
        loading: false,
        error: err.message || "Có lỗi xảy ra khi tạo hình ảnh."
      }));
    }
  };

  const handleRegenerateImage = async (newPrompt: string) => {
    if (!artDirection) return;
    // Just reuse the generation logic with new prompt, reset list
    handleGenerateFinalImages(newPrompt, false);
  };

  const handleSeparateLayout = async (selectedImage?: string) => {
    if (!artDirection) return;

    setSeparatedAssets(prev => ({ ...prev, loading: true, error: null }));

    try {
       const result = await separateDesignComponents(
         artDirection.final_prompt,
         artDirection.recommendedAspectRatio,
         request.quality,
         selectedImage // Pass the selected image as reference
       );

       setSeparatedAssets({
         background: result.background,
         textLayer: result.textLayer,
         subjects: result.subjects,
         decor: result.decor,
         lighting: result.lighting,
         loading: false,
         error: (!result.background && result.subjects.length === 0) ? "Không thể tách các thành phần." : null
       });

    } catch (err: any) {
      setSeparatedAssets(prev => ({
        ...prev,
        loading: false,
        error: err.message || "Lỗi khi tách bố cục."
      }));
    }
  };

  const handleRefine = async (sourceImage: string, instruction: string) => {
    if (!artDirection) return;

    // Set Refinement loading, keep original images intact
    setRefinementResult(prev => ({ ...prev, loading: true, error: null, imageUrls: [] }));
    setSeparatedAssets({ background: null, textLayer: null, subjects: [], decor: [], lighting: null, loading: false, error: null });

    try {
      const newImages = await refineDesignImage(
        sourceImage,
        instruction,
        artDirection.recommendedAspectRatio,
        request.quality
      );

      setRefinementResult({
        imageUrls: newImages,
        loading: false,
        error: newImages.length === 0 ? "Không thể hiệu chỉnh hình ảnh." : null
      });

    } catch (err: any) {
      setRefinementResult(prev => ({
        ...prev,
        loading: false,
        error: err.message || "Lỗi khi hiệu chỉnh hình ảnh."
      }));
    }
  };

  // Reset refinement when selecting a new image
  const handleResetRefinement = () => {
    setRefinementResult({ imageUrls: [], loading: false, error: null });
  };

  return (
    <div className="min-h-screen bg-[#0f172a] text-slate-200 selection:bg-purple-500/30">
      {/* Background Ambience */}
      <div className="fixed inset-0 z-0 pointer-events-none">
        <div className="absolute top-0 left-1/4 w-96 h-96 bg-purple-600/10 rounded-full blur-[100px]"></div>
        <div className="absolute bottom-0 right-1/4 w-96 h-96 bg-blue-600/10 rounded-full blur-[100px]"></div>
      </div>

      <div className="relative z-10 container mx-auto px-4 py-6 h-screen flex flex-col">
        {/* Header */}
        <header className="flex items-center justify-between mb-6 shrink-0">
          <div className="flex items-center gap-3">
             <div className="w-10 h-10 bg-gradient-to-br from-purple-500 to-blue-600 rounded-lg flex items-center justify-center shadow-lg shadow-purple-500/20">
               <span className="text-white font-bold text-xl">Ai</span>
             </div>
             <div>
               <h1 className="text-xl font-bold text-white tracking-tight">Giám Đốc Nghệ Thuật</h1>
               <p className="text-xs text-slate-400">Powered by Gemini</p>
             </div>
          </div>
          <div className="flex gap-2">
            <span className="px-3 py-1 bg-slate-800 rounded-full text-xs font-medium text-slate-400 border border-slate-700">v1.5 Pro</span>
          </div>
        </header>

        {/* Main Content Grid */}
        <main className="flex-grow grid grid-cols-1 lg:grid-cols-12 gap-6 overflow-hidden min-h-0 pb-2">
          {/* Left: Input Panel */}
          <div className="lg:col-span-4 h-full min-h-[500px]">
            <InputForm 
              values={request} 
              onChange={handleInputChange} 
              onSubmit={handleAnalyze} // Now calls Analyze first
              isGenerating={isAnalyzing || imageResult.loading}
            />
          </div>

          {/* Right: Visualization Panel */}
          <div className="lg:col-span-8 h-full min-h-[500px]">
            <ResultDisplay 
              request={request} // Pass raw request
              artDirection={artDirection} 
              imageResult={imageResult}
              refinementResult={refinementResult}
              isAnalyzing={isAnalyzing}
              isUpdatingPlan={isUpdatingPlan}
              onGenerateImages={handleGenerateFinalImages}
              onUpdatePlan={handleUpdatePlan}
              onRegenerateImage={handleRegenerateImage}
              onSeparateLayout={handleSeparateLayout}
              onRefineImage={handleRefine}
              onResetRefinement={handleResetRefinement}
              separatedAssets={separatedAssets}
            />
          </div>
        </main>
      </div>
    </div>
  );
};

export default App;

