  if (!artDirection && !isAnalyzing && !imageResult.loading && imageResult.imageUrls.length === 0) {
    return (
      <div className="h-full flex items-center justify-center bg-slate-800/30 rounded-2xl border border-slate-700/50 border-dashed">
        <div className="text-center p-8 max-w-md">
          <div className="w-16 h-16 bg-slate-800 rounded-full flex items-center justify-center mx-auto mb-4 text-slate-500">
             <svg xmlns="http://www.w3.org/2000/svg" className="h-8 w-8" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 5H7a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2V7a2 2 0 00-2-2h-2M9 5a2 2 0 002 2h2a2 2 0 002-2M9 5a2 2 0 012-2h2a2 2 0 012 2" />
             </svg>
          </div>
          <h3 className="text-lg font-medium text-slate-300 mb-2">Quy Trình Sáng Tạo</h3>
          <p className="text-slate-500 text-sm">
            1. Nhập yêu cầu & Tải tài nguyên<br/>
            2. AI Phân tích & Lập kế hoạch<br/>
            3. Chỉnh sửa Bố cục trực quan<br/>
            4. Tạo thiết kế cuối cùng
          </p>
        </div>
      </div>
    );
  }

  // State: Analyzing
  if (isAnalyzing) {
    return (
        <div className="h-full flex flex-col items-center justify-center bg-slate-800/30 rounded-2xl border border-slate-700/50">
             <div className="w-16 h-16 border-4 border-blue-500 border-t-purple-500 rounded-full animate-spin mb-6"></div>
             <h3 className="text-xl font-bold text-white mb-2">Đang Phân Tích & Tư Duy...</h3>
             <p className="text-slate-400 text-sm max-w-xs text-center">
                AI đang giải mã yêu cầu (Reverse Engineering), phân rã theo 6 tiêu chí thiết kế chuyên sâu.
             </p>
        </div>
    );
  }

  // Check if any separation data exists
  const hasSeparation = separatedAssets.background || 
                        separatedAssets.textLayer || 
                        separatedAssets.subjects.length > 0 ||
                        separatedAssets.decor.length > 0 ||
                        separatedAssets.lighting ||
                        separatedAssets.loading;

  return (
    <div className="flex flex-col h-full gap-6 overflow-y-auto pr-2 relative">
      {/* Lightbox Modal */}
      {lightboxImage && (
        <div className="fixed inset-0 z-50 bg-black/90 flex items-center justify-center p-4 backdrop-blur-sm" onClick={() => setLightboxImage(null)}>
          <div className="relative max-w-7xl max-h-screen">
            <img src={lightboxImage} alt="Full view" className="max-h-[90vh] max-w-full rounded-lg shadow-2xl" />
            <button 
              className="absolute -top-4 -right-4 bg-white/10 hover:bg-white/20 text-white rounded-full p-2"
              onClick={() => setLightboxImage(null)}
            >
              <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
              </svg>
            </button>
          </div>
        </div>
      )}

      {/* 1. Planning Stage: Analysis & Prompt Editing */}
      {artDirection && localPlan && (
        <div className="bg-slate-800/80 rounded-2xl border border-blue-500/30 overflow-hidden shadow-lg backdrop-blur-sm flex-shrink-0 animate-fade-in-down">
           {/* ... Header ... */}
           <div className="bg-gradient-to-r from-blue-900/40 to-purple-900/40 px-6 py-3 border-b border-white/10 flex items-center justify-between">
             <div className="flex items-center gap-2">
                <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5 text-blue-400" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 5H7a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2V7a2 2 0 00-2-2h-2M9 5a2 2 0 002 2h2a2 2 0 002-2M9 5a2 2 0 012-2h2a2 2 0 012 2" />
                </svg>
                <span className="text-white text-sm font-bold tracking-wider uppercase">Bảng Kế Hoạch & Bố Cục</span>
             </div>
             <div className="flex items-center gap-3">
                 {isUpdatingPlan && <span className="text-xs text-blue-300 animate-pulse">Đang viết lại Prompt...</span>}
                 <span className="text-slate-400 text-xs bg-slate-900/50 px-2 py-1 rounded">Tỉ lệ đề xuất: {artDirection.recommendedAspectRatio}</span>
             </div>
           </div>

           <div className="p-5 space-y-5">
             {/* 1.1 Input Summary Display */}
             <div className="grid grid-cols-2 gap-4 bg-slate-900/50 p-3 rounded-lg border border-slate-700/50 text-xs">
                 <div>
                    <span className="text-slate-500 block">Nội dung phụ (Secondary Content):</span>
                    <span className="text-slate-200 font-medium">{request.secondaryText || "Không có"}</span>
                 </div>
                 <div>
                    <span className="text-slate-500 block">Tham Khảo (Reference):</span>
                    <span className="text-emerald-400 font-medium block leading-tight">
                        {getReferenceSummary()}
                    </span>
                 </div>
             </div>

             {/* 1.2 The 6-Criteria Breakdown Grid */}
             <div>
                <div className="flex justify-between items-center mb-2">
                    <label className="text-xs font-semibold text-blue-400 uppercase block">1. Phân Tích & Phân Rã (6 Tiêu Chí)</label>
                    <button 
                        onClick={() => localPlan && onUpdatePlan(localPlan)}
                        disabled={isUpdatingPlan}
                        className="text-xs bg-blue-600 hover:bg-blue-500 text-white px-3 py-1 rounded flex items-center gap-1 transition-colors disabled:opacity-50"
                    >
                        {isUpdatingPlan ? (
                             <svg className="animate-spin h-3 w-3 text-white" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                                <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                                <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                             </svg>
                        ) : (
                            <svg xmlns="http://www.w3.org/2000/svg" className="h-3 w-3" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" />
                            </svg>
                        )}
                        Cập nhật Prompt từ Kế hoạch
                    </button>
                </div>
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-3">
                   {criteriaList.map((item) => (
                       <div key={item.key} className="bg-slate-900/80 p-3 rounded border border-slate-700 focus-within:border-blue-500 transition-colors flex flex-col h-full">
                           <h4 className="text-[10px] text-blue-300 font-bold uppercase mb-1 flex items-center gap-1">
                               {item.label}
                               <svg xmlns="http://www.w3.org/2000/svg" className="h-3 w-3 text-slate-500" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                                   <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15.232 5.232l3.536 3.536m-2.036-5.036a2.5 2.5 0 113.536 3.536L6.5 21.036H3v-3.572L16.732 3.732z" />
                               </svg>
                           </h4>
                           <textarea
                               value={localPlan[item.key] || ''}
                               onChange={(e) => handlePlanChange(item.key, e.target.value)}
                               className="w-full bg-transparent text-slate-300 text-xs leading-relaxed outline-none resize-none flex-grow min-h-[60px] border-b border-transparent focus:border-blue-500/50 pb-1"
                           />
                       </div>
                   ))}
                </div>
             </div>

             {/* 1.5 NEW LAYOUT EDITOR */}
             {localLayout && (
                 <div className="mt-2">
                     <LayoutEditor 
                        layout={localLayout}
                        onLayoutChange={(updated) => setLocalLayout(updated)}
                        onConfirm={handleLayoutConfirm}
                     />
                 </div>
             )}

             {/* 1.3 Editable Prompt */}
             <div>
                <label className="text-xs font-semibold text-slate-400 uppercase mb-2 block flex justify-between">
                    <span>2. Prompt Cuối Cùng (Tiếng Anh - Tự động tạo từ Kế hoạch)</span>
                    <span className="text-[10px] text-slate-500 lowercase font-normal">Có thể chỉnh sửa thủ công</span>
                </label>
                <textarea 
                    value={editablePrompt}
                    onChange={(e) => setEditablePrompt(e.target.value)}
                    className="w-full bg-slate-900 border border-slate-700 rounded-lg p-3 text-xs text-slate-300 focus:border-blue-500 outline-none font-mono leading-relaxed"
                    rows={3}
                />
             </div>

             {/* Action Button: Generate (Only show if no images yet) */}
             {!imageResult.loading && imageResult.imageUrls.length === 0 && (
                 <button
                    onClick={() => handleGenerateClick(false)}
                    className="w-full py-3 bg-gradient-to-r from-emerald-600 to-teal-600 hover:from-emerald-500 hover:to-teal-500 rounded-lg text-white font-bold shadow-lg shadow-emerald-900/20 transition-all transform hover:scale-[1.01] flex items-center justify-center gap-2"
                 >
                    <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M14.752 11.168l-3.197-2.132A1 1 0 0010 9.87v4.263a1 1 0 001.555.832l3.197-2.132a1 1 0 000-1.664z" />
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 12a9 9 0 11-18 0 9 9 0 0118 0z" />
                    </svg>
                    Tiến Hành Tạo Thiết Kế
                 </button>
             )}
           </div>
        </div>
      )}

      {/* 2. Image Results Grid */}
      {imageResult.imageUrls.length > 0 && (
          <div className="flex-grow flex flex-col gap-4 animate-fade-in-up">
            <div className="flex items-center justify-between">
                <h3 className="text-white font-bold text-lg flex items-center gap-2">
                    <span className="w-2 h-6 bg-purple-500 rounded-sm"></span>
                    Kết Quả Thiết Kế
                </h3>
            </div>

            {/* The Grid */}
            <div className={`grid gap-4 ${imageResult.imageUrls.length === 1 ? 'grid-cols-1' : 'grid-cols-2 md:grid-cols-3'}`}>
                {imageResult.imageUrls.map((url, idx) => (
                <div 
                    key={idx} 
                    className={`group relative rounded-xl overflow-hidden border-2 transition-all duration-300 cursor-pointer h-auto aspect-auto bg-slate-900 ${
                    selectedImage === url ? 'border-emerald-500 ring-2 ring-emerald-500/30' : 'border-slate-700 hover:border-slate-500'
                    }`}
                    onClick={(e) => { e.stopPropagation(); setSelectedImage(selectedImage === url ? null : url); }}
                >
                    {/* Thumbnail Image */}
                    <img src={url} alt={`Option ${idx + 1}`} className="w-full h-full object-contain" />

                    {/* Overlay Controls */}
                    <div className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center gap-4">
                    <button 
                        onClick={(e) => { e.stopPropagation(); setLightboxImage(url); }}
                        className="bg-slate-800/80 p-2 rounded-full text-white hover:bg-blue-600 transition-colors"
                        title="Xem lớn"
                    >
                        <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0zM10 7v3m0 0v3m0-3h3m-3 0H7" />
                        </svg>
                    </button>

                    <span className="text-white font-medium text-sm">Chọn để Sửa/Tách</span>
                    </div>

                    {/* Always Visible Selection Indicator */}
                    {selectedImage === url && (
                    <div className="absolute top-2 left-2 bg-emerald-500 text-white p-1 rounded-full shadow-lg">
                        <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M5 13l4 4L19 7" />
                        </svg>
                    </div>
                    )}
                </div>
                ))}
            </div>

            {/* "More Ideas" Button Area - Located BELOW Results */}
            <div className="flex justify-center mt-2">
                 {imageResult.loading ? (
                    <div className="flex items-center gap-2 px-6 py-2 bg-slate-800 rounded-full border border-slate-700 animate-pulse">
                         <div className="w-4 h-4 border-2 border-purple-500 border-t-transparent rounded-full animate-spin"></div>
                         <span className="text-xs text-purple-400 font-medium">Đang vẽ thêm ý tưởng mới...</span>
                    </div>
                 ) : (
                    <button
                        onClick={() => handleGenerateClick(true)}
                        className="bg-slate-800 hover:bg-slate-700 text-white px-8 py-3 rounded-full flex items-center gap-2 transition-all border border-slate-600 hover:border-emerald-500 shadow-lg group"
                    >
                        <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5 text-emerald-400 group-hover:rotate-180 transition-transform duration-500" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                           <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" />
                        </svg>
                        <span className="font-medium">Thêm Ý Tưởng Khác</span>
                    </button>
                 )}
            </div>
          </div>
      )}

      {/* Initial Loading State (Only if no images exist yet) */}
      {imageResult.loading && imageResult.imageUrls.length === 0 && (
        <div className="bg-slate-900/50 rounded-2xl border border-slate-700 h-96 flex flex-col items-center justify-center animate-pulse">
            <div className="inline-block w-12 h-12 border-4 border-purple-500 border-t-transparent rounded-full animate-spin mb-4"></div>
            <p className="text-slate-400 text-sm">Đang hiện thực hóa ý tưởng...</p>
        </div>
      )}

      {/* 3. Action Panel (Appears when an image is selected) */}
      {selectedImage && !imageResult.loading && (
        <div className="bg-slate-800 border border-slate-700 rounded-xl p-4 sticky bottom-0 z-10 shadow-2xl animate-fade-in-up">
           {/* ... (Refine buttons same as before) ... */}
           <div className="flex items-center justify-between mb-4">
             <h3 className="text-white font-semibold flex items-center gap-2">
               <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5 text-emerald-400" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 12l2 2 4-4m6 2a9 9 0 11-18 0 9 9 0 0118 0z" />
               </svg>
               Đã chọn sản phẩm
             </h3>
             <a 
               href={selectedImage} 
               download="selected-design.png"
               className="text-xs bg-slate-700 hover:bg-slate-600 text-white px-3 py-1.5 rounded flex items-center gap-1 transition-colors"
             >
               <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" />
               </svg>
               Tải Về
             </a>
           </div>

           <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <div className={`border rounded-lg p-3 transition-colors ${isRefiningPanelOpen ? 'border-purple-500 bg-purple-900/20' : 'border-slate-600 bg-slate-900'}`}>
                 <button 
                   onClick={() => setIsRefiningPanelOpen(!isRefiningPanelOpen)}
                   className="w-full text-left text-sm font-medium text-white flex items-center justify-between mb-2"
                 >
                   <span className="flex items-center gap-2">
                     <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4 text-purple-400" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M11 5H6a2 2 0 00-2 2v11a2 2 0 002 2h11a2 2 0 002-2v-5m-1.414-9.414a2 2 0 112.828 2.828L11.828 15H9v-2.828l8.586-8.586z" />
                     </svg>
                     Hiệu Chỉnh (Refine)
                   </span>
                   <span className="text-xs text-slate-400">{isRefiningPanelOpen ? '▲' : '▼'}</span>
                 </button>

                 {isRefiningPanelOpen && (
                   <div className="mt-2 animate-fade-in">
                      <textarea
                        className="w-full bg-slate-800 border border-slate-600 rounded p-2 text-sm text-white focus:border-purple-500 outline-none resize-none mb-2"
                        placeholder="Nhập yêu cầu sửa đổi (vd: đổi màu nền sang xanh, làm chữ to hơn...)"
                        rows={2}
                        value={refineInstruction}
                        onChange={(e) => setRefineInstruction(e.target.value)}
                      />
                      <button
                        onClick={handleRefineSubmit}
                        disabled={!refineInstruction || refinementResult.loading}
                        className="w-full bg-purple-600 hover:bg-purple-500 disabled:opacity-50 disabled:cursor-not-allowed text-white text-xs py-2 rounded font-medium transition-colors"
                      >
                        {refinementResult.loading ? 'Đang Xử Lý...' : 'Thực Hiện Hiệu Chỉnh'}
                      </button>
                   </div>
                 )}
              </div>

              {/* Separation Buttons Grid */}
              <div className="flex flex-col gap-2">
                  <button
                    onClick={() => onSeparateLayout(selectedImage, 'full')}
                    disabled={separatedAssets.loading}
                    className="flex-1 bg-slate-900 border border-slate-600 hover:border-emerald-500 hover:bg-emerald-900/10 rounded-lg p-2 flex items-center justify-center gap-2 transition-all group disabled:opacity-50"
                  >
                     {separatedAssets.loading ? (
                        <div className="w-4 h-4 border-2 border-emerald-500 border-t-transparent rounded-full animate-spin"></div>
                     ) : (
                        <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4 text-emerald-400" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                           <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8 16H6a2 2 0 01-2-2V6a2 2 0 012-2h8a2 2 0 012 2v2m-6 12h8a2 2 0 002-2v-8a2 2 0 00-2-2h-8a2 2 0 00-2 2v8a2 2 0 002 2z" />
                        </svg>
                     )}
                     <span className="text-xs font-medium text-white">Tách Lớp Chi Tiết (Full)</span>
                  </button>

                  <button
                    onClick={() => onSeparateLayout(selectedImage, 'background')}
                    disabled={separatedAssets.loading}
                    className="flex-1 bg-slate-900 border border-slate-600 hover:border-blue-500 hover:bg-blue-900/10 rounded-lg p-2 flex items-center justify-center gap-2 transition-all group disabled:opacity-50"
                  >
                     {separatedAssets.loading ? (
                        <div className="w-4 h-4 border-2 border-blue-500 border-t-transparent rounded-full animate-spin"></div>
                     ) : (
                        <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4 text-blue-400" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                           <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" />
                        </svg>
                     )}
                     <span className="text-xs font-medium text-white">Chỉ Lấy Nền (Clean BG)</span>
                  </button>
              </div>
           </div>

           {/* REFINEMENT VIEW */}
           {(refinementResult.loading || refinementResult.imageUrls.length > 0) && (
               <div className="mt-4 pt-4 border-t border-slate-700 animate-fade-in">
                  <div className="grid grid-cols-2 gap-4 items-center bg-slate-900/50 p-3 rounded-lg border border-slate-700">
                      <div className="relative group">
                          <span className="absolute top-2 left-2 bg-slate-800/80 text-xs text-white px-2 py-1 rounded backdrop-blur-sm z-10 border border-slate-600">Ảnh Gốc</span>
                          <img src={selectedImage} alt="Original" className="w-full h-48 object-contain rounded-lg border border-slate-600" onClick={() => setLightboxImage(selectedImage)} />
                      </div>
                      <div className="relative group">
                          <span className="absolute top-2 left-2 bg-purple-600/90 text-xs text-white px-2 py-1 rounded backdrop-blur-sm z-10 border border-purple-400 shadow-lg shadow-purple-500/20">Kết Quả Mới</span>
                          {refinementResult.loading ? (
                             <div className="w-full h-48 bg-slate-800 rounded-lg flex flex-col items-center justify-center border border-slate-700 border-dashed animate-pulse">
                                 <div className="w-8 h-8 border-2 border-purple-500 border-t-transparent rounded-full animate-spin mb-2"></div>
                                 <span className="text-xs text-slate-500">Đang vẽ lại...</span>
                             </div>
                          ) : (
                             <img src={refinementResult.imageUrls[0]} alt="Refined" className="w-full h-48 object-contain rounded-lg border-2 border-purple-500 shadow-lg shadow-purple-500/10 cursor-pointer" onClick={() => setLightboxImage(refinementResult.imageUrls[0])} />
                          )}
                      </div>
                  </div>
               </div>
           )}
        </div>
      )}

      {/* 4. Separated Assets Display */}
      {hasSeparation && (
        <div className="mt-4 pt-4 border-t border-slate-700 animate-fade-in-up">
            <h3 className="text-lg font-bold text-white mb-4 flex items-center gap-2">
                <span className="w-2 h-6 bg-emerald-500 rounded-sm"></span>
                Kết Quả Tách Lớp & Nguyên Liệu (4K)
            </h3>

            <div className="space-y-6">

                {/* 1. Nền & Ánh Sáng */}
                <div>
                    <h4 className="text-xs text-slate-400 font-bold uppercase mb-2">1. Nền & Ánh Sáng</h4>
                    <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                         <AssetCard 
                            title="Background" 
                            image={separatedAssets.background} 
                            loading={separatedAssets.loading} 
                            onZoom={() => separatedAssets.background && setLightboxImage(separatedAssets.background)}
                        />
                         <AssetCard 
                            title="Lighting / Atmosphere" 
                            image={separatedAssets.lighting} 
                            loading={separatedAssets.loading} 
                            onZoom={() => separatedAssets.lighting && setLightboxImage(separatedAssets.lighting)}
                        />
                    </div>
                </div>

                {/* 2. Chủ Thể (Subjects) */}
                <div>
                    <h4 className="text-xs text-slate-400 font-bold uppercase mb-2">2. Chủ Thể (Isolated Subjects)</h4>
                    <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                        {separatedAssets.loading && separatedAssets.subjects.length === 0 ? (
                             <>
                                <AssetCard title="Main Hero Subject" image={null} loading={true} />
                                <AssetCard title="Secondary Subject" image={null} loading={true} />
                             </>
                        ) : (
                             separatedAssets.subjects.map((img, idx) => (
                                <AssetCard 
                                    key={`sub-${idx}`}
                                    title={idx === 0 ? "Main Subject (Hero)" : "Secondary / Angle"} 
                                    image={img} 
                                    loading={false} 
                                    isWhiteBg
                                    onZoom={() => setLightboxImage(img)}
                                />
                             ))
                        )}
                        {/* If empty but loaded */}
                        {!separatedAssets.loading && separatedAssets.subjects.length === 0 && <span className="text-xs text-slate-600 italic">Không có chủ thể tách biệt.</span>}
                    </div>
                </div>

                {/* 3. Trang Trí (Decor) */}
                <div>
                    <h4 className="text-xs text-slate-400 font-bold uppercase mb-2">3. Chi Tiết Trang Trí (Decor Elements)</h4>
                    <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                        {separatedAssets.loading && separatedAssets.decor.length === 0 ? (
                             <>
                                <AssetCard title="Main Props / Podium" image={null} loading={true} />
                                <AssetCard title="Particles / Effects" image={null} loading={true} />
                             </>
                        ) : (
                             separatedAssets.decor.map((img, idx) => (
                                <AssetCard 
                                    key={`decor-${idx}`}
                                    title={idx === 0 ? "Large Props / Podium" : "Small Particles / Effects"} 
                                    image={img} 
                                    loading={false} 
                                    isWhiteBg
                                    onZoom={() => setLightboxImage(img)}
                                />
                             ))
                        )}
                        {!separatedAssets.loading && separatedAssets.decor.length === 0 && <span className="text-xs text-slate-600 italic">Không có chi tiết trang trí.</span>}
                    </div>
                </div>

                {/* 4. Text */}
                <div>
                    <h4 className="text-xs text-slate-400 font-bold uppercase mb-2">4. Typography</h4>
                    <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                         <AssetCard 
                            title="Text Layer" 
                            image={separatedAssets.textLayer} 
                            loading={separatedAssets.loading} 
                            isWhiteBg
                            onZoom={() => separatedAssets.textLayer && setLightboxImage(separatedAssets.textLayer)}
                        />
                    </div>
                </div>

            </div>

            {separatedAssets.error && (
                <div className="mt-4 p-3 bg-red-900/30 border border-red-500/30 rounded-lg text-red-200 text-sm">
                    Lỗi khi tách bố cục: {separatedAssets.error}
                </div>
            )}
        </div>
      )}
    </div>
  );
};

export default ResultDisplay;

import { GoogleGenAI, Type, Schema } from "@google/genai";
import { ArtDirectionRequest, ArtDirectionResponse, ProductImageMode, VisualStyle, ColorMode, DesignPlan, LayoutSuggestion } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const SYSTEM_INSTRUCTION = `
You are a professional "AI Art Director" and "Prompt Engineer".
Your task is to **DECOMPOSE** the user request into a specific 6-point design plan, **GENERATE A SPATIAL LAYOUT**, and then synthesize a highly detailed English prompt.

### 6-POINT DECOMPOSITION CRITERIA (Must be in VIETNAMESE for the 'designPlan'):
1.  **Subject & Secondary Content (Chủ thể):** 
    *   **PRIORITY RULE:** If the user provides **ASSET IMAGES** (Product Images), these are the **HERO**. The Reference Image's subject is only a placeholder for pose/angle.
    *   Define the main hero image and how Secondary Text is integrated.
2.  **Style & Context (Bối cảnh & Phong cách):** Define the environment, artistic style (Reference Image attributes go here), and overall mood.
3.  **Composition & Camera (Bố cục):** Define the layout structure, camera angle, and focal length.
4.  **Color & Lighting (Màu sắc & Ánh sáng):** 
    *   If **Brand Logo** is provided, analyze and list its specific colors.
    *   Define the palette, lighting type, and contrast.
5.  **Decor Elements (Chi tiết trang trí):** Define specific graphical elements, shapes, particles, or props.
6.  **Typography (Chữ):** 
    *   **CRITICAL FOR REFERENCE IMAGES:** If 'Typography' is selected on a Reference, you must describe BOTH the **Font Style** (Weight, Serif/Sans) AND the **TEXT LAYOUT** (Kerning, Leading, Stacking, Rotation, Hierarchy). 
    *   Explain how the User's "Main Headline" will physically match this arrangement.

### SPATIAL LAYOUT GENERATION (JSON):
You must also generate a 'layout_suggestion' containing bounding boxes (0-100 scale) for key elements.
- **Elements:** Include boxes for 'Main Subject', 'Headline Text', 'Secondary Text', 'Logo', and key 'Decor'.
- **Canvas Ratio:** Ensure the layout coordinates fit the requested aspect ratio.

### INPUT HANDLING RULES (CRITICAL)
*   **REFERENCE IMAGE LOGIC:**
    The user may provide up to 3 Reference Images. Each image has specific **Attributes** to copy.

    *   **If Image X has 'Subject' OR 'Composition' AND User has 'Asset Images':**
        -> **SWAP OPERATION:** Use the layout/pose/angle from Image X, but **REPLACE** the subject in Image X with the User's provided Asset Image.
        -> *Example:* "Place the User's [Asset Product] in the exact same position and angle as the [Reference Subject]."

    *   **If Image X has 'Typography' -> DEEP COPY MODE:**
        1.  Analyze Font Family (Serif/Sans/Script).
        2.  Analyze **TEXT ARRANGEMENT** (Is it stacked? Arched? Overlapping the subject? Huge & Bold?).
        3.  **ACTION:** "Format the text '${'{mainHeadline}'}' to visually mirror the typesetting and layout of the text in Reference Image X."

*   **COLOR/LIGHTING CONFLICT RULE:**
    *   **Brand Logo Mode overrides Reference Colors:** If Color Mode IS 'Brand Logo', ignore Reference Colors. Use Logo colors, but keep Reference Lighting/Contrast.

### OUTPUT FORMAT (JSON)
Return a JSON object with:
1.  "designPlan": Object containing the 6 Vietnamese strings defined above.
2.  "layout_suggestion": JSON object with 'canvas_ratio' and 'elements' array (x, y, width, height, color, name).
3.  "analysis": A short creative summary in Vietnamese.
4.  "final_prompt": The optimized English prompt derived from the plan.
5.  "recommendedAspectRatio": The best ratio.
`;

const RESPONSE_SCHEMA: Schema = {
  type: Type.OBJECT,
  properties: {
    designPlan: {
      type: Type.OBJECT,
      properties: {
        subject: { type: Type.STRING, description: "Analysis of Subject & Content in Vietnamese" },
        styleContext: { type: Type.STRING, description: "Analysis of Style & Context in Vietnamese" },
        composition: { type: Type.STRING, description: "Analysis of Composition & Camera in Vietnamese" },
        colorLighting: { type: Type.STRING, description: "Analysis of Color & Lighting in Vietnamese" },
        decorElements: { type: Type.STRING, description: "Analysis of Decor Elements in Vietnamese" },
        typography: { type: Type.STRING, description: "Analysis of Typography in Vietnamese" }
      },
      required: ["subject", "styleContext", "composition", "colorLighting", "decorElements", "typography"]
    },
    layout_suggestion: {
      type: Type.OBJECT,
      properties: {
        canvas_ratio: { type: Type.STRING, description: "e.g., 9:16 or 1:1" },
        elements: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              id: { type: Type.STRING },
              name: { type: Type.STRING },
              type: { type: Type.STRING, enum: ["subject", "text", "decor", "logo"] },
              color: { type: Type.STRING, description: "Hex color code for UI visualization" },
              rect: {
                type: Type.OBJECT,
                properties: {
                  x: { type: Type.NUMBER, description: "Percentage 0-100" },
                  y: { type: Type.NUMBER, description: "Percentage 0-100" },
                  width: { type: Type.NUMBER, description: "Percentage 0-100" },
                  height: { type: Type.NUMBER, description: "Percentage 0-100" }
                },
                required: ["x", "y", "width", "height"]
              }
            },
            required: ["name", "type", "color", "rect"]
          }
        }
      },
      required: ["canvas_ratio", "elements"]
    },
    analysis: {
      type: Type.STRING,
      description: "Brief summary in Vietnamese.",
    },
    final_prompt: {
      type: Type.STRING,
      description: "The detailed English prompt.",
    },
    recommendedAspectRatio: {
      type: Type.STRING,
      enum: ["1:1", "3:4", "4:3", "9:16", "16:9"],
    },
  },
  required: ["designPlan", "layout_suggestion", "analysis", "final_prompt", "recommendedAspectRatio"],
};

export const generateArtDirection = async (request: ArtDirectionRequest): Promise<ArtDirectionResponse> => {
  try {
    const parts: any[] = [];

    // Logic for Conflict: Brand Logo Mode vs Reference 'Color'
    const isBrandLogoMode = request.colorMode === ColorMode.BRAND_LOGO;
    const hasUserAssets = request.assetImages.length > 0;

    // Check if ANY reference image has 'Color' selected
    const anyRefHasColor = request.referenceImages.some(img => img.attributes.includes('Color'));

    let colorInstruction = "";

    // Construct Reference Instructions
    let allRefInstructions = "";

    request.referenceImages.forEach((refImg, index) => {
        const i = index + 1;
        let activeAttributes = [...refImg.attributes];

        let specificNote = "";

        // Handle Typography Specifics
        if (activeAttributes.includes('Typography')) {
            specificNote += `\n   - **TYPOGRAPHY & LAYOUT INSTRUCTION:** 
             1. Analyze the font style (Weight, Family) in Ref Image ${i}.
             2. **CRITICAL:** Analyze the **SPATIAL ARRANGEMENT** (Alignment, Line Spacing, Overlap) of the text in Ref Image ${i}.
             3. **ACTION:** Render the Main Headline "${request.mainHeadline}" to EXACTLY MIMIC this visual hierarchy and layout.`;
        }

        // Handle Subject/Composition with User Assets
        if (hasUserAssets && (activeAttributes.includes('Subject') || activeAttributes.includes('Composition'))) {
             specificNote += `\n   - **ASSET INTEGRATION (CRITICAL):** The User provided a PRODUCT IMAGE (Asset). 
             **DO NOT** generate the subject from Ref Image ${i}. 
             INSTEAD, take the **Composition/Angle/Pose** from Ref Image ${i} and **INSERT** the User's Asset into that spot.`;
        }

        // Handle Color Conflict
        if (isBrandLogoMode && activeAttributes.includes('Color')) {
             // Conflict logic: Remove Color from the "Copy" list for this image context, replace with Lighting note
             activeAttributes = activeAttributes.filter(attr => attr !== 'Color');
             specificNote += `\n   - **LIGHTING ONLY:** 'Color' attribute was checked, BUT mode is 'Brand Logo'. -> Extract **LIGHTING & SHADOWS ONLY** from Ref Image ${i}. **DO NOT** use its Colors. Use Brand Logo Colors instead.`;
        }

        if (activeAttributes.length > 0 || specificNote) {
            allRefInstructions += `
            -- REFERENCE IMAGE ${i} --
            Attributes to Copy: [${activeAttributes.join(', ')}]
            ${specificNote}
            `;
        }
    });

    if (isBrandLogoMode) {
        colorInstruction = "STRICTLY USE COLORS EXTRACTED FROM THE PROVIDED BRAND LOGO IMAGE.";
    } else {
        colorInstruction = request.colorMode === 'Custom' ? `Custom Palette: ${request.customColors.join(', ')}` : 'Auto/AI Decision';
    }

    let styleInstruction = request.visualStyle === VisualStyle.FOLLOW_REF 
        ? "STRICTLY MIMIC the Reference Image style(s)." 
        : request.visualStyle;

    let promptText = `
      -- CORE DATA --
      Product Type: ${request.productType}
      Dimensions: ${request.width}cm x ${request.height}cm

      -- TEXT CONTENT --
      Main Headline: "${request.mainHeadline}"
      Secondary Text: "${request.secondaryText}"

      -- BRANDING & ASSETS --
      Has Brand Logo: ${request.logoImage ? "YES" : "NO"}
      Has User Product Assets: ${hasUserAssets ? "YES (PRIORITY HERO)" : "NO"}
      Color Mode: ${request.colorMode}
      Color Instruction: ${colorInstruction}

      -- USER REQUIREMENTS --
      Layout/Description: "${request.layoutRequirements}"
      Font Preferences: "${request.fontPreferences}"
      Visual Style: ${styleInstruction}
      Product Mode: ${request.productImageMode}

      -- REFERENCE INSTRUCTIONS (CRITICAL) --
      ${allRefInstructions}
    `;

    parts.push({ text: promptText });

    // Attach Images
    if (request.logoImage) parts.push({ inlineData: { mimeType: "image/png", data: request.logoImage.split(',')[1] } });
    request.assetImages.forEach(img => parts.push({ inlineData: { mimeType: "image/png", data: img.split(',')[1] } }));
    if (request.mainHeadlineImage) parts.push({ inlineData: { mimeType: "image/png", data: request.mainHeadlineImage.split(',')[1] } });

    // Attach Reference Images with Labels
    request.referenceImages.forEach((refImg, index) => {
        parts.push({ text: `REFERENCE IMAGE ${index + 1}:`});
        parts.push({ inlineData: { mimeType: "image/png", data: refImg.image.split(',')[1] } });
    });

    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: { parts },
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        responseMimeType: "application/json",
        responseSchema: RESPONSE_SCHEMA,
      },
    });

    const text = response.text;
    if (!text) throw new Error("No response from AI Director");

    // Post-process to ensure IDs exist for layout elements
    const result = JSON.parse(text) as ArtDirectionResponse;
    if (result.layout_suggestion && result.layout_suggestion.elements) {
        result.layout_suggestion.elements = result.layout_suggestion.elements.map((el, idx) => ({
            ...el,
            id: el.id || `el-${Date.now()}-${idx}`
        }));
    }

    return result;
  } catch (error) {
    console.error("Error generating art direction:", error);
    throw error;
  }
};

// Helper to convert the Visual Layout back into Text for the Prompt
export const convertLayoutToPrompt = (layout: LayoutSuggestion): string => {
    if (!layout || !layout.elements || layout.elements.length === 0) return "";

    let promptAddition = "\n\n-- FORCED COMPOSITION LAYOUT (STRICT) --\n";
    promptAddition += "Place the following elements exactly as described:\n";

    layout.elements.forEach(el => {
        // Convert percentages to approximate placement words for better understanding
        const x = el.rect.x;
        const y = el.rect.y;
        const w = el.rect.width;
        const h = el.rect.height;

        promptAddition += `- Element "${el.name}" (${el.type}): Position at X=${x}%, Y=${y}%. Size: Width=${w}%, Height=${h}% of the canvas.\n`;
    });

    return promptAddition;
};

// Function to Update/Refine the Plan based on user manual edits
export const regeneratePromptFromPlan = async (
    updatedPlan: DesignPlan,
    originalRequest: ArtDirectionRequest,
    currentAspectRatio: string
): Promise<ArtDirectionResponse> => {
    try {
        const prompt = `
            You are the AI Art Director. The user has MANUALLY EDITED the "Design Plan" (in Vietnamese).

            **YOUR TASK:**
            1.  Read the **UPDATED DESIGN PLAN** below.
            2.  Re-synthesize the "final_prompt" (English) to STRICTLY reflect these new Vietnamese details.
            3.  Ensure the English prompt still incorporates instructions for the provided images (Logo, Assets, References) mentioned in the original request context.
            4.  Regenerate the 'layout_suggestion' to match the updated plan.

            **UPDATED DESIGN PLAN (VIETNAMESE):**
            ${JSON.stringify(updatedPlan, null, 2)}

            **ORIGINAL CONTEXT:**
            Product: ${originalRequest.productType}
            Headline: ${originalRequest.mainHeadline}

            **OUTPUT:**
            Return the full JSON (ArtDirectionResponse) with the 'designPlan' (same as provided), updated 'analysis', new 'layout_suggestion', and the NEW 'final_prompt'.
            Keep 'recommendedAspectRatio' as: ${currentAspectRatio}.
        `;

        const response = await ai.models.generateContent({
            model: "gemini-3-flash-preview",
            contents: { parts: [{ text: prompt }] },
            config: {
                systemInstruction: SYSTEM_INSTRUCTION,
                responseMimeType: "application/json",
                responseSchema: RESPONSE_SCHEMA,
            },
        });

        const text = response.text;
        if (!text) throw new Error("No response from AI update");

        // Post-process IDs
        const result = JSON.parse(text) as ArtDirectionResponse;
        if (result.layout_suggestion && result.layout_suggestion.elements) {
            result.layout_suggestion.elements = result.layout_suggestion.elements.map((el, idx) => ({
                ...el,
                id: el.id || `el-update-${Date.now()}-${idx}`
            }));
        }

        return result;

    } catch (error) {
        console.error("Error regenerating prompt from plan:", error);
        throw error;
    }
};

export const generateDesignImage = async (
  prompt: string, 
  aspectRatio: string, 
  batchSize: number, 
  imageSize: string,
  assetImages: string[] = [],
  logoImage: string | null = null
): Promise<string[]> => {
  try {
    const modelName = "gemini-3-pro-image-preview";
    const parts: any[] = [{ text: prompt }];

    if (logoImage) {
      parts.push({ text: " REFERENCE_IMAGE_LOGO (Incorporate this logo unchanged): " });
      parts.push({ inlineData: { mimeType: "image/png", data: logoImage.split(',')[1] } });
    }

    if (assetImages.length > 0) {
       parts.push({ text: " REFERENCE_IMAGE_PRODUCT (Main Subject - Isolate and Place): " });
       assetImages.forEach(img => {
          parts.push({ inlineData: { mimeType: "image/png", data: img.split(',')[1] } });
       });
    }

    const promises = Array.from({ length: batchSize }).map(async () => {
      const response = await ai.models.generateContent({
        model: modelName,
        contents: { parts },
        config: { imageConfig: { aspectRatio: aspectRatio, imageSize: imageSize } },
      });

      for (const part of response.candidates?.[0]?.content?.parts || []) {
        if (part.inlineData) return `data:image/png;base64,${part.inlineData.data}`;
      }
      return null;
    });

    const results = await Promise.all(promises);
    return results.filter((url): url is string => url !== null);
  } catch (error) {
    console.error("Error generating image:", error);
    throw error;
  }
};

export const refineDesignImage = async (sourceImageBase64: string, instruction: string, aspectRatio: string, imageSize: string): Promise<string[]> => {
  try {
    const modelName = "gemini-3-pro-image-preview";
    const prompt = `Perform the following edit: ${instruction}. Keep layout/elements consistent. High fidelity.`;

    const response = await ai.models.generateContent({
      model: modelName,
      contents: {
        parts: [
          { text: prompt },
          { inlineData: { mimeType: "image/png", data: sourceImageBase64.split(',')[1] } }
        ]
      },
      config: { imageConfig: { aspectRatio, imageSize } },
    });

    const urls: string[] = [];
    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData) urls.push(`data:image/png;base64,${part.inlineData.data}`);
    }
    return urls;
  } catch (error) {
    console.error("Error refining image:", error);
    throw error;
  }
};

export const separateDesignComponents = async (
    originalPrompt: string, 
    aspectRatio: string, 
    _userImageSize: string, 
    referenceImageBase64?: string,
    mode: 'full' | 'background' = 'full'
): Promise<{ background: string | null, textLayer: string | null, subjects: string[], decor: string[], lighting: string | null }> => {
  const modelName = "gemini-3-pro-image-preview";
  const MAX_QUALITY_SIZE = "4K"; 

  const buildParts = (taskPrompt: string) => {
    const parts: any[] = [{ text: taskPrompt }];
    if (referenceImageBase64) parts.push({ inlineData: { mimeType: "image/png", data: referenceImageBase64.split(',')[1] } });
    return parts;
  };

  const extractImage = (response: any) => {
       for (const part of response.candidates?.[0]?.content?.parts || []) {
        if (part.inlineData) return `data:image/png;base64,${part.inlineData.data}`;
      }
      return null;
  };

  try {
      // 1. Background / Clean Version logic
      // Updated to strictly PRESERVE subjects/decor/lighting, only removing text/logos
      const bgInstruction = mode === 'background' 
         ? `Based on reference: GENERATE A HIGH-FIDELITY COPY of the image but REMOVE ALL TEXT, HEADLINES, and LOGOS.
            CRITICAL: PRESERVE the Main Subject/Product, Lighting, Decor, and Composition EXACTLY as they are. 
            Do NOT remove the main subject or foreground elements. Only remove typographic overlays and branding symbols.`
         : `Based on reference: GENERATE BACKGROUND ONLY. Remove text, products, foreground elements. Keep texture, lighting environment. High Resolution.`;

      const bgRes = await ai.models.generateContent({ 
          model: modelName, 
          contents: { parts: buildParts(bgInstruction) }, 
          config: { imageConfig: { aspectRatio, imageSize: MAX_QUALITY_SIZE } } 
      });

      const background = extractImage(bgRes);

      // If Background Only Mode (Clean Version), return immediately
      if (mode === 'background') {
          return {
              background: background,
              textLayer: null,
              subjects: [],
              decor: [],
              lighting: null
          };
      }

      // 2. Full Mode Separation
      const textPrompt = `Based on reference: GENERATE TYPOGRAPHY LAYER ONLY on WHITE background. Replicate font/layout exactly. High Resolution.`;
      const subjectMainPrompt = `Based on reference: GENERATE & ISOLATE THE SINGLE MAIN HERO SUBJECT (Product/Person) on WHITE background. High precision. No extra decor.`;
      const subjectSecondaryPrompt = `Based on reference: GENERATE & ISOLATE SECONDARY SUBJECTS (or alternate angle of hero) on WHITE background. High precision.`;
      const decorMainPrompt = `Based on reference: GENERATE & ISOLATE MAIN 3D PROPS (Podiums, Stands, Large Geometric Shapes) on WHITE background. No small particles.`;
      const decorParticlesPrompt = `Based on reference: GENERATE & ISOLATE DECORATIVE PARTICLES (Leaves, Confetti, Abstract Floaters) scattered on WHITE background.`;
      const lightingPrompt = `Based on reference: GENERATE LIGHTING & ATMOSPHERE LAYER (Light beams, Lens flares, Fog, Shadows) on BLACK background (Screen Mode). High Resolution.`;

      const [textRes, subMainRes, subSecRes, decorMainRes, decorPartRes, lightRes] = await Promise.all([
        ai.models.generateContent({ model: modelName, contents: { parts: buildParts(textPrompt) }, config: { imageConfig: { aspectRatio, imageSize: MAX_QUALITY_SIZE } } }),
        ai.models.generateContent({ model: modelName, contents: { parts: buildParts(subjectMainPrompt) }, config: { imageConfig: { aspectRatio, imageSize: MAX_QUALITY_SIZE } } }),
        ai.models.generateContent({ model: modelName, contents: { parts: buildParts(subjectSecondaryPrompt) }, config: { imageConfig: { aspectRatio, imageSize: MAX_QUALITY_SIZE } } }),
        ai.models.generateContent({ model: modelName, contents: { parts: buildParts(decorMainPrompt) }, config: { imageConfig: { aspectRatio, imageSize: MAX_QUALITY_SIZE } } }),
        ai.models.generateContent({ model: modelName, contents: { parts: buildParts(decorParticlesPrompt) }, config: { imageConfig: { aspectRatio, imageSize: MAX_QUALITY_SIZE } } }),
        ai.models.generateContent({ model: modelName, contents: { parts: buildParts(lightingPrompt) }, config: { imageConfig: { aspectRatio, imageSize: MAX_QUALITY_SIZE } } })
      ]);

      const subjects = [];
      const s1 = extractImage(subMainRes);
      const s2 = extractImage(subSecRes);
      if (s1) subjects.push(s1);
      if (s2) subjects.push(s2);

      const decor = [];
      const d1 = extractImage(decorMainRes);
      const d2 = extractImage(decorPartRes);
      if (d1) decor.push(d1);
      if (d2) decor.push(d2);

      return { 
          background: background, 
          textLayer: extractImage(textRes), 
          subjects: subjects,
          decor: decor,
          lighting: extractImage(lightRes)
      };

  } catch (error) {
    console.error("Error separating components:", error);
    throw error;
  }
};

