import React, { useRef, useState, useEffect } from 'react';

interface SmartRemoverProps {
  imageUrl: string;
  onClose: () => void;
  onProcess: (maskBase64: string) => void;
  isProcessing: boolean;
}

interface DrawPath {
  x: number;
  y: number;
  size: number;
}

const SmartRemover: React.FC<SmartRemoverProps> = ({ imageUrl, onClose, onProcess, isProcessing }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const [isDrawing, setIsDrawing] = useState(false);
  const [brushSize, setBrushSize] = useState(30);
  const [paths, setPaths] = useState<DrawPath[][]>([]); // Array of strokes
  const [currentPath, setCurrentPath] = useState<DrawPath[]>([]);
  const [imageSize, setImageSize] = useState({ w: 0, h: 0 });

  // Initialize Canvas with Image
  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    const img = new Image();
    img.crossOrigin = "anonymous";
    img.src = imageUrl;
    img.onload = () => {
      canvas.width = img.naturalWidth;
      canvas.height = img.naturalHeight;
      setImageSize({ w: img.naturalWidth, h: img.naturalHeight });
      ctx.drawImage(img, 0, 0);
    };
  }, [imageUrl]);

  // Redraw function (draws image + red overlay paths)
  const redraw = () => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    // 1. Clear & Draw Original Image
    const img = new Image();
    img.crossOrigin = "anonymous";
    img.src = imageUrl;
    // Note: In a real optimized app, we wouldn't reload the image every frame, 
    // but for this specific scope it ensures the base is clean.
    // Better: clearRect and assume background is set or use a second canvas layer.
    // Simple approach:
    ctx.clearRect(0, 0, canvas.width, canvas.height);
    ctx.drawImage(img, 0, 0, canvas.width, canvas.height);

    // 2. Draw Red Mask Overlay
    ctx.lineCap = 'round';
    ctx.lineJoin = 'round';
    ctx.strokeStyle = 'rgba(255, 0, 0, 0.5)'; // Red, semi-transparent

    const allPaths = [...paths, currentPath];

    allPaths.forEach(path => {
      if (path.length < 1) return;
      ctx.beginPath();
      ctx.lineWidth = path[0].size;
      ctx.moveTo(path[0].x, path[0].y);
      for (let i = 1; i < path.length; i++) {
        // Handle varying brush sizes per stroke if needed, usually constant per stroke
        ctx.lineWidth = path[i].size; 
        ctx.lineTo(path[i].x, path[i].y);
      }
      ctx.stroke();
    });
  };

  // Trigger redraw whenever paths change
  useEffect(() => {
    redraw();
  }, [paths, currentPath]);

  const getCoordinates = (e: React.MouseEvent | React.TouchEvent) => {
    if (!canvasRef.current) return { x: 0, y: 0 };
    const rect = canvasRef.current.getBoundingClientRect();
    const scaleX = canvasRef.current.width / rect.width;
    const scaleY = canvasRef.current.height / rect.height;

    let clientX, clientY;
    if ('touches' in e) {
      clientX = e.touches[0].clientX;
      clientY = e.touches[0].clientY;
    } else {
      clientX = (e as React.MouseEvent).clientX;
      clientY = (e as React.MouseEvent).clientY;
    }

    return {
      x: (clientX - rect.left) * scaleX,
      y: (clientY - rect.top) * scaleY
    };
  };

  const startDrawing = (e: React.MouseEvent | React.TouchEvent) => {
    setIsDrawing(true);
    const coords = getCoordinates(e);
    setCurrentPath([{ x: coords.x, y: coords.y, size: brushSize }]);
  };

  const draw = (e: React.MouseEvent | React.TouchEvent) => {
    if (!isDrawing) return;
    const coords = getCoordinates(e);
    setCurrentPath(prev => [...prev, { x: coords.x, y: coords.y, size: brushSize }]);
  };

  const stopDrawing = () => {
    if (!isDrawing) return;
    setIsDrawing(false);
    if (currentPath.length > 0) {
      setPaths(prev => [...prev, currentPath]);
      setCurrentPath([]);
    }
  };

  const handleUndo = () => {
    setPaths(prev => prev.slice(0, -1));
  };

  const handleGenerateMaskAndProcess = () => {
    // Create a temporary canvas to generate the B/W mask
    const maskCanvas = document.createElement('canvas');
    maskCanvas.width = imageSize.w;
    maskCanvas.height = imageSize.h;
    const mCtx = maskCanvas.getContext('2d');
    if (!mCtx) return;

    // 1. Fill Black (Keep areas)
    mCtx.fillStyle = '#000000';
    mCtx.fillRect(0, 0, maskCanvas.width, maskCanvas.height);

    // 2. Draw White Strokes (Remove areas)
    mCtx.lineCap = 'round';
    mCtx.lineJoin = 'round';
    mCtx.strokeStyle = '#FFFFFF';

    paths.forEach(path => {
      if (path.length < 1) return;
      mCtx.beginPath();
      mCtx.lineWidth = path[0].size; // Use the size stored in the path
      mCtx.moveTo(path[0].x, path[0].y);
      for (let i = 1; i < path.length; i++) {
        mCtx.lineTo(path[i].x, path[i].y);
      }
      mCtx.stroke();
    });

    const maskBase64 = maskCanvas.toDataURL('image/png');
    onProcess(maskBase64);
  };

  return (
    <div className="fixed inset-0 z-50 bg-black/90 flex flex-col items-center justify-center p-4 backdrop-blur-md">
      {/* Header Controls */}
      <div className="w-full max-w-4xl flex items-center justify-between mb-4 bg-slate-800 p-3 rounded-lg border border-slate-700">
        <h3 className="text-white font-bold flex items-center gap-2">
          <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5 text-red-500" viewBox="0 0 20 20" fill="currentColor">
            <path fillRule="evenodd" d="M9 2a1 1 0 00-.894.553L7.382 4H4a1 1 0 000 2v10a2 2 0 002 2h8a2 2 0 002-2V6a1 1 0 100-2h-3.382l-.724-1.447A1 1 0 0011 2H9zM7 8a1 1 0 012 0v6a1 1 0 11-2 0V8zm5-1a1 1 0 00-1 1v6a1 1 0 102 0V8a1 1 0 00-1-1z" clipRule="evenodd" />
          </svg>
          Smart Object Remover
        </h3>

        <div className="flex items-center gap-4">
           {/* Brush Size Slider */}
           <div className="flex items-center gap-2">
              <span className="text-xs text-slate-400">Cọ: {brushSize}px</span>
              <input 
                type="range" min="5" max="100" 
                value={brushSize} 
                onChange={(e) => setBrushSize(parseInt(e.target.value))}
                className="w-24 h-2 bg-slate-600 rounded-lg appearance-none cursor-pointer accent-red-500"
              />
           </div>

           <button 
             onClick={handleUndo}
             className="p-2 bg-slate-700 hover:bg-slate-600 text-white rounded text-xs flex items-center gap-1 transition-colors"
             title="Hoàn tác (Undo)"
           >
             <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M3 10h10a8 8 0 018 8v2M3 10l6 6m-6-6l6-6" />
             </svg>
           </button>
        </div>
      </div>

      {/* Canvas Area */}
      <div 
        ref={containerRef}
        className="relative overflow-hidden shadow-2xl rounded-lg border border-slate-700 bg-slate-900/50 flex-shrink-0"
        style={{ maxWidth: '100%', maxHeight: '75vh' }}
      >
        <canvas
          ref={canvasRef}
          onMouseDown={startDrawing}
          onMouseMove={draw}
          onMouseUp={stopDrawing}
          onMouseLeave={stopDrawing}
          onTouchStart={startDrawing}
          onTouchMove={draw}
          onTouchEnd={stopDrawing}
          className="cursor-crosshair block max-w-full max-h-full object-contain"
          style={{ maxHeight: '75vh' }}
        />
        {isProcessing && (
           <div className="absolute inset-0 bg-black/70 flex flex-col items-center justify-center z-10">
               <div className="w-12 h-12 border-4 border-red-500 border-t-transparent rounded-full animate-spin mb-3"></div>
               <p className="text-white font-medium animate-pulse">Đang xóa vật thể & tái tạo nền...</p>
           </div>
        )}
      </div>

      {/* Footer Actions */}
      <div className="mt-4 flex gap-3">
         <button 
           onClick={onClose}
           className="px-6 py-2 bg-slate-700 hover:bg-slate-600 text-white rounded-lg font-medium transition-colors"
           disabled={isProcessing}
         >
           Hủy Bỏ
         </button>
         <button 
           onClick={handleGenerateMaskAndProcess}
           disabled={paths.length === 0 || isProcessing}
           className="px-8 py-2 bg-red-600 hover:bg-red-500 disabled:opacity-50 disabled:cursor-not-allowed text-white rounded-lg font-bold shadow-lg shadow-red-900/30 flex items-center gap-2 transition-all"
         >
           {isProcessing ? 'Đang Xử Lý...' : 'Thực Hiện Xóa'}
         </button>
      </div>

      <p className="mt-2 text-xs text-slate-500">
         * Tô màu đỏ lên các khu vực muốn xóa (Logo, Text, Vật thể thừa). AI sẽ tự động xóa và điền nền.
      </p>
    </div>
  );
};

