    ctx.lineCap = 'round';
    ctx.lineJoin = 'round';
    ctx.strokeStyle = 'rgba(239, 68, 68, 0.6)'; // Red-500, semi-transparent

    const allPaths = [...paths, currentPath];

    allPaths.forEach(path => {
