  request: ArtDirectionRequest; // Receive raw request to show input info
  artDirection: ArtDirectionResponse | null;
  imageResult: ImageGenerationResult;
  refinementResult: ImageGenerationResult;
  isAnalyzing: boolean;
  isUpdatingPlan: boolean;
  onGenerateImages: (finalPrompt: string, append?: boolean) => void;
  onUpdatePlan: (updatedPlan: DesignPlan) => void;
  onRegenerateImage: (prompt: string) => void;
  onSeparateLayout: (selectedImage: string, mode: 'full' | 'background') => void;
  onRefineImage: (sourceImage: string, instruction: string) => void;
  onSmartRemove: (sourceImage: string, maskBase64: string) => void;
  onResetRefinement: () => void;
  separatedAssets: SeparatedAssets;
}

const ResultDisplay: React.FC<ResultDisplayProps> = ({ 
  request,
  artDirection, 
  imageResult, 
  refinementResult,
  isAnalyzing,
  isUpdatingPlan,
  onGenerateImages,
  onUpdatePlan,
  onRegenerateImage, 
  onSeparateLayout,
  onRefineImage,
  onSmartRemove,
  onResetRefinement,
  separatedAssets
}) => {
  const [editablePrompt, setEditablePrompt] = useState('');
  const [localPlan, setLocalPlan] = useState<DesignPlan | null>(null);
  const [localLayout, setLocalLayout] = useState<LayoutSuggestion | null>(null);
  const [selectedImage, setSelectedImage] = useState<string | null>(null);
  const [lightboxImage, setLightboxImage] = useState<string | null>(null);
  const [refineInstruction, setRefineInstruction] = useState('');
  const [isRefiningPanelOpen, setIsRefiningPanelOpen] = useState(false);
  const [showSmartRemover, setShowSmartRemover] = useState(false);
  const [isUpscaling, setIsUpscaling] = useState(false);

  // Criteria List for display only
  const criteriaList: { key: keyof DesignPlan; label: string }[] = [
      { key: 'subject', label: 'Chủ thể & Nội dung phụ' },
      { key: 'styleContext', label: 'Bối cảnh & Phong cách' },
      { key: 'composition', label: 'Bố cục & Góc máy' },
      { key: 'colorLighting', label: 'Màu sắc & Ánh sáng' },
      { key: 'decorElements', label: 'Chi tiết trang trí' },
      { key: 'typography', label: 'Typography (Chữ)' },
  ];

  // Update local prompt state when art direction changes
  useEffect(() => {
    if (artDirection) {
      setEditablePrompt(artDirection.final_prompt);
      setLocalPlan(artDirection.designPlan);
      setLocalLayout(artDirection.layout_suggestion);
    }
  }, [artDirection]);

  useEffect(() => {
    setSelectedImage(null);
    setIsRefiningPanelOpen(false);
    setRefineInstruction('');
    setShowSmartRemover(false);
    onResetRefinement();
  }, [imageResult.imageUrls]);

  useEffect(() => {
    if (selectedImage) {
        onResetRefinement();
        setRefineInstruction('');
        setIsRefiningPanelOpen(false);
        setShowSmartRemover(false);
    }
  }, [selectedImage]);


  const handleRefineSubmit = () => {
    if (selectedImage && refineInstruction) {
      onRefineImage(selectedImage, refineInstruction);
    }
  };

  const handlePlanChange = (key: keyof DesignPlan, value: string) => {
    if (localPlan) {
        setLocalPlan({ ...localPlan, [key]: value });
    }
  };

  // Update the editable prompt with the current layout data
  const handleLayoutConfirm = () => {
      if (!localLayout) return;
      const layoutMarker = "\n\n-- FORCED COMPOSITION LAYOUT (STRICT) --";
      const layoutInstruction = convertLayoutToPrompt(localLayout);

      let basePrompt = editablePrompt;
      // If layout prompt already exists, remove it before appending the new one to avoid duplication
      if (basePrompt.includes(layoutMarker)) {
          basePrompt = basePrompt.split(layoutMarker)[0];
      }

      // Update prompt state with new coordinates
      setEditablePrompt(basePrompt + layoutInstruction);
  };

  const handleGenerateClick = (append: boolean) => {
      // Logic: If the user clicked "Confirm", the layout is already in editablePrompt.
      // If they didn't, we should append it now to ensure it's used.
      let finalPromptToSend = editablePrompt;
      const layoutMarker = "-- FORCED COMPOSITION LAYOUT (STRICT) --";

      // Only append if it's NOT already in the text area (i.e. user didn't click update, or just typed manually)
      if (localLayout && !finalPromptToSend.includes(layoutMarker)) {
          const layoutInstruction = convertLayoutToPrompt(localLayout);
          finalPromptToSend += layoutInstruction;
      }
      onGenerateImages(finalPromptToSend, append);
  };

  const handleDownload4K = async () => {
      if (!selectedImage || !artDirection) return;

      setIsUpscaling(true);
      try {
          const upscaleUrl = await upscaleImageTo4K(selectedImage, artDirection.recommendedAspectRatio);

          // Create a temporary link to download
          const link = document.createElement('a');
          link.href = upscaleUrl;
          link.download = `design-4k-${Date.now()}.png`;
          document.body.appendChild(link);
          link.click();
          document.body.removeChild(link);
      } catch (error) {
          console.error("Upscale failed", error);
          alert("Không thể nâng cấp ảnh lên 4K. Vui lòng thử lại.");
      } finally {
          setIsUpscaling(false);
      }
  };

  // Helper to format reference info
  const getReferenceSummary = () => {
      if (request.referenceImages.length === 0) return "Không chọn";
      return request.referenceImages.map((img, idx) => {
          if (img.attributes.length === 0) return `Ảnh ${idx + 1} (Không chọn thuộc tính)`;
          return `Ảnh ${idx + 1}: ${img.attributes.join(', ')}`;
      }).join(' | ');
  };

  // Initial State
  if (!artDirection && !isAnalyzing && !imageResult.loading && imageResult.imageUrls.length === 0) {
    return (
      <div className="h-full flex items-center justify-center bg-slate-800/30 rounded-2xl border border-slate-700/50 border-dashed">
        <div className="text-center p-8 max-w-md">
          <div className="w-16 h-16 bg-slate-800 rounded-full flex items-center justify-center mx-auto mb-4 text-slate-500">
             <svg xmlns="http://www.w3.org/2000/svg" className="h-8 w-8" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 5H7a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2V7a2 2 0 00-2-2h-2M9 5a2 2 0 002 2h2a2 2 0 002-2M9 5a2 2 0 012-2h2a2 2 0 012 2" />
             </svg>
          </div>
          <h3 className="text-lg font-medium text-slate-300 mb-2">Quy Trình Sáng Tạo</h3>
          <p className="text-slate-500 text-sm">
            1. Nhập yêu cầu & Tải tài nguyên<br/>
            2. AI Phân tích & Lập kế hoạch<br/>
            3. Chỉnh sửa Bố cục trực quan<br/>
            4. Tạo thiết kế cuối cùng
          </p>
        </div>
      </div>
    );
  }

  // State: Analyzing
  if (isAnalyzing) {
    return (
        <div className="h-full flex flex-col items-center justify-center bg-slate-800/30 rounded-2xl border border-slate-700/50">
             <div className="w-16 h-16 border-4 border-blue-500 border-t-purple-500 rounded-full animate-spin mb-6"></div>
             <h3 className="text-xl font-bold text-white mb-2">Đang Phân Tích & Tư Duy...</h3>
             <p className="text-slate-400 text-sm max-w-xs text-center">
                AI đang giải mã yêu cầu (Reverse Engineering), phân rã theo 6 tiêu chí thiết kế chuyên sâu.
             </p>
        </div>
    );
  }

  // Check if any separation data exists
  const hasSeparation = separatedAssets.background || 
                        separatedAssets.textLayer || 
                        separatedAssets.subjects.length > 0 ||
                        separatedAssets.decor.length > 0 ||
                        separatedAssets.lighting ||
                        separatedAssets.loading;

  return (
    <div className="flex flex-col h-full gap-6 overflow-y-auto pr-2 relative">
      {/* Lightbox Modal */}
      {lightboxImage && (
        <div className="fixed inset-0 z-50 bg-black/90 flex items-center justify-center p-4 backdrop-blur-sm" onClick={() => setLightboxImage(null)}>
          <div className="relative max-w-7xl max-h-screen">
            <img src={lightboxImage} alt="Full view" className="max-h-[90vh] max-w-full rounded-lg shadow-2xl" />
            <button 
              className="absolute -top-4 -right-4 bg-white/10 hover:bg-white/20 text-white rounded-full p-2"
              onClick={() => setLightboxImage(null)}
            >
              <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
              </svg>
            </button>
          </div>
        </div>
      )}

      {/* Smart Remover Modal */}
      {showSmartRemover && selectedImage && (
          <SmartRemover 
             imageUrl={selectedImage}
             onClose={() => setShowSmartRemover(false)}
             isProcessing={refinementResult.loading}
             onProcess={(maskBase64) => {
                 onSmartRemove(selectedImage, maskBase64);
                 // We don't close immediately, wait for loading in component or close manually
                 // Actually, best UX is to keep it open or show loading state inside it.
                 // The SmartRemover component handles its own loading state via prop.
             }}
          />
      )}

      {/* 1. Planning Stage: Analysis & Prompt Editing */}
      {artDirection && localPlan && (
        <div className="bg-slate-800/80 rounded-2xl border border-blue-500/30 overflow-hidden shadow-lg backdrop-blur-sm flex-shrink-0 animate-fade-in-down">
           {/* ... Header ... */}
           <div className="bg-gradient-to-r from-blue-900/40 to-purple-900/40 px-6 py-3 border-b border-white/10 flex items-center justify-between">
             <div className="flex items-center gap-2">
                <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5 text-blue-400" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 5H7a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2V7a2 2 0 00-2-2h-2M9 5a2 2 0 002 2h2a2 2 0 002-2M9 5a2 2 0 012-2h2a2 2 0 012 2" />
                </svg>
                <span className="text-white text-sm font-bold tracking-wider uppercase">Bảng Kế Hoạch & Bố Cục</span>
             </div>
             <div className="flex items-center gap-3">
                 {isUpdatingPlan && <span className="text-xs text-blue-300 animate-pulse">Đang viết lại Prompt...</span>}
                 <span className="text-slate-400 text-xs bg-slate-900/50 px-2 py-1 rounded">Tỉ lệ đề xuất: {artDirection.recommendedAspectRatio}</span>
             </div>
           </div>

           <div className="p-5 space-y-5">
             {/* 1.1 Input Summary Display */}
             <div className="grid grid-cols-2 gap-4 bg-slate-900/50 p-3 rounded-lg border border-slate-700/50 text-xs">
                 <div>
                    <span className="text-slate-500 block">Nội dung phụ (Secondary Content):</span>
                    <span className="text-slate-200 font-medium">{request.secondaryText || "Không có"}</span>
                 </div>
                 <div>
                    <span className="text-slate-500 block">Tham Khảo (Reference):</span>
                    <span className="text-emerald-400 font-medium block leading-tight">
                        {getReferenceSummary()}
                    </span>
                 </div>
             </div>

             {/* 1.2 The 6-Criteria Breakdown Grid */}
             <div>
                <div className="flex justify-between items-center mb-2">
                    <label className="text-xs font-semibold text-blue-400 uppercase block">1. Phân Tích & Phân Rã (6 Tiêu Chí)</label>
                    <button 
                        onClick={() => localPlan && onUpdatePlan(localPlan)}
                        disabled={isUpdatingPlan}
                        className="text-xs bg-blue-600 hover:bg-blue-500 text-white px-3 py-1 rounded flex items-center gap-1 transition-colors disabled:opacity-50"
                    >
                        {isUpdatingPlan ? (
                             <svg className="animate-spin h-3 w-3 text-white" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                                <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                                <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                             </svg>
                        ) : (
                            <svg xmlns="http://www.w3.org/2000/svg" className="h-3 w-3" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" />
                            </svg>
                        )}
                        Cập nhật Prompt từ Kế hoạch
                    </button>
                </div>
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-3">
                   {criteriaList.map((item) => (
                       <div key={item.key} className="bg-slate-900/80 p-3 rounded border border-slate-700 focus-within:border-blue-500 transition-colors flex flex-col h-full">
                           <h4 className="text-[10px] text-blue-300 font-bold uppercase mb-1 flex items-center gap-1">
                               {item.label}
                               <svg xmlns="http://www.w3.org/2000/svg" className="h-3 w-3 text-slate-500" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                                   <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15.232 5.232l3.536 3.536m-2.036-5.036a2.5 2.5 0 113.536 3.536L6.5 21.036H3v-3.572L16.732 3.732z" />
                               </svg>
                           </h4>
                           <textarea
                               value={localPlan[item.key] || ''}
                               onChange={(e) => handlePlanChange(item.key, e.target.value)}
                               className="w-full bg-transparent text-slate-300 text-xs leading-relaxed outline-none resize-none flex-grow min-h-[60px] border-b border-transparent focus:border-blue-500/50 pb-1"
                           />
                       </div>
                   ))}
                </div>
             </div>

             {/* 1.5 NEW LAYOUT EDITOR */}
             {localLayout && (
                 <div className="mt-2">
                     <LayoutEditor 
                        layout={localLayout}
                        onLayoutChange={(updated) => setLocalLayout(updated)}
                        onConfirm={handleLayoutConfirm}
                     />
                 </div>
             )}

             {/* 1.3 Editable Prompt */}
             <div>
                <label className="text-xs font-semibold text-slate-400 uppercase mb-2 block flex justify-between">
                    <span>2. Prompt Cuối Cùng (Tiếng Anh - Tự động tạo từ Kế hoạch)</span>
                    <span className="text-[10px] text-slate-500 lowercase font-normal">Có thể chỉnh sửa thủ công</span>
                </label>
                <textarea 
                    value={editablePrompt}
                    onChange={(e) => setEditablePrompt(e.target.value)}
                    className="w-full bg-slate-900 border border-slate-700 rounded-lg p-3 text-xs text-slate-300 focus:border-blue-500 outline-none font-mono leading-relaxed"
                    rows={3}
                />
             </div>

             {/* Action Button: Generate (Only show if no images yet) */}
             {!imageResult.loading && imageResult.imageUrls.length === 0 && (
                 <button
                    onClick={() => handleGenerateClick(false)}
                    className="w-full py-3 bg-gradient-to-r from-emerald-600 to-teal-600 hover:from-emerald-500 hover:to-teal-500 rounded-lg text-white font-bold shadow-lg shadow-emerald-900/20 transition-all transform hover:scale-[1.01] flex items-center justify-center gap-2"
                 >
                    <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M14.752 11.168l-3.197-2.132A1 1 0 0010 9.87v4.263a1 1 0 001.555.832l3.197-2.132a1 1 0 000-1.664z" />
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 12a9 9 0 11-18 0 9 9 0 0118 0z" />
                    </svg>
                    Tiến Hành Tạo Thiết Kế
                 </button>
             )}
           </div>
        </div>
      )}

      {/* 2. Image Results Grid */}
      {imageResult.imageUrls.length > 0 && (
          <div className="flex-grow flex flex-col gap-4 animate-fade-in-up">
            <div className="flex items-center justify-between">
                <h3 className="text-white font-bold text-lg flex items-center gap-2">
                    <span className="w-2 h-6 bg-purple-500 rounded-sm"></span>
                    Kết Quả Thiết Kế
                </h3>
            </div>

            {/* The Grid */}
            <div className={`grid gap-4 ${imageResult.imageUrls.length === 1 ? 'grid-cols-1' : 'grid-cols-2 md:grid-cols-3'}`}>
                {imageResult.imageUrls.map((url, idx) => (
                <div 
                    key={idx} 
                    className={`group relative rounded-xl overflow-hidden border-2 transition-all duration-300 cursor-pointer h-auto aspect-auto bg-slate-900 ${
                    selectedImage === url ? 'border-emerald-500 ring-2 ring-emerald-500/30' : 'border-slate-700 hover:border-slate-500'
                    }`}
                    onClick={(e) => { e.stopPropagation(); setSelectedImage(selectedImage === url ? null : url); }}
                >
                    {/* Thumbnail Image */}
                    <img src={url} alt={`Option ${idx + 1}`} className="w-full h-full object-contain" />

                    {/* Overlay Controls */}
                    <div className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center gap-4">
                    <button 
                        onClick={(e) => { e.stopPropagation(); setLightboxImage(url); }}
                        className="bg-slate-800/80 p-2 rounded-full text-white hover:bg-blue-600 transition-colors"
                        title="Xem lớn"
                    >
                        <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0zM10 7v3m0 0v3m0-3h3m-3 0H7" />
                        </svg>
                    </button>

                    <span className="text-white font-medium text-sm">Chọn để Sửa/Tách</span>
                    </div>

                    {/* Always Visible Selection Indicator */}
                    {selectedImage === url && (
                    <div className="absolute top-2 left-2 bg-emerald-500 text-white p-1 rounded-full shadow-lg">
                        <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M5 13l4 4L19 7" />
                        </svg>
                    </div>
                    )}
                </div>
                ))}
            </div>

            {/* "More Ideas" Button Area - Located BELOW Results */}
            <div className="flex justify-center mt-2">
                 {imageResult.loading ? (
                    <div className="flex items-center gap-2 px-6 py-2 bg-slate-800 rounded-full border border-slate-700 animate-pulse">
                         <div className="w-4 h-4 border-2 border-purple-500 border-t-transparent rounded-full animate-spin"></div>
                         <span className="text-xs text-purple-400 font-medium">Đang vẽ thêm ý tưởng mới...</span>
                    </div>
                 ) : (
                    <button
                        onClick={() => handleGenerateClick(true)}
                        className="bg-slate-800 hover:bg-slate-700 text-white px-8 py-3 rounded-full flex items-center gap-2 transition-all border border-slate-600 hover:border-emerald-500 shadow-lg group"
                    >
                        <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5 text-emerald-400 group-hover:rotate-180 transition-transform duration-500" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                           <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" />
                        </svg>
                        <span className="font-medium">Thêm Ý Tưởng Khác</span>
                    </button>
                 )}
            </div>
          </div>
      )}

      {/* Initial Loading State (Only if no images exist yet) */}
      {imageResult.loading && imageResult.imageUrls.length === 0 && (
        <div className="bg-slate-900/50 rounded-2xl border border-slate-700 h-96 flex flex-col items-center justify-center animate-pulse">
            <div className="inline-block w-12 h-12 border-4 border-purple-500 border-t-transparent rounded-full animate-spin mb-4"></div>
            <p className="text-slate-400 text-sm">Đang hiện thực hóa ý tưởng...</p>
        </div>
      )}

      {/* 3. Action Panel (Appears when an image is selected) */}
      {selectedImage && !imageResult.loading && (
        <div className="bg-slate-800 border border-slate-700 rounded-xl p-4 sticky bottom-0 z-10 shadow-2xl animate-fade-in-up">
           {/* ... (Refine buttons same as before) ... */}
           <div className="flex items-center justify-between mb-4">
             <h3 className="text-white font-semibold flex items-center gap-2">
               <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5 text-emerald-400" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 12l2 2 4-4m6 2a9 9 0 11-18 0 9 9 0 0118 0z" />
               </svg>
               Đã chọn sản phẩm
             </h3>
             <button
               onClick={handleDownload4K}
               disabled={isUpscaling}
               className="text-xs bg-emerald-600 hover:bg-emerald-500 text-white px-4 py-1.5 rounded flex items-center gap-2 transition-colors disabled:opacity-50 disabled:cursor-not-allowed shadow-lg shadow-emerald-900/20"
             >
               {isUpscaling ? (
                 <>
                   <div className="w-3 h-3 border-2 border-white border-t-transparent rounded-full animate-spin"></div>
                   <span>Đang Upscale (4K)...</span>
                 </>
               ) : (
                 <>
                   <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" />
                   </svg>
                   <span>Tải Về (Upscale 4K)</span>
                 </>
               )}
             </button>
           </div>

           <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <div className="space-y-4">
                 {/* 1. Smart Object Remover Button */}
                 <button 
                    onClick={() => setShowSmartRemover(true)}
                    className="w-full bg-slate-900 border border-red-500/50 hover:bg-red-900/10 text-white text-sm py-2 rounded-lg font-medium transition-colors flex items-center justify-center gap-2 group"
                 >
                     <div className="bg-red-500/20 p-1 rounded-full group-hover:bg-red-500/40">
                         <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4 text-red-400" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" />
                         </svg>
                     </div>
                     <span>Xóa Chi Tiết (Magic Eraser)</span>
                 </button>

                 {/* 2. Text/Prompt Refinement (Accordion) */}
                 <div className={`border rounded-lg p-3 transition-colors ${isRefiningPanelOpen ? 'border-purple-500 bg-purple-900/20' : 'border-slate-600 bg-slate-900'}`}>
                    <button 
                      onClick={() => setIsRefiningPanelOpen(!isRefiningPanelOpen)}
                      className="w-full text-left text-sm font-medium text-white flex items-center justify-between mb-2"
                    >
                      <span className="flex items-center gap-2">
                        <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4 text-purple-400" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                           <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M11 5H6a2 2 0 00-2 2v11a2 2 0 002 2h11a2 2 0 002-2v-5m-1.414-9.414a2 2 0 112.828 2.828L11.828 15H9v-2.828l8.586-8.586z" />
                        </svg>
                        Hiệu Chỉnh Bằng Lời (Refine)
                      </span>
                      <span className="text-xs text-slate-400">{isRefiningPanelOpen ? '▲' : '▼'}</span>
                    </button>

                    {isRefiningPanelOpen && (
                      <div className="mt-2 animate-fade-in">
                         <textarea
                           className="w-full bg-slate-800 border border-slate-600 rounded p-2 text-sm text-white focus:border-purple-500 outline-none resize-none mb-2"
                           placeholder="Nhập yêu cầu sửa đổi (vd: đổi màu nền sang xanh, làm chữ to hơn...)"
                           rows={2}
                           value={refineInstruction}
                           onChange={(e) => setRefineInstruction(e.target.value)}
                         />
                         <button
                           onClick={handleRefineSubmit}
                           disabled={!refineInstruction || refinementResult.loading}
                           className="w-full bg-purple-600 hover:bg-purple-500 disabled:opacity-50 disabled:cursor-not-allowed text-white text-xs py-2 rounded font-medium transition-colors"
                         >
                           {refinementResult.loading ? 'Đang Xử Lý...' : 'Thực Hiện Hiệu Chỉnh'}
                         </button>
                      </div>
                    )}
                 </div>
              </div>

              {/* Separation Buttons Grid */}
              <div className="flex flex-col gap-2">
                  <button
                    onClick={() => onSeparateLayout(selectedImage, 'full')}
                    disabled={separatedAssets.loading}
                    className="flex-1 bg-slate-900 border border-slate-600 hover:border-emerald-500 hover:bg-emerald-900/10 rounded-lg p-2 flex items-center justify-center gap-2 transition-all group disabled:opacity-50"
                  >
                     {separatedAssets.loading ? (
                        <div className="w-4 h-4 border-2 border-emerald-500 border-t-transparent rounded-full animate-spin"></div>
                     ) : (
                        <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4 text-emerald-400" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                           <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8 16H6a2 2 0 01-2-2V6a2 2 0 012-2h8a2 2 0 012 2v2m-6 12h8a2 2 0 002-2v-8a2 2 0 00-2-2h-8a2 2 0 00-2 2v8a2 2 0 002 2z" />
                        </svg>
                     )}
                     <span className="text-xs font-medium text-white">Tách Lớp Chi Tiết (Full)</span>
                  </button>

                  <button
                    onClick={() => onSeparateLayout(selectedImage, 'background')}
                    disabled={separatedAssets.loading}
                    className="flex-1 bg-slate-900 border border-slate-600 hover:border-blue-500 hover:bg-blue-900/10 rounded-lg p-2 flex items-center justify-center gap-2 transition-all group disabled:opacity-50"
                  >
                     {separatedAssets.loading ? (
                        <div className="w-4 h-4 border-2 border-blue-500 border-t-transparent rounded-full animate-spin"></div>
                     ) : (
                        <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4 text-blue-400" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                           <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" />
                        </svg>
                     )}
                     <span className="text-xs font-medium text-white">Ảnh Sạch (Bỏ Chữ/Logo)</span>
                  </button>
              </div>
           </div>

           {/* REFINEMENT VIEW */}
           {(refinementResult.loading || refinementResult.imageUrls.length > 0) && (
               <div className="mt-4 pt-4 border-t border-slate-700 animate-fade-in">
                  <div className="grid grid-cols-2 gap-4 items-center bg-slate-900/50 p-3 rounded-lg border border-slate-700">
                      <div className="relative group">
                          <span className="absolute top-2 left-2 bg-slate-800/80 text-xs text-white px-2 py-1 rounded backdrop-blur-sm z-10 border border-slate-600">Ảnh Gốc</span>
                          <img src={selectedImage} alt="Original" className="w-full h-48 object-contain rounded-lg border border-slate-600" onClick={() => setLightboxImage(selectedImage)} />
                      </div>
                      <div className="relative group">
                          <span className="absolute top-2 left-2 bg-purple-600/90 text-xs text-white px-2 py-1 rounded backdrop-blur-sm z-10 border border-purple-400 shadow-lg shadow-purple-500/20">Kết Quả Mới</span>
                          {refinementResult.loading ? (
                             <div className="w-full h-48 bg-slate-800 rounded-lg flex flex-col items-center justify-center border border-slate-700 border-dashed animate-pulse">
                                 <div className="w-8 h-8 border-2 border-purple-500 border-t-transparent rounded-full animate-spin mb-2"></div>
                                 <span className="text-xs text-slate-500">Đang vẽ lại...</span>
                             </div>
                          ) : (
                             <img src={refinementResult.imageUrls[0]} alt="Refined" className="w-full h-48 object-contain rounded-lg border-2 border-purple-500 shadow-lg shadow-purple-500/10 cursor-pointer" onClick={() => setLightboxImage(refinementResult.imageUrls[0])} />
                          )}
                      </div>
                  </div>
               </div>
           )}
        </div>
      )}

      {/* 4. Separated Assets Display */}
      {hasSeparation && (
        <div className="mt-4 pt-4 border-t border-slate-700 animate-fade-in-up">
            <h3 className="text-lg font-bold text-white mb-4 flex items-center gap-2">
                <span className="w-2 h-6 bg-emerald-500 rounded-sm"></span>
                Kết Quả Tách Lớp & Nguyên Liệu (4K)
            </h3>

            <div className="space-y-6">

                {/* 1. Nền & Ánh Sáng */}
                <div>
                    <h4 className="text-xs text-slate-400 font-bold uppercase mb-2">1. Nền & Ánh Sáng</h4>
                    <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                         <AssetCard 
                            title="Background" 
                            image={separatedAssets.background} 
                            loading={separatedAssets.loading} 
                            onZoom={() => separatedAssets.background && setLightboxImage(separatedAssets.background)}
                        />
                         <AssetCard 
                            title="Lighting / Atmosphere" 
                            image={separatedAssets.lighting} 
                            loading={separatedAssets.loading} 
                            onZoom={() => separatedAssets.lighting && setLightboxImage(separatedAssets.lighting)}
                        />
                    </div>
                </div>

                {/* 2. Chủ Thể (Subjects) */}
                <div>
                    <h4 className="text-xs text-slate-400 font-bold uppercase mb-2">2. Chủ Thể (Isolated Subjects)</h4>
                    <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                        {separatedAssets.loading && separatedAssets.subjects.length === 0 ? (
                             <>
                                <AssetCard title="Main Hero Subject" image={null} loading={true} />
                                <AssetCard title="Secondary Subject" image={null} loading={true} />
                             </>
                        ) : (
                             separatedAssets.subjects.map((img, idx) => (
                                <AssetCard 
                                    key={`sub-${idx}`}
                                    title={idx === 0 ? "Main Subject (Hero)" : "Secondary / Angle"} 
                                    image={img} 
                                    loading={false} 
                                    isWhiteBg
                                    onZoom={() => setLightboxImage(img)}
                                />
                             ))
                        )}
                        {/* If empty but loaded */}
                        {!separatedAssets.loading && separatedAssets.subjects.length === 0 && <span className="text-xs text-slate-600 italic">Không có chủ thể tách biệt.</span>}
                    </div>
                </div>

                {/* 3. Trang Trí (Decor) */}
                <div>
                    <h4 className="text-xs text-slate-400 font-bold uppercase mb-2">3. Chi Tiết Trang Trí (Decor Elements)</h4>
                    <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                        {separatedAssets.loading && separatedAssets.decor.length === 0 ? (
                             <>
                                <AssetCard title="Main Props / Podium" image={null} loading={true} />
                                <AssetCard title="Particles / Effects" image={null} loading={true} />
                             </>
                        ) : (
                             separatedAssets.decor.map((img, idx) => (
                                <AssetCard 
                                    key={`decor-${idx}`}
                                    title={idx === 0 ? "Large Props / Podium" : "Small Particles / Effects"} 
                                    image={img} 
                                    loading={false} 
                                    isWhiteBg
                                    onZoom={() => setLightboxImage(img)}
                                />
                             ))
                        )}
                        {!separatedAssets.loading && separatedAssets.decor.length === 0 && <span className="text-xs text-slate-600 italic">Không có chi tiết trang trí.</span>}
                    </div>
                </div>

                {/* 4. Text */}
                <div>
                    <h4 className="text-xs text-slate-400 font-bold uppercase mb-2">4. Typography</h4>
                    <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                         <AssetCard 
                            title="Text Layer" 
                            image={separatedAssets.textLayer} 
                            loading={separatedAssets.loading} 
                            isWhiteBg
                            onZoom={() => separatedAssets.textLayer && setLightboxImage(separatedAssets.textLayer)}
                        />
                    </div>
                </div>

            </div>

            {separatedAssets.error && (
                <div className="mt-4 p-3 bg-red-900/30 border border-red-500/30 rounded-lg text-red-200 text-sm">
                    Lỗi khi tách bố cục: {separatedAssets.error}
                </div>
            )}
        </div>
      )}
    </div>
  );
};

export default ResultDisplay;

export enum ProductType {
  POSTER = 'Poster',
  STANDEE = 'Standee',
  BACKDROP = 'Backdrop',
  BANNER = 'Banner',
  SOCIAL_POST = 'Social Media Post',
  FLYER = 'Flyer'
}

export enum VisualStyle {
  MODERN_TECH = 'Modern Tech',
  LUXURY = 'Luxury',
  VINTAGE = 'Vintage',
  FESTIVE = 'Festive',
  MINIMALIST = 'Minimalist',
  CORPORATE = 'Corporate',
  CYBERPUNK = 'Cyberpunk',
  NATURAL_ORGANIC = 'Natural/Organic',
  FOLLOW_REF = 'Follow Reference' // New option
}

export enum ColorMode {
  AUTO = 'Auto',
  CUSTOM = 'Custom',
  BRAND_LOGO = 'Brand Logo' // New option
}

export enum QualityLevel {
  LOW = '1K',
  MEDIUM = '2K',
  HIGH = '4K'
}

export enum ProductImageMode {
  REALISTIC = 'Realistic', // Làm nét, giữ nguyên chi tiết, tách nền
  STYLIZED = 'Stylized'    // AI Cách điệu, vẽ lại
}

export interface ReferenceImageConfig {
  id: string;
  image: string; // Base64 string
  attributes: string[]; // 'Subject', 'Style', 'Composition', 'Color', 'Decor', 'Typography'
}

export interface ArtDirectionRequest {
  productType: ProductType;
  // Content Text Split
  mainHeadline: string;
  mainHeadlineImage: string | null; // Image reference specifically for the headline style
  secondaryText: string;

  visualStyle: VisualStyle;
  colorMode: ColorMode;
  customColors: string[];

  // Design Requirements
  layoutRequirements: string; // Specific placement instructions & Scene description merged
  fontPreferences: string; // New field for typography/font usage

  width: string;
  height: string;

  // Assets & Logo
  logoImage: string | null; // Base64 string for Brand Logo
  assetImages: string[]; // Base64 strings
  productImageMode: ProductImageMode; // How to treat the asset images

  // Updated to support multiple references
  referenceImages: ReferenceImageConfig[]; 

  batchSize: 1 | 2 | 3;
  quality: QualityLevel;
}

// New Interface for Decomposed Plan
export interface DesignPlan {
  subject: string;        // Chủ thể chính & Nội dung phụ
  styleContext: string;   // Bối cảnh & Phong cách
  composition: string;    // Bố cục & Góc máy
  colorLighting: string;  // Màu sắc & Ánh sáng
  decorElements: string;  // Chi tiết trang trí
  typography: string;     // Typography (Chữ)
