// --- NEW LAYOUT TYPES ---
export interface LayoutRect {
  x: number; // Percentage 0-100
  y: number; // Percentage 0-100
  width: number; // Percentage 0-100
  height: number; // Percentage 0-100
}

export interface LayoutElement {
  id: string;
  name: string;
  type: 'subject' | 'text' | 'decor' | 'logo';
