export const generateArtDirection = async (request: ArtDirectionRequest): Promise<ArtDirectionResponse> => {
  try {
    const parts: any[] = [];

    // Logic for Conflict: Brand Logo Mode vs Reference 'Color'
    const isBrandLogoMode = request.colorMode === ColorMode.BRAND_LOGO;
    const hasUserAssets = request.assetImages.length > 0;

    // Check if ANY reference image has 'Color' selected
    const anyRefHasColor = request.referenceImages.some(img => img.attributes.includes('Color'));

    let colorInstruction = "";

    // Construct Reference Instructions
    let allRefInstructions = "";

    request.referenceImages.forEach((refImg, index) => {
        const i = index + 1;
        let activeAttributes = [...refImg.attributes];

        let specificNote = "";

        // Handle Typography Specifics
        if (activeAttributes.includes('Typography')) {
            specificNote += `\n   - **TYPOGRAPHY & LAYOUT INSTRUCTION:** 
             1. Analyze the font style (Weight, Family) in Ref Image ${i}.
             2. **CRITICAL:** Analyze the **SPATIAL ARRANGEMENT** (Alignment, Line Spacing, Overlap) of the text in Ref Image ${i}.
             3. **ACTION:** Render the Main Headline "${request.mainHeadline}" to EXACTLY MIMIC this visual hierarchy and layout.`;
        }

        // Handle Subject/Composition with User Assets
        if (hasUserAssets && (activeAttributes.includes('Subject') || activeAttributes.includes('Composition'))) {
             specificNote += `\n   - **ASSET INTEGRATION (CRITICAL):** The User provided a PRODUCT IMAGE (Asset). 
             **DO NOT** generate the subject from Ref Image ${i}. 
             INSTEAD, take the **Composition/Angle/Pose** from Ref Image ${i} and **INSERT** the User's Asset into that spot.`;
        }

        // Handle Color Conflict
        if (isBrandLogoMode && activeAttributes.includes('Color')) {
             // Conflict logic: Remove Color from the "Copy" list for this image context, replace with Lighting note
             activeAttributes = activeAttributes.filter(attr => attr !== 'Color');
             specificNote += `\n   - **LIGHTING ONLY:** 'Color' attribute was checked, BUT mode is 'Brand Logo'. -> Extract **LIGHTING & SHADOWS ONLY** from Ref Image ${i}. **DO NOT** use its Colors. Use Brand Logo Colors instead.`;
        }

        if (activeAttributes.length > 0 || specificNote) {
            allRefInstructions += `
            -- REFERENCE IMAGE ${i} --
            Attributes to Copy: [${activeAttributes.join(', ')}]
            ${specificNote}
            `;
        }
    });

    if (isBrandLogoMode) {
        colorInstruction = "STRICTLY USE COLORS EXTRACTED FROM THE PROVIDED BRAND LOGO IMAGE.";
    } else {
        colorInstruction = request.colorMode === 'Custom' ? `Custom Palette: ${request.customColors.join(', ')}` : 'Auto/AI Decision';
    }

    let styleInstruction = request.visualStyle === VisualStyle.FOLLOW_REF 
        ? "STRICTLY MIMIC the Reference Image style(s)." 
        : request.visualStyle;

    let promptText = `
      -- CORE DATA --
      Product Type: ${request.productType}
      Dimensions: ${request.width}cm x ${request.height}cm

      -- TEXT CONTENT --
      Main Headline: "${request.mainHeadline}"
      Secondary Text: "${request.secondaryText}"

      -- BRANDING & ASSETS --
      Has Brand Logo: ${request.logoImage ? "YES" : "NO"}
      Has User Product Assets: ${hasUserAssets ? "YES (PRIORITY HERO)" : "NO"}
      Color Mode: ${request.colorMode}
      Color Instruction: ${colorInstruction}

      -- USER REQUIREMENTS --
      Layout/Description: "${request.layoutRequirements}"
      Font Preferences: "${request.fontPreferences}"
      Visual Style: ${styleInstruction}
      Product Mode: ${request.productImageMode}

      -- REFERENCE INSTRUCTIONS (CRITICAL) --
      ${allRefInstructions}
    `;

    parts.push({ text: promptText });

    // Attach Images
    if (request.logoImage) parts.push({ inlineData: { mimeType: "image/png", data: request.logoImage.split(',')[1] } });
    request.assetImages.forEach(img => parts.push({ inlineData: { mimeType: "image/png", data: img.split(',')[1] } }));
    if (request.mainHeadlineImage) parts.push({ inlineData: { mimeType: "image/png", data: request.mainHeadlineImage.split(',')[1] } });

    // Attach Reference Images with Labels
    request.referenceImages.forEach((refImg, index) => {
        parts.push({ text: `REFERENCE IMAGE ${index + 1}:`});
        parts.push({ inlineData: { mimeType: "image/png", data: refImg.image.split(',')[1] } });
    });

    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: { parts },
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        responseMimeType: "application/json",
        responseSchema: RESPONSE_SCHEMA,
      },
    });

    const text = response.text;
    if (!text) throw new Error("No response from AI Director");

    // Post-process to ensure IDs exist for layout elements
    const result = JSON.parse(text) as ArtDirectionResponse;
    if (result.layout_suggestion && result.layout_suggestion.elements) {
        result.layout_suggestion.elements = result.layout_suggestion.elements.map((el, idx) => ({
            ...el,
            id: el.id || `el-${Date.now()}-${idx}`
        }));
    }

    return result;
  } catch (error) {
    console.error("Error generating art direction:", error);
    throw error;
  }
};

// Helper to convert the Visual Layout back into Text for the Prompt
export const convertLayoutToPrompt = (layout: LayoutSuggestion): string => {
    if (!layout || !layout.elements || layout.elements.length === 0) return "";

    let promptAddition = "\n\n-- FORCED COMPOSITION LAYOUT (STRICT) --\n";
    promptAddition += "Place the following elements exactly as described:\n";

    layout.elements.forEach(el => {
        // Convert percentages to approximate placement words for better understanding
        const x = el.rect.x;
        const y = el.rect.y;
        const w = el.rect.width;
        const h = el.rect.height;

        promptAddition += `- Element "${el.name}" (${el.type}): Position at X=${x}%, Y=${y}%. Size: Width=${w}%, Height=${h}% of the canvas.\n`;
    });

    return promptAddition;
};

