import React, { useState, useRef, useEffect } from 'react';
import { LayoutSuggestion, LayoutElement } from '../types';

interface LayoutEditorProps {
  layout: LayoutSuggestion;
  validAspectRatio: string; // Force strictly valid aspect ratio (e.g., "9:16")
  onLayoutChange: (updatedLayout: LayoutSuggestion) => void;
  onConfirm: (maskBase64: string, currentRatio: string) => void; // Updated signature
}

const LayoutEditor: React.FC<LayoutEditorProps> = ({ layout, validAspectRatio, onLayoutChange, onConfirm }) => {
  const [elements, setElements] = useState<LayoutElement[]>(layout.elements);
  const containerRef = useRef<HTMLDivElement>(null);
  const [selectedId, setSelectedId] = useState<string | null>(null);

  // Local state for ratio to support toggling
  const [currentRatio, setCurrentRatio] = useState(validAspectRatio);

  // Dragging State
  const [isDragging, setIsDragging] = useState(false);
  const [isResizing, setIsResizing] = useState(false);
  const [activeId, setActiveId] = useState<string | null>(null);
  const [startPos, setStartPos] = useState({ x: 0, y: 0 });

  // Sync if props change
  useEffect(() => {
    setElements(layout.elements);
  }, [layout]);

  useEffect(() => {
    setCurrentRatio(validAspectRatio);
  }, [validAspectRatio]);

  // Handle Selection
  const handleMouseDown = (e: React.MouseEvent, id: string, type: 'move' | 'resize') => {
    e.stopPropagation();
    setActiveId(id);
    setSelectedId(id);
    setStartPos({ x: e.clientX, y: e.clientY });

    if (type === 'move') setIsDragging(true);
    if (type === 'resize') setIsResizing(true);
  };

  // Global Mouse Up
  useEffect(() => {
    const handleMouseUp = () => {
      if (isDragging || isResizing) {
        setIsDragging(false);
        setIsResizing(false);
        setActiveId(null);
        onLayoutChange({ ...layout, elements });
      }
    };

    const handleMouseMove = (e: MouseEvent) => {
      if (!activeId || !containerRef.current) return;

      const containerRect = containerRef.current.getBoundingClientRect();
      const deltaX = e.clientX - startPos.x;
      const deltaY = e.clientY - startPos.y;

      const deltaXPercent = (deltaX / containerRect.width) * 100;
      const deltaYPercent = (deltaY / containerRect.height) * 100;

      if (isDragging) {
        setElements(prev => prev.map(el => {
          if (el.id !== activeId) return el;
          let newX = el.rect.x + deltaXPercent;
          let newY = el.rect.y + deltaYPercent;
          return { ...el, rect: { ...el.rect, x: newX, y: newY } };
        }));
        setStartPos({ x: e.clientX, y: e.clientY });
      }

      if (isResizing) {
        setElements(prev => prev.map(el => {
            if (el.id !== activeId) return el;
            let newW = Math.max(5, el.rect.width + deltaXPercent);
            let newH = Math.max(5, el.rect.height + deltaYPercent);
            return { ...el, rect: { ...el.rect, width: newW, height: newH } };
        }));
        setStartPos({ x: e.clientX, y: e.clientY });
      }
    };

    if (isDragging || isResizing) {
      window.addEventListener('mousemove', handleMouseMove);
      window.addEventListener('mouseup', handleMouseUp);
    }

    return () => {
      window.removeEventListener('mousemove', handleMouseMove);
      window.removeEventListener('mouseup', handleMouseUp);
    };
  }, [isDragging, isResizing, activeId, startPos, elements, layout, onLayoutChange]);

  // Orientation Logic
  const toggleOrientation = () => {
      if (!currentRatio.includes(':')) return;
      const [w, h] = currentRatio.split(':').map(Number);
      // Swap width and height
      const newRatio = `${h}:${w}`;
      setCurrentRatio(newRatio);
  };

  const getRatioValue = () => {
      if (currentRatio && currentRatio.includes(':')) {
          const [w, h] = currentRatio.split(':').map(Number);
          if (w && h) return w / h;
      }
      return 1;
  };

  const getAspectRatioStyle = () => {
    return { aspectRatio: `${getRatioValue()}` };
  };

  /**
   * Generates a "Clean Segmentation Mask" for AI Input.
   * STRICT RULES:
   * 1. Black Background (#000000).
   * 2. Solid Filled Rectangles ONLY (ctx.fillRect).
   * 3. NO Text, NO Borders, NO Handles, NO Grid lines.
   */
  const generateCleanSegmentationMask = (): string => {
      const canvas = document.createElement('canvas');
      // Use high resolution for precision
      const width = 1024; 

      const ratioValue = getRatioValue();
      const height = Math.round(width / ratioValue);

      canvas.width = width;
      canvas.height = height;

      const ctx = canvas.getContext('2d');
      if (!ctx) return '';

      // 1. Fill Background Absolute Black
      ctx.fillStyle = '#000000';
      ctx.fillRect(0, 0, width, height);

      // 2. Draw Elements as Solid Blocks
      elements.forEach(el => {
          const x = (el.rect.x / 100) * width;
          const y = (el.rect.y / 100) * height;
          const w = (el.rect.width / 100) * width;
          const h = (el.rect.height / 100) * height;

          // Use the element's distinct color as the segmentation ID
          ctx.fillStyle = el.color; 
          // Fill ONLY. No stroke.
          ctx.fillRect(x, y, w, h);
      });

      return canvas.toDataURL('image/png');
  };

  const handleConfirm = () => {
      // Use the new CLEAN function
      const maskBase64 = generateCleanSegmentationMask();
      onConfirm(maskBase64, currentRatio);
  };

  return (
    <div className="bg-slate-900 rounded-xl border border-slate-700 overflow-hidden flex flex-col">
       <div className="bg-slate-800 px-4 py-2 border-b border-slate-700 flex justify-between items-center">
           <h4 className="text-sm font-bold text-slate-300 flex items-center gap-2">
              <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4 text-purple-400" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                 <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 5a1 1 0 011-1h14a1 1 0 011 1v2a1 1 0 01-1 1H5a1 1 0 01-1-1V5zM4 13a1 1 0 011-1h6a1 1 0 011 1v6a1 1 0 01-1 1H5a1 1 0 01-1-1v-6zM16 13a1 1 0 011-1h2a1 1 0 011 1v6a1 1 0 01-1 1h-2a1 1 0 01-1-1v-6z" />
              </svg>
              Trình Chỉnh Sửa Bố Cục
           </h4>
           <div className="flex items-center gap-2">
               <button 
                 onClick={toggleOrientation}
                 className="bg-slate-700 hover:bg-slate-600 text-white text-[10px] px-2 py-1 rounded flex items-center gap-1 transition-colors border border-slate-600"
                 title="Đổi chiều Ngang/Dọc"
               >
                   <svg xmlns="http://www.w3.org/2000/svg" className="h-3 w-3" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" />
                   </svg>
                   Xoay Chiều
               </button>
               <div className="text-[10px] text-emerald-400 bg-slate-950 px-2 py-1 rounded font-mono border border-slate-700">
                  {currentRatio}
               </div>
           </div>
       </div>

       <div className="p-6 flex justify-center bg-slate-950 relative min-h-[300px] overflow-auto">
          <div 
            ref={containerRef}
            className="relative w-full max-w-[400px] bg-white/5 border border-slate-700 rounded shadow-2xl overflow-hidden self-center transition-all duration-300"
            style={getAspectRatioStyle()} 
          >
             {/* Grid Lines for UI Only - Won't be in mask */}
             <div className="absolute inset-0 grid grid-cols-3 grid-rows-3 pointer-events-none opacity-10 z-0">
                 <div className="border-r border-b border-white"></div>
                 <div className="border-r border-b border-white"></div>
                 <div className="border-b border-white"></div>
                 <div className="border-r border-b border-white"></div>
                 <div className="border-r border-b border-white"></div>
                 <div className="border-b border-white"></div>
                 <div className="border-r border-white"></div>
                 <div className="border-r border-white"></div>
             </div>

             {elements.map((el) => {
                 const isSelected = el.id === selectedId;
                 return (
                    <div
                        key={el.id}
                        onMouseDown={(e) => handleMouseDown(e, el.id, 'move')}
                        className={`absolute flex flex-col items-center justify-center p-1 text-center cursor-move transition-shadow select-none group border ${isSelected ? 'z-10 ring-1 ring-white' : 'z-0 border-transparent'}`}
                        style={{
                            left: `${el.rect.x}%`,
                            top: `${el.rect.y}%`,
                            width: `${el.rect.width}%`,
                            height: `${el.rect.height}%`,
                            backgroundColor: `${el.color}90`
                        }}
                    >
                        {/* These text spans are UI ONLY. They are NOT drawn in generateCleanSegmentationMask */}
                        <span className="text-[9px] font-bold text-white drop-shadow-md leading-tight pointer-events-none">
                            {el.name}
                        </span>

                        <span className="text-[7px] text-white/80 uppercase tracking-wider pointer-events-none bg-black/20 px-1 rounded mt-0.5">
                            {el.type}
